export interface MCQQuestion { id: number; text: string; image?: string; table?: string;
  options: { label: string; text: string }[]; correct: string; }
export interface MCQPaper { id: string; year: number; session: string; paperCode: string; questionData: MCQQuestion[]; }

const paper_01: MCQQuestion[] = [{"id":1,"text":"What is a negative consumption externality associated with chewing gum?","options":[{"label":"A","text":"better dental hygiene from chewing gum"},{"label":"B","text":"costs of the ingredients in chewing gum"},{"label":"C","text":"discarded chewing gum on pavements"},{"label":"D","text":"smells from chewing gum factories"}],"correct":""},{"id":2,"text":"In 2008 Beijing held the Olympic Games and built a new stadium and infrastructure. 1.5 million people lost their homes and were relocated far away from their communities. Factories were closed during the games to reduce air pollution. Today, the stadium is a major tourist attraction and the athletes' accommodation is used as apartments. For which group is the likely excess of marginal social benefit over marginal social cost the greatest?","options":[{"label":"A","text":"construction workers who built the site"},{"label":"B","text":"factory workers who returned to their jobs after the games"},{"label":"C","text":"residents who were rehoused far away from Beijing"},{"label":"D","text":"those who live in the former athletes' accommodation"}],"correct":""},{"id":3,"text":"The graph shows the budget line for a household as used in indifference curve analysis. What can be concluded about the amount of income that could be spent by the household?","options":[{"label":"A","text":"It is greater at point R than point S."},{"label":"B","text":"It is greater at point T than point S."},{"label":"C","text":"It is greatest at point S."},{"label":"D","text":") It is the same at points R, S and T."}],"correct":"","image":"/images/econ-a2-mcq/1_633_232_530_422_0.jpg"},{"id":4,"text":"Which act of purchase or consumption is most likely to illustrate the law of diminishing marginal utility?","options":[{"label":"A","text":"the final course of an 'eat all you can' banquet to end an evening out"},{"label":"B","text":"the last coin to complete an enthusiast's coin collection"},{"label":"C","text":"the second of the two rolls of wallpaper needed to decorate a room"},{"label":"D","text":") the tenth driving lesson needed to enable a learner to pass the driving test"}],"correct":""},{"id":5,"text":"A kinked demand curve is often used when economists attempt to analyse the way in which oligopolists operate. What does the kinked demand curve indicate?","options":[{"label":"A","text":"Oligopolists are unable to achieve profit maximisation."},{"label":"B","text":"Satisficing is the best objective for firms that operate under conditions of oligopoly."},{"label":"C","text":"There are always benefits available for oligopolists if they reduce price, but not if they increase it."},{"label":"D","text":"There is a tendency towards price stability when firms operate under conditions of oligopoly."}],"correct":""},{"id":6,"text":"Why might a firm adopt a policy of diversification?","options":[{"label":"A","text":"to achieve cost economies of scale"},{"label":"B","text":"to agree common prices with rivals"},{"label":"C","text":"to ensure greater ability to spread investment risks"},{"label":"D","text":"to increase productivity of labour"}],"correct":""},{"id":7,"text":"The diagram shows a firm's short-run total cost curve (TC). Which statement is correct?","options":[{"label":"A","text":"Average total cost is minimised at output \\({\\mathrm{{OQ}}}_{2}\\) ."},{"label":"B","text":"Average variable cost is minimised at output \\({\\mathrm{{OQ}}}_{1}\\) ."},{"label":"C","text":"Average variable cost is minimised at output \\({\\mathrm{{OQ}}}_{3}\\) ."},{"label":"D","text":"Marginal cost is minimised at output \\({\\mathrm{{OQ}}}_{1}\\) ."}],"correct":"","image":"/images/econ-a2-mcq/3_549_238_691_597_0.jpg"},{"id":8,"text":"When there are positive externalities in consumption, what can be concluded about the output of the market?","options":[{"label":"A","text":"Output must be above the allocative efficient level."},{"label":"B","text":"Output must be at the allocative efficient level."},{"label":"C","text":"Output must be below the allocative efficient level."},{"label":"D","text":"Output can be above or below the allocative efficient level."}],"correct":""},{"id":9,"text":"The Gini coefficient of a country is 0.40 The poorest income earners in this country pay no income tax. The government increases the tax rate on the highest income earners, which results in a more even distribution of income. What could be concluded from this?","options":[{"label":"A","text":"The Gini coefficient falls and the income tax system becomes more progressive."},{"label":"B","text":"The Gini coefficient falls and the income tax system becomes more regressive."},{"label":"C","text":"The Gini coefficient rises and the income tax system becomes more progressive."},{"label":"D","text":"The Gini coefficient rises and the income tax system becomes more regressive."}],"correct":""},{"id":10,"text":"What is meant by economic rent?","options":[{"label":"A","text":"any amount above the minimum earnings required to keep labour in its current job"},{"label":"B","text":"the marginal physical product of labour multiplied by marginal revenue"},{"label":"C","text":"the minimum amount required to keep labour in its current job"},{"label":"D","text":") the regular payment to a property owner in exchange for the use of a building"}],"correct":""},{"id":11,"text":"A government attempts to stimulate growth by cutting its main interest rate. What might reduce the effectiveness of this?","options":[{"label":"A","text":"if investors' expectations are rising"},{"label":"B","text":"if more borrowing is taking place"},{"label":"C","text":"if savings are falling"},{"label":"D","text":"if the marginal propensity to consume is falling"}],"correct":""},{"id":12,"text":"The diagram shows the relative position of two countries \\(X\\) and \\(Y\\) on a Kuznets curve. What does the diagram indicate?","options":[{"label":"A","text":"Country X collects more income tax than country Y."},{"label":"B","text":"Country X has a higher national income than country Y."},{"label":"C","text":"Country Y has less income inequality than country X."},{"label":"D","text":"Country Y is less economically developed than country X."}],"correct":"","image":"/images/econ-a2-mcq/6_580_232_633_412_0.jpg"},{"id":13,"text":"The Measure of Economic Welfare (MEW) is often regarded as a better measure of economic welfare than Gross Domestic Product (GDP) per head. What is additionally included in the calculation for MEW?","options":[{"label":"A","text":"the cost of paid work"},{"label":"B","text":"the cost of producing armaments"},{"label":"C","text":"the estimated cost of damage to the environment"},{"label":"D","text":"the negative impact on the shadow economy"}],"correct":""},{"id":14,"text":"Which statement about national income accounting is correct?","options":[{"label":"A","text":"Depreciation does not need to be subtracted from GDP figures because it has already been taken into account by firms."},{"label":"B","text":"GDP greatly overstates the true value of output because some of the profit it includes is supernormal profit."},{"label":"C","text":"GDP is a better measure of living standards than GNP because net property income from abroad is not available for citizens."},{"label":"D","text":"GNP per capita ignores many important factors that affect citizens' living standards."}],"correct":""},{"id":15,"text":"What describes the multiplier process, as it operates within a closed economy with no government sector?","options":[{"label":"A","text":"Changes in National Income determine the level of investment."},{"label":"B","text":"The level of consumption depends on the level of National Income."},{"label":"C","text":"The levels of consumption and investment together determine the level of National Income."},{"label":"D","text":"When investment changes, there will be a greater change in equilibrium National Income."}],"correct":""},{"id":16,"text":"Which policy does a central bank undertake to pursue quantitative easing?","options":[{"label":"A","text":"purchase long-term government debt from the public"},{"label":"B","text":"purchase short-term government debt from the public"},{"label":"C","text":"sell long-term government debt to the public"},{"label":"D","text":"sell short-term government debt to the public"}],"correct":""},{"id":17,"text":"What would be an increase in leakages or withdrawals from the circular flow of income?","options":[{"label":"A","text":"increase in government spending on anti-smoking campaigns"},{"label":"B","text":"increase in spending on imports of luxury cars"},{"label":"C","text":"increase in spending on transfer payments"},{"label":"D","text":") increase in wages paid to government employees"}],"correct":""},{"id":18,"text":"Which statement would both Keynesian and Monetarist schools of thought accept?","options":[{"label":"A","text":"High inflation and high unemployment are undesirable in a properly-functioning economy."},{"label":"B","text":"Increased government spending on investment projects will always crowd out private investment."},{"label":"C","text":"The best way for an economy to get out of a recession is for the government to increase its expenditure."},{"label":"D","text":"The most effective way to reduce inflation is for the government to exercise tight control over the money supply."}],"correct":""},{"id":19,"text":"In country X the marginal rate of income tax imposed on the highest earners was \\({83}\\%\\) which increased to 98\\% if income was received from interest or dividends. The highest marginal rate was then reduced to 40\\%. Despite this reduction, the tax revenue raised from the highest earners increased substantially. Which theoretical concept illustrates this relationship between tax rates and tax revenue?","options":[{"label":"A","text":"the J curve"},{"label":"B","text":"the Laffer curve"},{"label":"C","text":"the Marshall-Lerner condition"},{"label":"D","text":"the Phillips curve"}],"correct":""},{"id":20,"text":"A government is increasing the role of market forces in its economy. However, it imposed temporary maximum price controls. Why might a government, committed to reducing central planning, introduce price controls?","options":[{"label":"A","text":"to increase allocative efficiency"},{"label":"B","text":"to increase the incentive for producers to raise supply"},{"label":"C","text":"to reduce consumer demand"},{"label":"D","text":"to reduce expectations of inflation"}],"correct":""},{"id":21,"text":"In country X the marginal rate of income tax imposed on the highest earners was \\( {83}\\% \\) which increased to 98% if income was received from interest or dividends. The highest marginal rate was then reduced to 40%. Despite this reduction, the tax revenue raised from the highest earners increased substantially. Which theoretical concept illustrates this relationship between tax rates and tax revenue?","options":[{"label":"A","text":"the J curve"},{"label":"B","text":"the Laffer curve"},{"label":"C","text":"the Marshall-Lerner condition"},{"label":"D","text":"the Phillips curve"}],"correct":""},{"id":22,"text":"An economy adopts an expansionary monetary policy to boost employment. A result of this policy is that the consumer price index rises at an accelerating rate. Which curve could represent this?","options":[{"label":"A","text":"Kuznets curve"},{"label":"B","text":"Laffer curve"},{"label":"C","text":"Lorenz curve"},{"label":"D","text":"Phillips curve"}],"correct":""},{"id":23,"text":"An economy is operating at full employment. Which policy is most likely to lead to an increase in real national output without an increase in the rate of inflation in the short term?","options":[{"label":"A","text":"additional spending on subsidies to increase export earnings"},{"label":"B","text":"the central bank introduces quantitative easing"},{"label":"C","text":"labour market reforms result in increased output per hour worked"},{"label":"D","text":"the government reduces income tax rates"}],"correct":""},{"id":24,"text":"A country's government imposes a tariff on steel imports. What is the likely impact of this tariff on this country's economy?","options":[{"label":"A","text":"It will make this country's steel exports more price competitive."},{"label":"B","text":"It will lead to productive inefficiency in this country's steel industry."},{"label":"C","text":"There will be an improvement in this country's terms of trade."},{"label":"D","text":"There will be a decrease in producer surplus for this country's steel producers."}],"correct":""},{"id":25,"text":"Which measurement is not included in the calculation of the Human Development Index?","options":[{"label":"A","text":"average years of schooling"},{"label":"B","text":"Gross National Income per capita"},{"label":"C","text":"infant mortality rate"},{"label":"D","text":"life expectancy at birth"}],"correct":""}];

const paper_02: MCQQuestion[] = [{"id":1,"text":"What is an argument against government intervention when there is market failure?","options":[{"label":"A","text":"Government intervention could increase positive externalities."},{"label":"B","text":"Government intervention could increase the availability of merit goods."},{"label":"C","text":"Government intervention could lead to a less efficient outcome."},{"label":"D","text":"Government intervention could reduce information failure."}],"correct":""},{"id":2,"text":"Which statement correctly describes the result of a price increase for an inferior good?","options":[{"label":"A","text":"Both the substitution effect and the income effect cause the consumer to buy less of the good."},{"label":"B","text":"Both the substitution effect and the income effect cause the consumer to buy more of the good."},{"label":"C","text":"The substitution effect causes the consumer to buy less of the good and the income effect causes the consumer to buy more of the good."},{"label":"D","text":"The substitution effect causes the consumer to buy more of the good and the income effect causes the consumer to buy less of the good."}],"correct":""},{"id":3,"text":"Which statement about a monopoly is correct?","options":[{"label":"A","text":"Profit maximisation occurs when average cost equals average revenue."},{"label":"B","text":"Sales maximisation occurs when marginal cost equals marginal revenue."},{"label":"C","text":"Sales revenue maximisation occurs when marginal revenue is equal to zero."},{"label":"D","text":"Satisficing occurs when marginal cost is equal to zero."}],"correct":""},{"id":4,"text":"A satellite communications company is bought by an investment bank. Which outcome has resulted from this purchase?","options":[{"label":"A","text":"a cartel"},{"label":"B","text":"diversification"},{"label":"C","text":"lateral integration"},{"label":"D","text":"vertical integration"}],"correct":""},{"id":5,"text":"The diagram shows the long-run average cost (LRAC) curve for a firm, and three short-run average cost (SRAC) curves. Which statement is correct?","options":[{"label":"A","text":"When the minimum point of SRAC3 is lower than the minimum point of SRAC2 it reflects the law of variable proportions."},{"label":"B","text":"The law of diminishing returns explains why each of the SRAC curves is U-shaped."},{"label":"C","text":"The position of SRAC2 shows the minimum efficient scale of production."},{"label":"D","text":"The rising section of SRAC1 indicates the existence of diseconomies of scale."}],"correct":"","image":"/images/econ-a2-mcq/13_540_268_714_366_0.jpg"},{"id":6,"text":"What is the most likely reason that barriers to entry might lead to x-inefficiency?","options":[{"label":"A","text":"The firm does not account for any external benefits."},{"label":"B","text":"The firm has no incentive to cut its costs of production."},{"label":"C","text":"The firm's price is set higher than its average costs."},{"label":"D","text":"The firm's price is set higher than its marginal costs."}],"correct":""},{"id":7,"text":"The diagram shows the long-run cost and revenue curves for a public sector monopoly. The government decides to set a price that maximises social welfare. What will be the consequence of this decision?","options":[{"label":"A","text":"The firm will experience diseconomies of scale."},{"label":"B","text":"The firm will make a loss."},{"label":"C","text":"The firm will maximise profits."},{"label":"D","text":"The firm will maximise total revenue."}],"correct":"","image":"/images/econ-a2-mcq/14_480_234_834_489_0.jpg"},{"id":8,"text":"The information gives the characteristics for a market structure. Which market structure is this most likely to be?","options":[{"label":"A","text":"monopolistic competition"},{"label":"B","text":"monopoly"},{"label":"C","text":"oligopoly"},{"label":"D","text":"perfect competition"}],"correct":""},{"id":9,"text":"In various countries, the supply of public utilities such as water and electricity have been licensed by the government to a few private firms. What should governments do to persuade these profit-seeking private firms not to overcharge consumers?","options":[{"label":"A","text":"allow private firms to merge to create a monopoly"},{"label":"B","text":"appoint a regulatory body to guarantee supplies at all times"},{"label":"C","text":"deregulate nationalised industries to create a free market"},{"label":"D","text":"enable customers to switch easily from one private firm to another"}],"correct":""},{"id":10,"text":"A government intends to use pollution permits to reduce environmental damage. Under what circumstances is this policy most likely to fail to achieve the intended reduction?","options":[{"label":"A","text":"Firms within the scheme are required to have a sufficient number of permits to cover the amount of pollution generated in production."},{"label":"B","text":"Firms improve their technology to reduce the number of permits they require."},{"label":"C","text":"Firms that do not use all of their permits can sell some of them to other firms."},{"label":"D","text":"The permits do not impose strict enough limits on carbon emissions."}],"correct":""},{"id":11,"text":"A government is committed to reducing the Gini coefficient. Which policy is most likely to fail to achieve that policy objective?","options":[{"label":"A","text":"a decrease in ad valorem sales tax rates"},{"label":"B","text":"a more regressive income tax system"},{"label":"C","text":"a more progressive income tax system"},{"label":"D","text":"an increase in transfer payments to the unemployed"}],"correct":""},{"id":12,"text":"Which calculation would give the marginal revenue product (MRP) of labour for a firm selling its product in an imperfectly competitive product market?","options":[{"label":"A","text":"average output produced per worker employed \\(\\times\\) marginal revenue of the product"},{"label":"B","text":"average output produced per worker employed \\(\\times\\) price of the product"},{"label":"C","text":"extra product produced by an additional worker \\(\\times\\) marginal revenue of the product"},{"label":"D","text":"extra product produced by an additional worker \\(\\times\\) price of the product"}],"correct":""},{"id":13,"text":"Which objective would not be suitable for a government if it were seeking sustainable economic growth?","options":[{"label":"A","text":"achieving the highest growth rate by using all the natural resources"},{"label":"B","text":"careful management of the use of non-renewable resources"},{"label":"C","text":"effective protection of the environment, wildlife and landscapes"},{"label":"D","text":"meeting the needs of both its current and future population"}],"correct":""},{"id":14,"text":"What is the difference between a country's gross domestic product and its gross national income?","options":[{"label":"A","text":"capital consumption"},{"label":"B","text":"gross fixed capital formation"},{"label":"C","text":"net property income from abroad"},{"label":"D","text":"the value of exports less imports"}],"correct":""},{"id":15,"text":"Some individuals seek to increase their share of existing wealth without creating new wealth. This can be a problem in developing economies. What is an example of this behaviour?","options":[{"label":"A","text":"a government official taking a bribe for special treatment for the person offering the bribe"},{"label":"B","text":"a land owner renting a field to a farmer"},{"label":"C","text":"a landlord being paid for the hire of a room"},{"label":"D","text":"an entrepreneur earning a reward for setting up a firm that pays low wages"}],"correct":""},{"id":16,"text":"The diagram shows changes in the numbers employed in four different industries in a city between 2015 and 2020. What can be concluded from the diagram?","options":[{"label":"A","text":"Finance was always the largest employer."},{"label":"B","text":"Leisure had the fastest growth rate in employment."},{"label":"C","text":"Manufacturing was the only industry to show signs of decline."},{"label":"D","text":"Total employment in the four industries decreased over the period."}],"correct":"","image":"/images/econ-a2-mcq/18_451_264_897_547_0.jpg"},{"id":17,"text":"Which change will allow an increase in an economy's money supply?","options":[{"label":"A","text":"An outflow of currency for trade and capital purposes becomes an inflow."},{"label":"B","text":"The central bank instructs commercial banks to keep higher ratios of cash to deposits."},{"label":"C","text":"The government budget balance moves from a deficit to a surplus."},{"label":"D","text":"The government replaces borrowing from the banks with borrowing from the general public."}],"correct":""},{"id":18,"text":"The UK gives aid to the Ugandan government to spend on a school. One condition is that they must buy the materials from the UK. Which type of aid does not take place?","options":[{"label":"A","text":"bilateral"},{"label":"B","text":"multilateral"},{"label":"C","text":"project"},{"label":"D","text":"tied"}],"correct":""},{"id":19,"text":"Unemployment in an economy increases. What is a probable consequence?","options":[{"label":"A","text":"a switch from direct to indirect taxation"},{"label":"B","text":"an increase in demand-pull inflation"},{"label":"C","text":"an increase in the balance of trade deficit"},{"label":"D","text":"an increase in the government budget deficit"}],"correct":""},{"id":20,"text":"A government currently has a balanced budget. It is considering the possible variations in tax revenue and government expenditure shown. } Which three options are likely to have the potential to move the budget into surplus?","options":[{"label":"A","text":"W, X and Y B W, X and Z C W, Y and Z D X, Y and Z"},{"label":"B","text":"Permission to reproduce items where third-party owned material protected by copyright is included has been sought and cleared where possible. Every reasonable effort has been made by the publisher (UCLES) to trace copyright holders, but if any items requiring clearance have unwittingly been included, the publisher will be pleased to make amends at the earliest possible opportunity."},{"label":"C","text":"To avoid the issue of disclosure of answer-related information to candidates, all copyright acknowledgements are reproduced online in the Cambridge Assessment International Education Copyright Acknowledgements Booklet. This is produced for each series of examinations and is freely available to download at www.cambridgeinternational.org after the live examination series."},{"label":"D","text":"Cambridge Assessment International Education is part of the Cambridge Assessment Group. Cambridge Assessment is the brand name of the University of Cambridge Local Examinations Syndicate (UCLES), which itself is a department of the University of Cambridge."}],"correct":"","table":"<table><tr><td>tax revenue</td><td>government expenditure</td></tr><tr><td>W</td><td>increase</td><td>increase</td></tr><tr><td>X</td><td>increase</td><td>reduce</td></tr><tr><td>Y</td><td>reduce</td><td>increase</td></tr><tr><td>Z</td><td>reduce</td><td>reduce</td></tr></table>"},{"id":21,"text":"A government currently has a balanced budget. It is considering the possible variations in tax revenue and government expenditure shown. Which three options are likely to have the potential to move the budget into surplus?","options":[{"label":"A","text":"W, X and Y B W, X and Z C W, Y and Z D X, Y and Z"},{"label":"B","text":"Permission to reproduce items where third-party owned material protected by copyright is included has been sought and cleared where possible. Every reasonable effort has been made by the publisher (UCLES) to trace copyright holders, but if any items requiring clearance have unwittingly been included, the publisher will be pleased to make amends at the earliest possible opportunity."},{"label":"C","text":"To avoid the issue of disclosure of answer-related information to candidates, all copyright acknowledgements are reproduced online in the Cambridge Assessment International Education Copyright Acknowledgements Booklet. This is produced for each series of examinations and is freely available to download at www.cambridgeinternational.org after the live examination series."},{"label":"D","text":"Cambridge Assessment International Education is part of the Cambridge Assessment Group. Cambridge Assessment is the brand name of the University of Cambridge Local Examinations Syndicate (UCLES), which itself is a department of the University of Cambridge."}],"correct":"","table":"<table><tr><td>option</td><td>tax revenue</td><td>government expenditure</td></tr><tr><td>W</td><td>increase</td><td>increase</td></tr><tr><td>X</td><td>increase</td><td>reduce</td></tr><tr><td>Y</td><td>reduce</td><td>increase</td></tr><tr><td>Z</td><td>reduce</td><td>reduce</td></tr></table>"},{"id":22,"text":"The table shows data on the unemployment and inflation rates for four countries in 2010 and 2014. } Which countries had a typical Phillips curve?","options":[{"label":"A","text":"Australia and Japan"},{"label":"B","text":"Australia only"},{"label":"C","text":"Japan only"},{"label":"D","text":"Canada and the United States"}],"correct":""},{"id":23,"text":"The turning point on the Kuznets curve for income inequality has been estimated to be in the region of US\\$10500. For a country that has a GDP per capita of \\$8000, what is most likely?","options":[{"label":"A","text":"A reduction in GDP per capita will have no effect on income inequality."},{"label":"B","text":"A reduction in GDP per capita will increase income inequality."},{"label":"C","text":"An increase in GDP per capita will have no effect on income inequality."},{"label":"D","text":"An increase in GDP per capita will increase income inequality."}],"correct":""},{"id":24,"text":"What is the most likely consequence when there is an increase in the national debt?","options":[{"label":"A","text":"the creation of additional money"},{"label":"B","text":"a current account deficit on the balance of payments"},{"label":"C","text":"a surplus in the government's budget"},{"label":"D","text":"the crowding out of private sector investment"}],"correct":""},{"id":25,"text":"Which policy will help to reduce income inequality?","options":[{"label":"A","text":"to increase indirect taxes"},{"label":"B","text":"to increase trade union power"},{"label":"C","text":"to increase the rate of interest"},{"label":"D","text":"to reduce welfare payments"}],"correct":""},{"id":26,"text":"Which policy will help to correct a deficit on the current account of the balance of payments?","options":[{"label":"A","text":"decreasing direct taxes"},{"label":"B","text":"decreasing government regulations"},{"label":"C","text":"increasing exchange rates"},{"label":"D","text":"increasing government spending"}],"correct":""},{"id":27,"text":"The following are four conditions sometimes attached to IMF loans to low-income countries. Which condition would conflict with the 'infant industry' argument?","options":[{"label":"A","text":"the need to allow free trade"},{"label":"B","text":"the need to control inflation"},{"label":"C","text":"the need to have a contractionary fiscal policy"},{"label":"D","text":"the need to privatise government enterprises"}],"correct":""}];

const paper_03: MCQQuestion[] = [{"id":1,"text":"What can be deduced about an economy where no-one can be made better off without making someone else worse off?","options":[{"label":"A","text":"Firms succeed in maximising profits."},{"label":"B","text":"Production causes no external costs or benefits."},{"label":"C","text":"The distribution of income and wealth is perfectly equal."},{"label":"D","text":"The resources of the economy are allocated efficiently."}],"correct":""},{"id":2,"text":"What is equivalent to social benefits?","options":[{"label":"A","text":"the amount that the government spends on social security benefits"},{"label":"B","text":"the benefit gained by society from total government spending"},{"label":"C","text":"the benefit to third parties from household consumption of a good"},{"label":"D","text":") the private and external benefits from household consumption of a good"}],"correct":""},{"id":3,"text":"How can the concept of marginal utility explain the shape of the downward sloping demand curve?","options":[{"label":"A","text":"Consumer tastes and preferences only change when their spending power increases."},{"label":"B","text":"Extra utility gained from consuming successive units of a good will fall continuously."},{"label":"C","text":"Satisfaction of consuming one more unit of a good is greater than the loss of money spent."},{"label":"D","text":"Total utility gained from buying more and more units of a good will continue to increase indefinitely."}],"correct":""},{"id":4,"text":"Small farmers supply all their rice production to a single buyer. Which term best describes this market structure?","options":[{"label":"A","text":"monopolistic"},{"label":"B","text":"monopoly"},{"label":"C","text":"monopsony"},{"label":"D","text":"perfect competition"}],"correct":""},{"id":5,"text":"The diagram shows the marginal cost (MC), average cost (AC), marginal revenue (MR) and average revenue (AR) curves of a profit-maximising, monopolistically competitive firm. Based on its profit, and assuming no market growth, what is likely to happen to the demand for this firm's output in the long run?","options":[{"label":"A","text":"The short-run profit position will encourage other firms to enter the market and the firm's demand curve will shift to the left."},{"label":"B","text":"The short-run profit position will encourage other firms to enter the market and the firm's demand curve will shift to the right."},{"label":"C","text":"The short-run profit position will encourage other firms to exit the market and the firm's demand curve will shift to the left."},{"label":"D","text":"The short-run profit position will encourage other firms to exit the market and the firm's demand curve will shift to the right."}],"correct":"","image":"/images/econ-a2-mcq/40_591_843_614_558_0.jpg"},{"id":6,"text":"A monopoly firm is producing output OT, and selling its product at price OW, thereby maximising its profits, as shown. The government now decides that the firm's operation generates positive externalities, and so gives the firm a subsidy. Assuming that the firm continues to seek maximum profit, what will result?","options":[{"label":"A","text":"The firm continues to produce OT, and price remains at OW."},{"label":"B","text":"The firm continues to produce OT, but charges a lower price."},{"label":"C","text":"The firm increases production above OT, and reduces price."},{"label":"D","text":"The firm reduces production below OT, and reduces price by the amount of the subsidy."}],"correct":"","image":"/images/econ-a2-mcq/41_508_266_782_538_0.jpg"},{"id":7,"text":"In many developed economies, large and small firms often exist side by side in the same industry. What is most likely to explain the survival of the small firms?","options":[{"label":"A","text":"They each offer a much wider range of products."},{"label":"B","text":"They have a higher minimum efficient scale."},{"label":"C","text":"They pay much higher wages to their staff."},{"label":"D","text":"They provide a more personal level of consumer service."}],"correct":""},{"id":8,"text":"What is generally associated with the principal agent problem?","options":[{"label":"A","text":"Directors prefer company growth to greater shareholder dividends."},{"label":"B","text":"Managers ignore workers' concerns about safety in the workplace."},{"label":"C","text":"Shareholders determine the price of products."},{"label":"D","text":"Workers go on strike against managers' reorganisation plans."}],"correct":""},{"id":9,"text":"A government wishes to reduce the negative externalities caused by the use of coal. Which policy should the government use?","options":[{"label":"A","text":"Impose an indirect tax on the production of hydroelectric power."},{"label":"B","text":"Increase income tax."},{"label":"C","text":"Remove any restrictions on coal production."},{"label":"D","text":"Subsidise wind-powered electricity production."}],"correct":""},{"id":10,"text":"What would be an example of 'nudge' theory?","options":[{"label":"A","text":"a subsidy on fresh fruit to increase demand"},{"label":"B","text":"a unit tax on unhealthy food to reduce demand"},{"label":"C","text":"banning all unhealthy food to reduce demand"},{"label":"D","text":"putting fresh fruit at eye level in shops to increase demand"}],"correct":""},{"id":11,"text":"When is a policy of income redistribution from rich people to poor people most appropriate?","options":[{"label":"A","text":"when control of demand-pull inflation is the priority"},{"label":"B","text":"when equality is valued more highly than efficiency"},{"label":"C","text":"when monetary reward is the best incentive to risk-taking"},{"label":"D","text":"when the rich have higher marginal utility curves than the poor"}],"correct":""},{"id":12,"text":"Wages in industry X are significantly higher than in industry Y. What could explain this difference?","options":[{"label":"A","text":"Workers in industry Y are highly mobile."},{"label":"B","text":"Trade union organisation in industry \\(Y\\) is relatively strong."},{"label":"C","text":"Industries \\(X\\) and \\(Y\\) compete with each other for workers."},{"label":"D","text":"Industry Y has non-monetary advantages."}],"correct":""},{"id":13,"text":"Economic growth has both benefits and costs. In which situation would living standards be judged to have definitely increased?","options":[{"label":"A","text":"As countries became industrialised, economic growth led to a fall in hours worked, as well as a rise in real incomes."},{"label":"B","text":"China had a huge rise in real GDP per head in the last 20 years but there was a decrease in air quality in urban areas."},{"label":"C","text":"Economic growth in high-income countries has seen childhood obesity increase, but has also seen increased resources devoted to its treatment."},{"label":"D","text":"The 1990s saw a significant rise in real GDP per head in the US with only a relatively small increase in the Gini coefficient during the same period."}],"correct":""},{"id":14,"text":"What is not included in National Income accounts?","options":[{"label":"A","text":"a gift by a parent to her daughter as a deposit on an apartment"},{"label":"B","text":"Bearnings of a part-time worker in a school dining room"},{"label":"C","text":"interest earned on savings accounts intended for retirement"},{"label":"D","text":"profits re-invested by a company to fund capital expenditure"}],"correct":""},{"id":15,"text":"A government wishes to attract foreign direct investment to assist the development of its economy. What is most likely to encourage this?","options":[{"label":"A","text":"improved health and safety standards for workers"},{"label":"B","text":"increased import quotas"},{"label":"C","text":"increased spending on infrastructure"},{"label":"D","text":"introducing a minimum wage"}],"correct":""},{"id":16,"text":"Which indicator is least likely to be used when measuring the comparative economic development of a country?","options":[{"label":"A","text":"adult literacy rate"},{"label":"B","text":"average life expectancy at birth"},{"label":"C","text":"level of real GNP per head"},{"label":"D","text":"size of population"}],"correct":""},{"id":17,"text":"Which term is given to short-term unemployment when people are changing jobs?","options":[{"label":"A","text":"cyclical"},{"label":"B","text":"frictional"},{"label":"C","text":"seasonal"},{"label":"D","text":"voluntary"}],"correct":""},{"id":18,"text":"Rapid economic growth is claimed by some to harm the environment. Which outcome would not harm the environment?","options":[{"label":"A","text":"the greater mobility of workers resulting from increased vehicle ownership"},{"label":"B","text":"the increased levels of income that reduce fertility rates and family size"},{"label":"C","text":"the relocation of workers from agricultural to manufacturing employment"},{"label":"D","text":") the use of improved technology to access previously inaccessible natural resources"}],"correct":""},{"id":19,"text":"Which statement would be associated with Keynesian economic theory?","options":[{"label":"A","text":"A change in the money supply is the main determinant of the rate of inflation."},{"label":"B","text":"When unemployment falls below its natural rate, there is upward pressure on prices."},{"label":"C","text":"Total spending in the economy affects real output and employment in the short run."},{"label":"D","text":"Wages and prices are flexible so output and employment will always return to its equilibrium rate."}],"correct":""},{"id":20,"text":"In a closed economy with no government sector, the multiplier shows the impact of a change in","options":[{"label":"A","text":"consumption on investment."},{"label":"B","text":"investment on national income."},{"label":"C","text":"national income on consumption."},{"label":"D","text":"national income on investment."}],"correct":""},{"id":21,"text":"What does the Laffer curve show?","options":[{"label":"A","text":"the relationship between the rate of inflation and the rate of unemployment"},{"label":"B","text":"the relationship between the rate of interest and the speculative demand for money"},{"label":"C","text":"the relationship between tax rates and the amount of tax revenue collected by governments"},{"label":"D","text":"the relationship between how two goods can be produced in an economy with given resources"}],"correct":""},{"id":22,"text":"The table shows key macroeconomic indicators for four countries in 2018. } What can be concluded from the table?","options":[{"label":"A","text":"Countries with current account surpluses had low unemployment rates."},{"label":"B","text":"Countries with high economic growth rates had high inflation rates."},{"label":"C","text":"Countries with low economic growth rates had high unemployment rates."},{"label":"D","text":"Countries with positive economic growth rates had current account deficits."}],"correct":"","table":"<table><tr><td>economic growth (% change in GDP per annum)</td><td>unemployment rate (%)</td><td>inflation rate (% change in CPI per annum)</td><td>current account balance (% of GDP)</td></tr><tr><td>Argentina</td><td>-6.2</td><td>9.1</td><td>50.7</td><td>-4.8</td></tr><tr><td>China</td><td>6.4</td><td>3.8</td><td>1.5</td><td>0.4</td></tr><tr><td>Italy</td><td>0</td><td>10.7</td><td>0.9</td><td>2.6</td></tr><tr><td>United States</td><td>3.0</td><td>3.8</td><td>1.5</td><td>-2.4</td></tr></table>"},{"id":23,"text":"The table shows key macroeconomic indicators for four countries in 2018. What can be concluded from the table?","options":[{"label":"A","text":"Countries with current account surpluses had low unemployment rates."},{"label":"B","text":"Countries with high economic growth rates had high inflation rates."},{"label":"C","text":"Countries with low economic growth rates had high unemployment rates."},{"label":"D","text":"Countries with positive economic growth rates had current account deficits."}],"correct":"","table":"<table><tr><td></td><td>economic growth (% change in GDP per annum)</td><td>unemployment rate (%)</td><td>inflation rate (% change in CPI per annum)</td><td>current account balance (% of GDP)</td></tr><tr><td>Argentina</td><td>-6.2</td><td>9.1</td><td>50.7</td><td>-4.8</td></tr><tr><td>China</td><td>6.4</td><td>3.8</td><td>1.5</td><td>0.4</td></tr><tr><td>Italy</td><td>0</td><td>10.7</td><td>0.9</td><td>2.6</td></tr><tr><td>United States</td><td>3.0</td><td>3.8</td><td>1.5</td><td>-2.4</td></tr></table>"},{"id":24,"text":"In 2021, a very large cargo ship carrying over 18000 cargo containers blocked the Suez Canal for seven days. It delayed over 350 other cargo ships, causing shortages of products in markets around the world as supplies were disrupted. Which consequence of globalisation is best illustrated by this event?","options":[{"label":"A","text":"cheaper products for consumers"},{"label":"B","text":"greater choice of products for consumers"},{"label":"C","text":"increased interdependence between countries"},{"label":"D","text":"increased migration of labour between countries"}],"correct":""},{"id":25,"text":"Under which circumstances will low wages and low-cost land in a low-income country not attract foreign investment in manufacturing?","options":[{"label":"A","text":"if the country creates genuine independence for their central bank"},{"label":"B","text":"if the country embarks on a programme of privatisation"},{"label":"C","text":"if the country lacks well-developed infrastructure"},{"label":"D","text":"if the country permits repatriation of profits"}],"correct":""},{"id":26,"text":"In an economy, the marginal propensity to consume is 0.2, the marginal propensity to save is 0.3, the marginal propensity to tax is 0.3 and the marginal propensity to import is 0.2 at all levels of income. What would be the most likely consequence of an increase in government expenditure of \\$1000m?","options":[{"label":"A","text":"Import expenditure would increase by \\$200m."},{"label":"B","text":"Import expenditure would increase by \\$1000m."},{"label":"C","text":"Tax revenues would increase by \\(\\$ {75}\\mathrm{\\;m}\\) ."},{"label":"D","text":"Tax revenues would increase by \\(\\$ {375}\\mathrm{\\;m}\\) ."}],"correct":""},{"id":27,"text":"A developing (low-income) economy is heavily dependent on the production of primary products. A multinational car manufacturing company invests in the country and builds a new factory. What will not be a long lasting benefit of the company's investment in the developing economy?","options":[{"label":"A","text":"The company introduces new technology to the economy."},{"label":"B","text":"The company provides diversification of production for the economy."},{"label":"C","text":"The company provides skills training for local workers."},{"label":"D","text":"The company purchases non-renewable local construction materials for the factory."}],"correct":""},{"id":28,"text":"An economy adopts an expansionary monetary policy to boost employment. A result of this policy is that the consumer price index rises at an accelerating rate. Which curve could represent this?","options":[{"label":"A","text":"Kuznets curve"},{"label":"B","text":"Laffer curve"},{"label":"C","text":"Lorenz curve"},{"label":"D","text":"Phillips curve"}],"correct":""},{"id":29,"text":"An economy is operating at full employment. Which policy is most likely to lead to an increase in real national output without an increase in the rate of inflation in the short term?","options":[{"label":"A","text":"additional spending on subsidies to increase export earnings"},{"label":"B","text":"the central bank introduces quantitative easing"},{"label":"C","text":"labour market reforms result in increased output per hour worked"},{"label":"D","text":"the government reduces income tax rates"}],"correct":""}];

const paper_04: MCQQuestion[] = [{"id":1,"text":"Which statement identifies the condition necessary to achieve Pareto optimality?","options":[{"label":"A","text":"All consumers maximise their utility subject to their available income."},{"label":"B","text":"It is not possible to produce greater output with the resources available."},{"label":"C","text":"It is not possible to reallocate resources to make someone better off without someone else becoming worse off."},{"label":"D","text":"Potential losers from any reallocation of resources cannot be compensated by those who gain."}],"correct":""},{"id":2,"text":"The diagram shows a production possibility curve (LM) for an economy producing agricultural goods and manufacturing goods. What can be concluded from the diagram?","options":[{"label":"A","text":"The economy must be allocatively efficient at point R."},{"label":"B","text":"The economy is Pareto efficient at point T."},{"label":"C","text":"The economy is productively efficient at point S."},{"label":"D","text":"The opportunity cost is constant as we move from L to M."}],"correct":"","image":"/images/econ-a2-mcq/48_533_689_728_484_0.jpg"},{"id":3,"text":"The private benefit of an activity is greater than the private cost. The social benefit of the same activity is less than the social cost. What must be true of the activity?","options":[{"label":"A","text":"external benefit = external cost"},{"label":"B","text":"external benefit > external cost"},{"label":"C","text":"external benefit < external cost"},{"label":"D","text":"external benefit > private benefit"}],"correct":""},{"id":4,"text":"What is the central principle of marginal utility theory?","options":[{"label":"A","text":"As more is consumed of a normal good, the additional satisfaction gained increases."},{"label":"B","text":"Consumers are in equilibrium when the marginal utility gained from good X equals the price of good Y."},{"label":"C","text":"Consumers are in equilibrium when the ratio of the marginal utility of goods X and Y are equal to the ratio of their prices."},{"label":"D","text":"Consumers are in equilibrium when the total utility gained from good X is the same as gained from good Y."}],"correct":""},{"id":5,"text":"Firms in a market decide to collude over the price that they charge for their products. What is not likely to be a feature of the market?","options":[{"label":"A","text":"Firms have similar cost structures."},{"label":"B","text":"Products of the firms are close substitutes."},{"label":"C","text":"There are high barriers to entry into the market."},{"label":"D","text":"There is a large number of competing firms."}],"correct":""},{"id":6,"text":"Firms often remain small even when growth could result in technical economies of scale. What is not a likely reason for this?","options":[{"label":"A","text":"Demand for the product tends to change often and rapidly."},{"label":"B","text":"Individual entrepreneurs wish to keep a tight personal control over their own firm."},{"label":"C","text":"The entrepreneurs who establish the firms tend to be ambitious risk-takers."},{"label":"D","text":"The market in which they operate is very specialised in nature, often selling unique products."}],"correct":""},{"id":7,"text":"The diagram shows the short-run equilibrium for a firm operating in a monopolistically competitive market. What is not likely to occur at the long-run equilibrium?","options":[{"label":"A","text":"The individual firm's demand curve is more elastic."},{"label":"B","text":"The individual firm's demand curve has moved left."},{"label":"C","text":"The profit-maximising price is greater than average cost."},{"label":"D","text":"The profit-maximising price is greater than marginal cost."}],"correct":"","image":"/images/econ-a2-mcq/50_496_1108_799_516_0.jpg"},{"id":8,"text":"In which circumstance would direct provision of a product by the government be least likely?","options":[{"label":"A","text":"when fixed costs are very high"},{"label":"B","text":"when the demand for the product is very high but unit costs are low"},{"label":"C","text":"when the industry faces large natural barriers to entry"},{"label":"D","text":"when the minimum efficient scale of production is above the level of demand at current prices"}],"correct":""},{"id":9,"text":"What would encourage an increase in the number of small firms?","options":[{"label":"A","text":"increasing government regulation of conditions in the workplace"},{"label":"B","text":"more risk-averse (cautious) lending policies by banks"},{"label":"C","text":"stronger government laws against the growth of monopoly"},{"label":"D","text":"tougher penalties in the case of personal bankruptcy"}],"correct":""},{"id":10,"text":"What is not a source of market failure?","options":[{"label":"A","text":"imperfect information"},{"label":"B","text":"income inequality"},{"label":"C","text":"monopoly"},{"label":"D","text":"non-excludability"}],"correct":""},{"id":11,"text":"What is an example of 'nudge' theory when applied to encouraging healthy eating?","options":[{"label":"A","text":"advertising the benefits of healthy eating"},{"label":"B","text":"increasing tax on sugary foods"},{"label":"C","text":"introducing a subsidy for fruit growers"},{"label":"D","text":"supermarkets putting fruit near cash registers"}],"correct":""},{"id":12,"text":"What is a definition of transfer earnings?","options":[{"label":"A","text":"the amount of earnings above that needed to keep a worker in their current job"},{"label":"B","text":"the minimum earnings needed to keep a worker in their current job"},{"label":"C","text":"the social security benefits paid to workers whose earnings are below the poverty line"},{"label":"D","text":"the amount of earnings needed to cause a worker to change to a different job"}],"correct":""},{"id":13,"text":"The chart gives information about the average daily wage rate for all industries in India. What could have caused this trend in wage rates?","options":[{"label":"A","text":"an increase in capital-intensive production"},{"label":"B","text":"an increase in the number of industrial workers"},{"label":"C","text":"an increase in the number of people unemployed"},{"label":"D","text":") an increase in the productivity of labour"}],"correct":"","image":"/images/econ-a2-mcq/53_460_234_880_523_0.jpg"},{"id":14,"text":"What could cause the official statistics for the national income per head of a developing country to overstate the true level of economic well-being of its inhabitants?","options":[{"label":"A","text":"if there is dependence on barter in internal trade"},{"label":"B","text":"if subsistence agriculture dominates total economic activity"},{"label":"C","text":"if services are an important component of exports"},{"label":"D","text":"if there is extreme income inequality"}],"correct":""},{"id":15,"text":"What is shown by the Kuznets curve?","options":[{"label":"A","text":"the rise and then fall in the balance of trade deficit following a devaluation"},{"label":"B","text":"the rise and then fall in the economic growth rate as the GDP increases"},{"label":"C","text":"the rise and then fall in inequality as the level of income per head rises"},{"label":"D","text":"the rise and then fall in tax revenue as the tax rate is increased"}],"correct":""},{"id":16,"text":"Which type of unemployment is associated with a deficiency in aggregate demand?","options":[{"label":"A","text":"cyclical"},{"label":"B","text":"frictional"},{"label":"C","text":"structural"},{"label":"D","text":"voluntary"}],"correct":""},{"id":17,"text":"There has been a switch in demand from goods produced by labour-intensive methods of production to similar goods produced using high-technology methods of production. This has led to an overall increase in unemployment. What is the best policy to reduce this type of unemployment?","options":[{"label":"A","text":"reduce the rate of income tax"},{"label":"B","text":"increase the rate of interest on borrowing for investment"},{"label":"C","text":"subsidise products produced by labour-intensive methods"},{"label":"D","text":"subsidise exports produced by high-technology industries"}],"correct":""},{"id":18,"text":"What would not exist in a free-market, open economy?","options":[{"label":"A","text":"autonomous investment"},{"label":"B","text":"household saving"},{"label":"C","text":"import spending"},{"label":"D","text":"indirect taxation"}],"correct":""},{"id":19,"text":"What is most likely to be found in an economy with a positive output gap?","options":[{"label":"A","text":"a higher potential than actual GDP"},{"label":"B","text":"high unemployment"},{"label":"C","text":"inflation"},{"label":"D","text":"low labour costs"}],"correct":""},{"id":20,"text":"Which statement about the Keynesian liquidity preference demand for money model is correct?","options":[{"label":"A","text":"Both the transactions and precautionary motives for holding liquidity are interest rate elastic."},{"label":"B","text":"The demand for liquidity is completely interest rate inelastic at low rates of interest."},{"label":"C","text":"The demand to hold liquidity by households is stable."},{"label":"D","text":"The rate of interest on long-term government securities is inversely related to their price."}],"correct":""},{"id":21,"text":"An increase in which factor will cause a decrease in investment spending?","options":[{"label":"A","text":"business confidence"},{"label":"B","text":"company profits"},{"label":"C","text":"interest rates"},{"label":"D","text":"national income"}],"correct":""},{"id":22,"text":"The diagram shows the relationship between tax revenue and the tax rate. What is the curve on the diagram called?","options":[{"label":"A","text":"income elasticity curve"},{"label":"B","text":"J curve"},{"label":"C","text":"Lorenz curve"},{"label":"D","text":"Laffer curve"}],"correct":"","image":"/images/econ-a2-mcq/56_601_583_598_432_0.jpg"},{"id":23,"text":"The table shows the rate of inflation (consumer prices index) and the monthly percentage rate of unemployment for the USA over a six month period in 2017. } What can be concluded from this table?","options":[{"label":"A","text":"Falling inflation leads to lower unemployment."},{"label":"B","text":"Increasing inflation leads to rising unemployment."},{"label":"C","text":"The rate of inflation correlates exactly with the rate of unemployment."},{"label":"D","text":"The rate of inflation has a marginal effect on the rate of unemployment."}],"correct":"","table":"<table><tr><td>April</td><td>May</td><td>June</td><td>July</td><td>Aug</td><td>Sept</td></tr><tr><td>rate of inflation (%)</td><td>2.2</td><td>1.9</td><td>1.6</td><td>1.7</td><td>1.9</td><td>2.2</td></tr><tr><td>rate of unemployment (%)</td><td>3.9</td><td>3.8</td><td>3.9</td><td>3.9</td><td>3.8</td><td>3.7</td></tr></table>"},{"id":24,"text":"The table shows the rate of inflation (consumer prices index) and the monthly percentage rate of unemployment for the USA over a six month period in 2017. What can be concluded from this table?","options":[{"label":"A","text":"Falling inflation leads to lower unemployment."},{"label":"B","text":"Increasing inflation leads to rising unemployment."},{"label":"C","text":"The rate of inflation correlates exactly with the rate of unemployment."},{"label":"D","text":"The rate of inflation has a marginal effect on the rate of unemployment."}],"correct":"","table":"<table><tr><td>month</td><td>April</td><td>May</td><td>June</td><td>July</td><td>Aug</td><td>Sept</td></tr><tr><td>rate of inflation (%)</td><td>2.2</td><td>1.9</td><td>1.6</td><td>1.7</td><td>1.9</td><td>2.2</td></tr><tr><td>rate of unemployment (%)</td><td>3.9</td><td>3.8</td><td>3.9</td><td>3.9</td><td>3.8</td><td>3.7</td></tr></table>"},{"id":25,"text":"What is most likely to cause the living standards of a country to rise?","options":[{"label":"A","text":"an increase in the number of doctors"},{"label":"B","text":"an increase in the gold reserves"},{"label":"C","text":"an increase in the number of people per house"},{"label":"D","text":"an increase in the money supply"}],"correct":""},{"id":26,"text":"The table shows data on the unemployment and inflation rates for four countries in 2010 and 2014. } Which countries had a typical Phillips curve?","options":[{"label":"A","text":"Australia and Japan"},{"label":"B","text":"Australia only"},{"label":"C","text":"Japan only"},{"label":"D","text":"Canada and the United States"}],"correct":""},{"id":27,"text":"The turning point on the Kuznets curve for income inequality has been estimated to be in the region of US\\$10500. For a country that has a GDP per capita of \\$8000, what is most likely?","options":[{"label":"A","text":"A reduction in GDP per capita will have no effect on income inequality."},{"label":"B","text":"A reduction in GDP per capita will increase income inequality."},{"label":"C","text":"An increase in GDP per capita will have no effect on income inequality."},{"label":"D","text":"An increase in GDP per capita will increase income inequality."}],"correct":""}];

const paper_05: MCQQuestion[] = [{"id":1,"text":"The diagram shows a firm producing at \\({Q}_{1}\\) on short-run average cost SRAC1. Which strategy will achieve the greatest reduction in average costs at this output?","options":[{"label":"A","text":"increasing its fixed factors of production only"},{"label":"B","text":"increasing its fixed and variable factors of production"},{"label":"C","text":"reducing its fixed factors of production only"},{"label":"D","text":"reducing its fixed and variable factors of production"}],"correct":"","image":"/images/econ-a2-mcq/73_523_598_754_530_0.jpg"},{"id":2,"text":"Which change would make it easier for a cartel to operate effectively?","options":[{"label":"A","text":"an increase in competition from closely related industries"},{"label":"B","text":"an increase in the number of firms in the industry"},{"label":"C","text":"an increase in the range of products made by cartel members"},{"label":"D","text":"an increase in the stability of the market for its products"}],"correct":""},{"id":3,"text":"Some workers in a low-paid job decide to work longer hours to increase their disposable income. However, this decision reduces state-provided benefits, leaving them worse off. What does this describe?","options":[{"label":"A","text":"debt trap"},{"label":"B","text":"liquidity trap"},{"label":"C","text":"poverty trap"},{"label":"D","text":"unemployment trap"}],"correct":""},{"id":4,"text":"What indicates that nationalisation has taken place?","options":[{"label":"A","text":"a firm buys supplies locally rather than from international sources"},{"label":"B","text":"a firm moves from private ownership to state ownership"},{"label":"C","text":"a firm restricts ownership of its shares to citizens of its own country"},{"label":"D","text":"a firm switches sales to the domestic market from the international market"}],"correct":""},{"id":5,"text":"Too many flights in the airline industry cause unnecessary damage to the environment. Which measure is most likely to result in the socially optimal number of flights?","options":[{"label":"A","text":"a complete ban on flights removing all private and external costs"},{"label":"B","text":"greater deregulation of the global airline industry"},{"label":"C","text":"publishing information to highlight the negative effects of flying on the environment"},{"label":"D","text":"the payment of a subsidy per passenger equal to the difference between the private and social benefit"}],"correct":""},{"id":6,"text":"What would not be regarded as an example of a possible negative impact of rapid economic growth?","options":[{"label":"A","text":"Greater production could result in greater atmospheric pollution."},{"label":"B","text":"A higher level of income could cause a higher balance of trade deficit."},{"label":"C","text":"Increased AD could cause domestic inflation to increase."},{"label":"D","text":"Increased GDP could generate greater tax receipts."}],"correct":""},{"id":7,"text":"How can GDP at market prices be calculated if GDP at factor cost is known?","options":[{"label":"A","text":"add taxes, add subsidies"},{"label":"B","text":"add taxes, subtract subsidies"},{"label":"C","text":"subtract taxes, add subsidies"},{"label":"D","text":"subtract taxes, subtract subsidies"}],"correct":""},{"id":8,"text":"Which statement about unemployment is correct?","options":[{"label":"A","text":"Cyclical unemployment is caused by the occupational immobility of labour."},{"label":"B","text":"Frictional unemployment is caused by a lack of information on jobs in the labour market."},{"label":"C","text":"Structural unemployment is caused by a deficiency in aggregate demand."},{"label":"D","text":"Voluntary unemployment is caused by variations in the demand for labour in the year."}],"correct":""},{"id":9,"text":"The graph shows the percentage unemployed in a country for the period 2017-2021. What is the most likely cause of the change in unemployment?","options":[{"label":"A","text":"a reduction in government expenditure"},{"label":"B","text":"a reduction in interest rates"},{"label":"C","text":"a reduction in investment by firms"},{"label":"D","text":"a slowdown in growth in the global economy"}],"correct":"","image":"/images/econ-a2-mcq/76_557_1091_684_449_0.jpg"},{"id":10,"text":"What is the definition of liquidity?","options":[{"label":"A","text":"the ability of the foreign exchange market to buy foreign currency"},{"label":"B","text":"the support a central bank provides for commercial banks"},{"label":"C","text":"the ease with which an asset can be converted into cash"},{"label":"D","text":"the reaction of governments to a global financial crisis"}],"correct":""},{"id":11,"text":"What will decrease if an open economy experiences a positive output gap?","options":[{"label":"A","text":"general price level"},{"label":"B","text":"import spending"},{"label":"C","text":"spare capacity"},{"label":"D","text":"wage rates"}],"correct":""},{"id":12,"text":"Which statement does not correctly characterise the Monetarist view of the way in which the economy operates?","options":[{"label":"A","text":"Inflation is always caused by increases in the money supply in the long run."},{"label":"B","text":"The long-run aggregate supply curve is vertical in shape."},{"label":"C","text":"The velocity of circulation of money is highly unstable."},{"label":"D","text":"Wages are flexible both upwards and downwards."}],"correct":""},{"id":13,"text":"In an economy, the marginal propensity to consume is 0.2, the marginal propensity to save is 0.3, the marginal propensity to tax is 0.3 and the marginal propensity to import is 0.2 at all levels of income. What would be the most likely consequence of an increase in government expenditure of \\$1000m?","options":[{"label":"A","text":"Import expenditure would increase by \\(\\$ {200}\\mathrm{\\;m}\\) ."},{"label":"B","text":"Import expenditure would increase by \\(\\$ {1000}\\mathrm{\\;m}\\) ."},{"label":"C","text":"Tax revenues would increase by \\(\\$ {75}\\mathrm{\\;m}\\) ."},{"label":"D","text":"Tax revenues would increase by \\(\\$ {375}\\mathrm{\\;m}\\) ."}],"correct":""},{"id":14,"text":"A developing (low-income) economy is heavily dependent on the production of primary products. A multinational car manufacturing company invests in the country and builds a new factory. What will not be a long lasting benefit of the company's investment in the developing economy?","options":[{"label":"A","text":"The company introduces new technology to the economy."},{"label":"B","text":"The company provides diversification of production for the economy."},{"label":"C","text":"The company provides skills training for local workers."},{"label":"D","text":"The company purchases non-renewable local construction materials for the factory."}],"correct":""},{"id":15,"text":"An economy adopts an expansionary monetary policy to boost employment. A result of this policy is that the consumer price index rises at an accelerating rate. Which curve could represent this?","options":[{"label":"A","text":"Kuznets curve"},{"label":"B","text":"Laffer curve"},{"label":"C","text":"Lorenz curve"},{"label":"D","text":"Phillips curve"}],"correct":""},{"id":16,"text":"An economy is operating at full employment. Which policy is most likely to lead to an increase in real national output without an increase in the rate of inflation in the short term?","options":[{"label":"A","text":"additional spending on subsidies to increase export earnings"},{"label":"B","text":"the central bank introduces quantitative easing"},{"label":"C","text":"labour market reforms result in increased output per hour worked"},{"label":"D","text":"the government reduces income tax rates"}],"correct":""},{"id":17,"text":"The chart gives information about the average daily wage rate for all industries in India. What could have caused this trend in wage rates?","options":[{"label":"A","text":"an increase in capital-intensive production"},{"label":"B","text":"an increase in the number of industrial workers"},{"label":"C","text":"an increase in the number of people unemployed"},{"label":"D","text":") an increase in the productivity of labour"}],"correct":"","image":"/images/econ-a2-mcq/53_460_234_880_523_0.jpg"},{"id":18,"text":"What could cause the official statistics for the national income per head of a developing country to overstate the true level of economic well-being of its inhabitants?","options":[{"label":"A","text":"if there is dependence on barter in internal trade"},{"label":"B","text":"if subsistence agriculture dominates total economic activity"},{"label":"C","text":"if services are an important component of exports"},{"label":"D","text":"if there is extreme income inequality"}],"correct":""},{"id":19,"text":"What is shown by the Kuznets curve?","options":[{"label":"A","text":"the rise and then fall in the balance of trade deficit following a devaluation"},{"label":"B","text":"the rise and then fall in the economic growth rate as the GDP increases"},{"label":"C","text":"the rise and then fall in inequality as the level of income per head rises"},{"label":"D","text":"the rise and then fall in tax revenue as the tax rate is increased"}],"correct":""},{"id":20,"text":"Which type of unemployment is associated with a deficiency in aggregate demand?","options":[{"label":"A","text":"cyclical"},{"label":"B","text":"frictional"},{"label":"C","text":"structural"},{"label":"D","text":"voluntary"}],"correct":""},{"id":21,"text":"There has been a switch in demand from goods produced by labour-intensive methods of production to similar goods produced using high-technology methods of production. This has led to an overall increase in unemployment. What is the best policy to reduce this type of unemployment?","options":[{"label":"A","text":"reduce the rate of income tax"},{"label":"B","text":"increase the rate of interest on borrowing for investment"},{"label":"C","text":"subsidise products produced by labour-intensive methods"},{"label":"D","text":"subsidise exports produced by high-technology industries"}],"correct":""},{"id":22,"text":"What would not exist in a free-market, open economy?","options":[{"label":"A","text":"autonomous investment"},{"label":"B","text":"household saving"},{"label":"C","text":"import spending"},{"label":"D","text":"indirect taxation"}],"correct":""},{"id":23,"text":"What is most likely to be found in an economy with a positive output gap?","options":[{"label":"A","text":"a higher potential than actual GDP"},{"label":"B","text":"high unemployment"},{"label":"C","text":"inflation"},{"label":"D","text":"low labour costs"}],"correct":""},{"id":24,"text":"Which statement about the Keynesian liquidity preference demand for money model is correct?","options":[{"label":"A","text":"Both the transactions and precautionary motives for holding liquidity are interest rate elastic."},{"label":"B","text":"The demand for liquidity is completely interest rate inelastic at low rates of interest."},{"label":"C","text":"The demand to hold liquidity by households is stable."},{"label":"D","text":"The rate of interest on long-term government securities is inversely related to their price."}],"correct":""},{"id":25,"text":"An increase in which factor will cause a decrease in investment spending?","options":[{"label":"A","text":"business confidence"},{"label":"B","text":"company profits"},{"label":"C","text":"interest rates"},{"label":"D","text":"national income"}],"correct":""},{"id":26,"text":"The diagram shows the relationship between tax revenue and the tax rate. What is the curve on the diagram called?","options":[{"label":"A","text":"income elasticity curve"},{"label":"B","text":"J curve"},{"label":"C","text":"Lorenz curve"},{"label":"D","text":"Laffer curve"}],"correct":"","image":"/images/econ-a2-mcq/56_601_583_598_432_0.jpg"},{"id":27,"text":"The table shows the rate of inflation (consumer prices index) and the monthly percentage rate of unemployment for the USA over a six month period in 2017. What can be concluded from this table?","options":[{"label":"A","text":"Falling inflation leads to lower unemployment."},{"label":"B","text":"Increasing inflation leads to rising unemployment."},{"label":"C","text":"The rate of inflation correlates exactly with the rate of unemployment."},{"label":"D","text":"The rate of inflation has a marginal effect on the rate of unemployment."}],"correct":"","table":"<table><tr><td>month</td><td>April</td><td>May</td><td>June</td><td>July</td><td>Aug</td><td>Sept</td></tr><tr><td>rate of inflation (%)</td><td>2.2</td><td>1.9</td><td>1.6</td><td>1.7</td><td>1.9</td><td>2.2</td></tr><tr><td>rate of unemployment (%)</td><td>3.9</td><td>3.8</td><td>3.9</td><td>3.9</td><td>3.8</td><td>3.7</td></tr></table>"},{"id":28,"text":"In 2021, a very large cargo ship carrying over 18000 cargo containers blocked the Suez Canal for seven days. It delayed over 350 other cargo ships, causing shortages of products in markets around the world as supplies were disrupted. Which consequence of globalisation is best illustrated by this event?","options":[{"label":"A","text":"cheaper products for consumers"},{"label":"B","text":"greater choice of products for consumers"},{"label":"C","text":"increased interdependence between countries"},{"label":"D","text":"increased migration of labour between countries"}],"correct":""},{"id":29,"text":"Under which circumstances will low wages and low-cost land in a low-income country not attract foreign investment in manufacturing?","options":[{"label":"A","text":"if the country creates genuine independence for their central bank"},{"label":"B","text":"if the country embarks on a programme of privatisation"},{"label":"C","text":"if the country lacks well-developed infrastructure"},{"label":"D","text":"if the country permits repatriation of profits"}],"correct":""}];

const paper_06: MCQQuestion[] = [{"id":1,"text":"What is most likely to improve the allocative efficiency of a market?","options":[{"label":"A","text":"a higher market concentration ratio"},{"label":"B","text":"collusion between firms in the market"},{"label":"C","text":"entry of new firms into the market"},{"label":"D","text":"mergers of firms in the market"}],"correct":""},{"id":2,"text":"Which statement about a budget line in consumer behaviour theory is correct?","options":[{"label":"A","text":"It illustrates consumer preference between two goods."},{"label":"B","text":"It illustrates combinations of two goods that consumers are able to purchase with a given income."},{"label":"C","text":"It illustrates the least cost combination of goods that yield the same level of utility."},{"label":"D","text":"It illustrates the income effect of a price change."}],"correct":""},{"id":3,"text":"When the price of a good increases, which statement is correct according to the analysis that uses budget lines and indifference curves?","options":[{"label":"A","text":"The income and substitution effects of the price increase will work in opposite directions in the case of a Giffen good."},{"label":"B","text":"The income effect of the price increase will result in reduced consumption for all goods."},{"label":"C","text":"The new equilibrium position will be where the new budget line meets the original indifference curve."},{"label":"D","text":"The price rise will be represented by a parallel shift inwards of the original budget line."}],"correct":""},{"id":4,"text":"The diagram shows short-run average cost curves (SRAC) and the long-run average cost curve (LRAC) for a firm. Which statement is correct?","options":[{"label":"A","text":"When each of the three SRAC curves is U-shaped it shows the existence of economies of scale."},{"label":"B","text":"When the LRAC curve is upward-sloping beyond output OQ it shows the existence of diseconomies of scale."},{"label":"C","text":"When the minimum point of \\({\\mathrm{{SRAC}}}_{2}\\) is below that of \\({\\mathrm{{SRAC}}}_{1}\\) it shows the existence of the law of variable proportions."},{"label":"D","text":"When the minimum point of \\({\\mathrm{{SRAC}}}_{2}\\) is below that of \\({\\mathrm{{SRAC}}}_{3}\\) it shows the existence of economies of scale."}],"correct":"","image":"/images/econ-a2-mcq/83_407_1014_987_439_0.jpg"},{"id":5,"text":"Which phrase best describes the market structure illustrated by the diagram if the firm produces at output \\({Q}_{1}\\) ?","options":[{"label":"A","text":"a monopolistic firm in short-run equilibrium"},{"label":"B","text":"a monopoly making supernormal profits"},{"label":"C","text":"an oligopoly engaged in a price war"},{"label":"D","text":"a non-profit maximising state monopoly"}],"correct":"","image":"/images/econ-a2-mcq/85_522_843_746_690_0.jpg"},{"id":6,"text":"The government wants to regulate the consumption of a demerit good in order to increase society's net welfare. In which situation will society's net welfare increase?","options":[{"label":"A","text":"The fall in the marginal social benefit is greater than the fall in the marginal social cost."},{"label":"B","text":"The fall in the marginal external cost is greater than the fall in the marginal external benefit."},{"label":"C","text":"The fall in the total social benefit is greater than the fall in the total social cost."},{"label":"D","text":"The fall in the total social cost is greater than the fall in the total social benefit."}],"correct":""},{"id":7,"text":"Governments often aim to reduce income inequalities. The diagram shows the effects of using taxation and benefits to try to achieve this aim. average income per household (\\$ per year) What can be concluded from the diagram about the effects of taxes and benefits?","options":[{"label":"A","text":"All income groups are better off except those originally earning more than \\$40000 per year."},{"label":"B","text":"Benefits paid to the lower income groups are not a burden because they are not paid out of tax revenues."},{"label":"C","text":"The average final income of the top 20\\% exceeds the combined final incomes of the other groups."},{"label":"D","text":"The progressive taxation system still favours the top \\({20}\\%\\) over the bottom \\({20}\\%\\) of households."}],"correct":"","image":"/images/econ-a2-mcq/86_386_724_1214_673_0.jpg"},{"id":8,"text":"Which policy is likely to be the least effective means of producing a more equal distribution of income amongst households?","options":[{"label":"A","text":"the imposition of minimum wage levels below the levels produced by the market"},{"label":"B","text":"the introduction of progressive personal income taxes"},{"label":"C","text":"the payment of benefits to low income households"},{"label":"D","text":"the removal of sales taxes on food consumed by lower income households"}],"correct":""},{"id":9,"text":"When is a trade union less likely to gain a large pay rise for its workers?","options":[{"label":"A","text":"It represents a large proportion of the workforce in the company."},{"label":"B","text":"It represents a workforce that has an elastic demand for its labour."},{"label":"C","text":"It represents a workforce that is increasing its labour productivity."},{"label":"D","text":"It represents a workforce that works for a highly profitable monopoly firm."}],"correct":""},{"id":10,"text":"Which statement does not support the view that extraction of mineral resources by a foreign company will make it more difficult for a developing economy to achieve future economic growth?","options":[{"label":"A","text":"Exports of these mineral resources will result in an appreciation of the exchange rate."},{"label":"B","text":"Reduced tax rates aimed at encouraging the foreign company to invest in the country will increase inflation."},{"label":"C","text":"The foreign company will raise the skill levels of the local population through training schemes."},{"label":"D","text":"The foreign company will send profits back to its own country."}],"correct":""},{"id":11,"text":"Growth rates can be calculated using changes in the value of GDP from year to year. Why is real GDP considered to be a better indicator than nominal GDP for this calculation?","options":[{"label":"A","text":"Real GDP adjusts for price changes by using a base year."},{"label":"B","text":"Real GDP ignores the effects of fluctuations in exchange rates on purchasing power."},{"label":"C","text":"Real GDP includes changes in the size of the population."},{"label":"D","text":"Real GDP measures GDP at factor cost rather than market prices."}],"correct":""},{"id":12,"text":"Why is disaster relief money sent by non-governmental organisations to a South American country not classified as official foreign aid?","options":[{"label":"A","text":"It does not finance a long-term investment programme."},{"label":"B","text":"It does not incur payment of interest."},{"label":"C","text":"It is not supplied by a government."},{"label":"D","text":"Only countries in Asia and Africa are classified as developing."}],"correct":""},{"id":13,"text":"What is a cause of seasonal unemployment?","options":[{"label":"A","text":"a general decrease in the demand for goods and services"},{"label":"B","text":"a lack of necessary skills in the workforce"},{"label":"C","text":"a temporary change in the pattern of consumers' expenditure"},{"label":"D","text":"an unwillingness of workers to move to other parts of the country where there is work"}],"correct":""},{"id":14,"text":"A firm initially employs 50 workers, each working 40 hours a week, and produces a total output of 18000 units. It then employs an additional 10 workers, again each working 40 hours, and total output rises to 19200 units. Which effect does this rise in employment have on labour productivity per hour?","options":[{"label":"A","text":"decreases it by 1 unit"},{"label":"B","text":"decreases it by 40 units"},{"label":"C","text":"increases it by 120 units"},{"label":"D","text":"increases it by 1200 units"}],"correct":""},{"id":15,"text":"According to Keynesian theory, when will an increase in the money supply leave the level of output unchanged?","options":[{"label":"A","text":"when there is a liquidity trap"},{"label":"B","text":"when the money supply increase was not anticipated"},{"label":"C","text":"when there is a floating exchange rate"},{"label":"D","text":"when there is an immediate adjustment to expectations about future price levels"}],"correct":""},{"id":16,"text":"What do Monetarists believe?","options":[{"label":"A","text":"Economies are naturally unstable."},{"label":"B","text":"Policy makers should follow set rules targeting the money supply."},{"label":"C","text":"The aggregate supply curve has a slight slope."},{"label":"D","text":"Wage movements are 'sticky' downwards."}],"correct":""},{"id":17,"text":"A country with an income tax rate X decides to increase its tax rate. The diagram shows tax revenue will fall. tax rate Why would this happen?","options":[{"label":"A","text":"Fewer goods will be produced."},{"label":"B","text":"People will work fewer hours to maintain incomes."},{"label":"C","text":"Prices will rise."},{"label":"D","text":"There will be an increase in tax avoidance."}],"correct":"","image":"/images/econ-a2-mcq/91_591_302_614_341_0.jpg"},{"id":18,"text":"What is most likely to influence subsequent increases in national income as a result of a government policy of reduced interest rates?","options":[{"label":"A","text":"marginal cost"},{"label":"B","text":"marginal efficiency of capital"},{"label":"C","text":"marginal product"},{"label":"D","text":"marginal utility"}],"correct":""},{"id":19,"text":"It is often argued that the UN Human Development Index (HDI) is a better indicator of economic development than income per capita because it adjusts for","options":[{"label":"A","text":"average hours worked by the population."},{"label":"B","text":"environmental pollution."},{"label":"C","text":"inequality in income distribution."},{"label":"D","text":"life expectancy at birth."}],"correct":""},{"id":20,"text":"Some conditions for providing foreign aid to low-income countries can be restrictive. Which kind of aid fits this description?","options":[{"label":"A","text":"food aid in the event of natural catastrophes such as severe drought"},{"label":"B","text":"grants that are tied to purchasing donor country goods"},{"label":"C","text":"loans that are repaid over a long period at a low rate of interest"},{"label":"D","text":"technical assistance using highly skilled worker transfers to provide support"}],"correct":""},{"id":21,"text":"What is most likely to cause the living standards of a country to rise?","options":[{"label":"A","text":"an increase in the number of doctors"},{"label":"B","text":"an increase in the gold reserves"},{"label":"C","text":"an increase in the number of people per house"},{"label":"D","text":"an increase in the money supply"}],"correct":""}];

const paper_07: MCQQuestion[] = [{"id":1,"text":"When is Pareto efficiency achieved?","options":[{"label":"A","text":"at a level of output that is productively and allocatively efficient"},{"label":"B","text":"when everyone has equal amounts of goods and services"},{"label":"C","text":"when social benefits are greater than private benefits"},{"label":"D","text":"when social marginal benefit is greater than social marginal cost"}],"correct":""},{"id":2,"text":"In which type of market structure are commercial banks usually found?","options":[{"label":"A","text":"perfect competition, because they all link their interest rates to that of the central bank"},{"label":"B","text":"perfect competition, because they offer identical products and services"},{"label":"C","text":"monopolistic competition, because a competitive market prevents them making excess profits"},{"label":"D","text":"oligopoly, because they are affected by the actions of other banks"}],"correct":""},{"id":3,"text":"The manufacture of some sports equipment is dominated by very large firms but there are also smaller firms in the industry. What enables a small firm to exist in such an industry?","options":[{"label":"A","text":"high concentration ratio that reduces competition"},{"label":"B","text":"high start-up costs that occur in a contestable market"},{"label":"C","text":"decreasing average cost as a large firm expands"},{"label":"D","text":"a requirement for personalised equipment"}],"correct":""},{"id":4,"text":"The marginal cost curve of a firm passes through the lowest point of the firm's","options":[{"label":"A","text":"average fixed cost curve."},{"label":"B","text":"average variable cost curve."},{"label":"C","text":"marginal revenue curve."},{"label":"D","text":"total cost curve."}],"correct":""},{"id":5,"text":"What would definitely be abnormal profits?","options":[{"label":"A","text":"the extra revenue received from the sale of a farmer's land to a house-building firm"},{"label":"B","text":"the extra revenue received by a firm from an unexpectedly large increase in demand"},{"label":"C","text":"the total revenue from the sale of a firm's products in excess of the total variable costs of the firm"},{"label":"D","text":"the total revenue in excess of total costs of the firm above the minimum needed to keep the firm in business in the long run"}],"correct":""},{"id":6,"text":"The diagram shows the cost and revenue curves for a monopoly market structure.","options":[{"label":"A","text":"monopoly was producing at \\({\\mathrm{P}}_{1}{\\mathrm{Q}}_{1}\\) but changed its aim and now produces at \\({\\mathrm{P}}_{2}{\\mathrm{Q}}_{2}\\) ."},{"label":"B","text":"What would not have caused this change?"},{"label":"C","text":"It wants to benefit from greater economies of scale."},{"label":"D","text":"It wants to maximise profits."}],"correct":"","image":"/images/econ-a2-mcq/96_616_232_559_552_0.jpg"},{"id":7,"text":"A government regards fresh fruit and vegetables as merit goods, and subsidises agriculture to boost their production. What could be a government failure arising from these subsidies?","options":[{"label":"A","text":"cheaper fresh fruit and vegetables"},{"label":"B","text":"land clearance reducing wildlife"},{"label":"C","text":"lower spending on treating dietary illnesses"},{"label":"D","text":"more jobs picking fruit and vegetables"}],"correct":""},{"id":8,"text":"The table shows the average incomes of the richest 20\\% of households and the poorest 20\\% of households in the UK (2015-2016), and the effects of government taxation and benefits on average income. } What can be concluded from the information in the table?","options":[{"label":"A","text":"The effects of direct taxation have affected the rich less than the poor."},{"label":"B","text":"The government's policy achieved income equality across households."},{"label":"C","text":"The government redistributed all income taken from the rich to the poor."},{"label":"D","text":"The government's policy reduced the income inequality between the poor and the rich."}],"correct":"","table":"<table><tr><td>average income (£) of richest 20%</td><td>average income (£) of poorest 20%</td></tr><tr><td>before taxes and benefits</td><td>85000</td><td>7000</td></tr><tr><td>after direct taxes and cash benefits</td><td>68000</td><td>13000</td></tr><tr><td>after all taxes (direct and indirect) and all benefits</td><td>63000</td><td>17000</td></tr></table>"},{"id":9,"text":"What would be the most likely effect of the imposition of a national maximum wage below the market equilibrium on the labour market for famous television celebrities?","options":[{"label":"A","text":"a reduction in the number of jobs for television celebrities"},{"label":"B","text":"an increase in other methods of rewarding television celebrities"},{"label":"C","text":"greater movement of celebrities between television channels"},{"label":"D","text":"increased employment of foreign television celebrities"}],"correct":""},{"id":10,"text":"Which government measure is most likely to encourage faster and more sustainable economic growth in a country?","options":[{"label":"A","text":"subsidies to firms using recycled materials in production"},{"label":"B","text":"grants for the exploration and exploitation of new oil deposits"},{"label":"C","text":"increased spending on environmental education in schools"},{"label":"D","text":"tougher legislative controls on emissions of air and water pollution"}],"correct":""},{"id":11,"text":"Which statement about National Income accounting is correct when Gross Domestic Product (GDP) is converted into Net National Income (NNI)?","options":[{"label":"A","text":"An allowance for depreciation has to be made, because the NNI does not include output that replaces capital that has been used up."},{"label":"B","text":"Both GDP and NNI have to be calculated by the incomes method, because that is what NNI is measuring."},{"label":"C","text":"Double counting is not a problem if the conversion uses the output method, but it is when using the expenditure method."},{"label":"D","text":"The value of exports needs to be added, because exports generate income for citizens."}],"correct":""},{"id":12,"text":"Real GNP per capita is often used when comparisons of living standards are made between a developed and a developing country. What is not a good reason to question the accuracy of this comparison of living standards?","options":[{"label":"A","text":"It is not possible to use price indices accurately when computing real figures because spending patterns are different."},{"label":"B","text":"People in developed countries enjoy very different amounts of leisure time to people in developing countries."},{"label":"C","text":"The extent of the unrecorded economy is very different in the two countries."},{"label":"D","text":"The purchasing power parity theory has been used to make comparisons."}],"correct":""},{"id":13,"text":"Based on the International Labour Office definition of unemployment, which individual is most likely to be classified as unemployed?","options":[{"label":"A","text":"a single parent who would like to work but cannot afford to pay for child-care facilities"},{"label":"B","text":"a teacher who has decided to retire permanently"},{"label":"C","text":"a redundant steel worker who is not actively seeking alternative work"},{"label":"D","text":"a student who is desperately seeking any weekend job to supplement his income"}],"correct":""},{"id":14,"text":"What is most likely to lead to an increase in labour productivity?","options":[{"label":"A","text":"encouraging women to enter the workforce"},{"label":"B","text":"increasing automation"},{"label":"C","text":"raising the retirement age"},{"label":"D","text":"reducing the division of labour"}],"correct":""},{"id":15,"text":"The table shows real GDP and unemployment for an economy. } What can be concluded from the data?","options":[{"label":"A","text":"Demand-pull inflation is likely to increase."},{"label":"B","text":"Potential output is likely to increase."},{"label":"C","text":"The balance of payments deficit is likely to increase."},{"label":"D","text":"The budget deficit is likely to increase."}],"correct":"","table":"<table><tr><td>2019</td><td>2021</td></tr><tr><td>real GDP ($ billions)</td><td>40000</td><td>38000</td></tr><tr><td>unemployment (millions)</td><td>2</td><td>3</td></tr></table>"},{"id":16,"text":"What is illustrated by the Laffer curve?","options":[{"label":"A","text":"As income increases, fewer hours will be worked."},{"label":"B","text":"As income increases, tax revenue will increase."},{"label":"C","text":"As the tax rate increases, tax revenue always increases."},{"label":"D","text":"As the tax rate increases, tax revenue will eventually fall."}],"correct":""},{"id":17,"text":"The table shows real GDP and unemployment for an economy. What can be concluded from the data?","options":[{"label":"A","text":"Demand-pull inflation is likely to increase."},{"label":"B","text":"Potential output is likely to increase."},{"label":"C","text":"The balance of payments deficit is likely to increase."},{"label":"D","text":"The budget deficit is likely to increase."}],"correct":"","table":"<table><tr><td>economic indicators</td><td>2019</td><td>2021</td></tr><tr><td>real GDP ($ billions)</td><td>40000</td><td>38000</td></tr><tr><td>unemployment (millions)</td><td>2</td><td>3</td></tr></table>"},{"id":18,"text":"During a year, a country's national income in money terms increased by 5\\%, prices increased by 4\\% and the total population increased by 2\\%. What was the approximate change in real income per head?","options":[{"label":"A","text":"a decrease of 1\\%"},{"label":"B","text":"a decrease of 2\\%"},{"label":"C","text":"an increase of 1\\%"},{"label":"D","text":"an increase of 2\\%"}],"correct":""}];

const paper_08: MCQQuestion[] = [{"id":1,"text":"The world's largest pharmaceutical companies developed and distributed an effective vaccine to combat a dangerous virus. What can be associated with this vaccine programme?","options":[{"label":"A","text":"demerit good and negative production externality"},{"label":"B","text":"imperfect competition and positive consumption externality"},{"label":"C","text":"perfect competition and negative consumption externality"},{"label":"D","text":"public good and negative production externality"}],"correct":""},{"id":2,"text":"A landlord owns a house which is rented to tenants. The tenants are required to pay the electricity and water bills. The landlord is required to decorate and repair damage to the house and its gardens. What is not an example of the principal-agent problem?","options":[{"label":"A","text":"The tenants forget to switch off a tap when filling a bath and water overflows, damaging the floor."},{"label":"B","text":"The tenants have a party and their guests cause damage to the interior of the house."},{"label":"C","text":"The tenants leave the lights and the TV on when they go out for an evening meal."},{"label":"D","text":"The tenants park their car in the garden, damaging the grass and the surrounding hedge."}],"correct":""},{"id":3,"text":"The result of a cost-benefit analysis of a proposed government road-building project is that there will be a positive net social benefit of \\$50 million. Why might the government not proceed with the project?","options":[{"label":"A","text":"The project would not be profitable for a private firm."},{"label":"B","text":"The project would cause negative externalities."},{"label":"C","text":"There is limited capital available for government projects."},{"label":"D","text":"There would be more who lost than gained."}],"correct":""},{"id":4,"text":"The diagram shows an industry's demand for and supply of labour. Initially, the labour market is in equilibrium. The government introduces a minimum wage of \\({\\mathrm{{OW}}}_{0}\\) . What will be the effect on the level of employment in the industry?","options":[{"label":"A","text":"a decrease equal to XY"},{"label":"B","text":"a decrease equal to XZ"},{"label":"C","text":"an increase equal to XY"},{"label":"D","text":"an increase equal to YZ"}],"correct":"","image":"/images/econ-a2-mcq/107_581_232_631_634_0.jpg"},{"id":5,"text":"The diagram shows the supply curve of labour for two separate markets, X and Y. What explains the difference in the gradients of the labour supply curves?","options":[{"label":"A","text":"Market X has a higher marginal revenue product per worker than Y."},{"label":"B","text":"Market X has a higher percentage of its labour belonging to a trade union than Y."},{"label":"C","text":"Market X has higher labour costs as a percentage of total costs than X."},{"label":"D","text":"Market X has more specific skills and training requirements than Y."}],"correct":"","image":"/images/econ-a2-mcq/107_637_1384_521_432_0.jpg"},{"id":6,"text":"The table shows the main characteristics of employment in two occupations. } What can definitely be deduced from the table?","options":[{"label":"A","text":"Those employed in occupation Y attach greater importance to job security."},{"label":"B","text":"Those employed in occupation X attach less importance to leisure activities."},{"label":"C","text":"There will be more competition for places on training courses to enter occupation X than occupation Y."},{"label":"D","text":"Occupation Y has more non-pecuniary advantages than occupation X."}],"correct":"","table":"<table><tr><td>occupation X</td><td>occupation Y</td></tr><tr><td>average annual wage</td><td>$100 000</td><td>$60000</td></tr><tr><td>number of weeks of annual leave</td><td>5 weeks</td><td>10 weeks</td></tr><tr><td>average length of working week</td><td>48 hours</td><td>44 hours</td></tr><tr><td>job security</td><td>low</td><td>high</td></tr><tr><td>length of training course to obtain job qualification</td><td>1 year</td><td>2 years</td></tr></table>"},{"id":7,"text":"A government wishes to reduce the use of cars in cities. Which policy should be used?","options":[{"label":"A","text":"a decrease in parking charges"},{"label":"B","text":"lowering tax on petrol (gasoline)"},{"label":"C","text":"restricting cycling"},{"label":"D","text":"subsidising public transport"}],"correct":""},{"id":8,"text":"What is most likely to be the biggest contribution to sustainable economic growth in a developed economy?","options":[{"label":"A","text":"a movement of people from rural to urban areas"},{"label":"B","text":"an increase in technical training"},{"label":"C","text":"an increase in the size of the population"},{"label":"D","text":"rising consumer credit levels"}],"correct":""},{"id":9,"text":"Which policy is likely to increase unemployment?","options":[{"label":"A","text":"an increase in retraining facilities"},{"label":"B","text":"a significant increase in indirect taxes"},{"label":"C","text":"the imposition of selective import controls"},{"label":"D","text":"an increase in the public sector deficit"}],"correct":""},{"id":10,"text":"What does the accelerator principle state?","options":[{"label":"A","text":"Consumption is a function of the rate of change of income."},{"label":"B","text":"Income is a function of the rate of change of investment."},{"label":"C","text":"Investment is a function of the rate of change of income."},{"label":"D","text":"Investment is a function of the rate of interest."}],"correct":""},{"id":11,"text":"Which government aim is least likely to be achieved using macroeconomic monetary policy measures?","options":[{"label":"A","text":"low unemployment level"},{"label":"B","text":"more equal income distribution"},{"label":"C","text":"stable exchange rate"},{"label":"D","text":"steady price level"}],"correct":""},{"id":12,"text":"Country X decides to devalue its currency to eliminate a balance of payments deficit. Why might devaluation have a positive effect on its macroeconomy?","options":[{"label":"A","text":"Competitive pricing of exports may create employment potential in country X."},{"label":"B","text":"Foreign importers may depreciate their own currencies and reduce any advantage gained by country X."},{"label":"C","text":"Inelastic demand for imported raw materials may lead to cost inflation in country X."},{"label":"D","text":"Loss of import duties by country X may reduce government backing for trade promotion."}],"correct":""},{"id":13,"text":"Which cause of economic growth would involve the least cost for present and future generations of a country's population?","options":[{"label":"A","text":"increased exploitation of a country's mineral resources"},{"label":"B","text":"investment financed by borrowing from abroad"},{"label":"C","text":"investment financed by high rates of domestic savings"},{"label":"D","text":"technological innovations in production processes"}],"correct":""},{"id":14,"text":"Which curve is shown in the diagram?","options":[{"label":"A","text":"Kuznets curve"},{"label":"B","text":"Laffer curve"},{"label":"C","text":"Lorenz curve"},{"label":"D","text":"Phillips curve"}],"correct":"","image":"/images/econ-a2-mcq/111_581_1161_632_370_0.jpg"},{"id":15,"text":"Which indicator is least likely to be used when measuring the comparative economic development of an economy?","options":[{"label":"A","text":"mean years of schooling"},{"label":"B","text":"average life expectancy at birth"},{"label":"C","text":"level of real GNP per head"},{"label":"D","text":"size of population"}],"correct":""},{"id":16,"text":"What is an example of an expenditure-switching policy?","options":[{"label":"A","text":"an increase in income tax rates"},{"label":"B","text":"an increase in interest rates"},{"label":"C","text":"an increase in tariff rates"},{"label":"D","text":") an increase in the supply of money"}],"correct":""},{"id":17,"text":"What would not be regarded as an example of a possible negative impact of rapid economic growth?","options":[{"label":"A","text":"Greater production could result in greater atmospheric pollution."},{"label":"B","text":"A higher level of income could cause a higher balance of trade deficit."},{"label":"C","text":"Increased AD could cause domestic inflation to increase."},{"label":"D","text":"Increased GDP could generate greater tax receipts."}],"correct":""},{"id":18,"text":"How can GDP at market prices be calculated if GDP at factor cost is known?","options":[{"label":"A","text":"add taxes, add subsidies"},{"label":"B","text":"add taxes, subtract subsidies"},{"label":"C","text":"subtract taxes, add subsidies"},{"label":"D","text":"subtract taxes, subtract subsidies"}],"correct":""},{"id":19,"text":"Which statement about unemployment is correct?","options":[{"label":"A","text":"Cyclical unemployment is caused by the occupational immobility of labour."},{"label":"B","text":"Frictional unemployment is caused by a lack of information on jobs in the labour market."},{"label":"C","text":"Structural unemployment is caused by a deficiency in aggregate demand."},{"label":"D","text":"Voluntary unemployment is caused by variations in the demand for labour in the year."}],"correct":""},{"id":20,"text":"The graph shows the percentage unemployed in a country for the period 2017-2021. What is the most likely cause of the change in unemployment?","options":[{"label":"A","text":"a reduction in government expenditure"},{"label":"B","text":"a reduction in interest rates"},{"label":"C","text":"a reduction in investment by firms"},{"label":"D","text":"a slowdown in growth in the global economy"}],"correct":"","image":"/images/econ-a2-mcq/76_557_1091_684_449_0.jpg"},{"id":21,"text":"What is the definition of liquidity?","options":[{"label":"A","text":"the ability of the foreign exchange market to buy foreign currency"},{"label":"B","text":"the support a central bank provides for commercial banks"},{"label":"C","text":"the ease with which an asset can be converted into cash"},{"label":"D","text":"the reaction of governments to a global financial crisis"}],"correct":""},{"id":22,"text":"What will decrease if an open economy experiences a positive output gap?","options":[{"label":"A","text":"general price level"},{"label":"B","text":"import spending"},{"label":"C","text":"spare capacity"},{"label":"D","text":"wage rates"}],"correct":""},{"id":23,"text":"Which statement does not correctly characterise the Monetarist view of the way in which the economy operates?","options":[{"label":"A","text":"Inflation is always caused by increases in the money supply in the long run."},{"label":"B","text":"The long-run aggregate supply curve is vertical in shape."},{"label":"C","text":"The velocity of circulation of money is highly unstable."},{"label":"D","text":"Wages are flexible both upwards and downwards."}],"correct":""},{"id":24,"text":"In an economy, the marginal propensity to consume is 0.2, the marginal propensity to save is 0.3, the marginal propensity to tax is 0.3 and the marginal propensity to import is 0.2 at all levels of income. What would be the most likely consequence of an increase in government expenditure of \\$1000m?","options":[{"label":"A","text":"Import expenditure would increase by \\( \\$ {200}\\mathrm{\\;m} \\) ."},{"label":"B","text":"Import expenditure would increase by \\( \\$ {1000}\\mathrm{\\;m} \\) ."},{"label":"C","text":"Tax revenues would increase by \\( \\$ {75}\\mathrm{\\;m} \\) ."},{"label":"D","text":"Tax revenues would increase by \\( \\$ {375}\\mathrm{\\;m} \\) ."}],"correct":""},{"id":25,"text":"A developing (low-income) economy is heavily dependent on the production of primary products. A multinational car manufacturing company invests in the country and builds a new factory. What will not be a long lasting benefit of the company's investment in the developing economy?","options":[{"label":"A","text":"The company introduces new technology to the economy."},{"label":"B","text":"The company provides diversification of production for the economy."},{"label":"C","text":"The company provides skills training for local workers."},{"label":"D","text":"The company purchases non-renewable local construction materials for the factory."}],"correct":""},{"id":26,"text":"An economy adopts an expansionary monetary policy to boost employment. A result of this policy is that the consumer price index rises at an accelerating rate. Which curve could represent this?","options":[{"label":"A","text":"Kuznets curve"},{"label":"B","text":"Laffer curve"},{"label":"C","text":"Lorenz curve"},{"label":"D","text":"Phillips curve"}],"correct":""},{"id":27,"text":"An economy is operating at full employment. Which policy is most likely to lead to an increase in real national output without an increase in the rate of inflation in the short term?","options":[{"label":"A","text":"additional spending on subsidies to increase export earnings"},{"label":"B","text":"the central bank introduces quantitative easing"},{"label":"C","text":"labour market reforms result in increased output per hour worked"},{"label":"D","text":"the government reduces income tax rates"}],"correct":""}];

const paper_09: MCQQuestion[] = [{"id":1,"text":"What does the marginal utility diagram show?","options":[{"label":"A","text":"Total utility becomes negative if the quantity consumed increases from Y to Z."},{"label":"B","text":"Total utility decreases if the quantity consumed increases from \\(X\\) to \\(Y\\) ."},{"label":"C","text":"Total utility decreases if the quantity consumed increases from \\(Y\\) to \\(Z\\) ."},{"label":"D","text":"Total utility is maximised at \\(X\\) ."}],"correct":"","image":"/images/econ-a2-mcq/114_529_232_739_465_0.jpg"},{"id":2,"text":"Which assumption in relation to an indifference theory diagram is not correct?","options":[{"label":"A","text":"The consumer's income may change."},{"label":"B","text":"The consumer may change their satisfaction-maximising objective."},{"label":"C","text":"The consumers may change their tastes and preferences."},{"label":"D","text":"The relative prices of products may change."}],"correct":""},{"id":3,"text":"Which type of efficiency is shown by the shift from long-run average cost curve \\(1\\left( {\\mathrm{{LRAC}}}_{1}\\right)\\) to long-run average cost curve \\(2\\left( {\\mathrm{{LRAC}}}_{2}\\right)\\) ?","options":[{"label":"A","text":"allocative"},{"label":"B","text":"dynamic"},{"label":"C","text":"Pareto"},{"label":"D","text":"productive"}],"correct":"","image":"/images/econ-a2-mcq/115_523_267_749_519_0.jpg"},{"id":4,"text":"A firm wishes to maximise its revenue. Which condition must be met to achieve this goal?","options":[{"label":"A","text":"average cost = average revenue"},{"label":"B","text":"marginal cost = average revenue"},{"label":"C","text":"marginal cost = marginal revenue"},{"label":"D","text":"marginal revenue = zero"}],"correct":""},{"id":5,"text":"A firm at its current level of production finds that its short-run marginal cost is less than its short-run average variable cost. Which conclusion about the firm can be drawn from this information?","options":[{"label":"A","text":"Average variable cost is constant."},{"label":"B","text":"Average variable cost is falling."},{"label":"C","text":"Average variable cost is greater than its average total cost."},{"label":"D","text":"Average variable cost is rising."}],"correct":""},{"id":6,"text":"What is an example of an external cost?","options":[{"label":"A","text":"distribution costs"},{"label":"B","text":"energy costs"},{"label":"C","text":"labour costs"},{"label":"D","text":"road congestion costs"}],"correct":""},{"id":7,"text":"What would definitely result from the divorce of ownership and control?","options":[{"label":"A","text":"decreased moral hazard"},{"label":"B","text":"the principal agent problem"},{"label":"C","text":"greater productive efficiency"},{"label":"D","text":"increased profit maximisation"}],"correct":""},{"id":8,"text":"One reason for market failure is the existence of public goods. Which policy option is appropriate for addressing such a market failure?","options":[{"label":"A","text":"direct provision of the good by the government"},{"label":"B","text":"provision of detailed information to consumers"},{"label":"C","text":"subsidising firms that currently produce the good"},{"label":"D","text":"the adoption of maximum price controls"}],"correct":""},{"id":9,"text":"In 2020, the governor of California issued an order to ban the sale of new vehicles from 2035 that are powered by petrol or diesel fuel. Which type of government policy is this?","options":[{"label":"A","text":"a nudge"},{"label":"B","text":"a permit to pollute"},{"label":"C","text":"nationalisation"},{"label":"D","text":"regulation"}],"correct":""},{"id":10,"text":"Economics textbooks state that labour is a derived demand for a firm in imperfect competition. How is the demand curve for labour derived?","options":[{"label":"A","text":"by multiplying the average physical product by the average revenue"},{"label":"B","text":"by multiplying the average physical product by the marginal revenue"},{"label":"C","text":"by multiplying the marginal physical product by the marginal cost"},{"label":"D","text":"by multiplying the marginal physical product by the marginal revenue"}],"correct":""},{"id":11,"text":"The diagram shows the Lorenz curves for Norway (N) and India (I). of households What can be concluded from a comparison of the Lorenz curves?","options":[{"label":"A","text":"India is more likely to have lower indirect taxes and a public sector education system than Norway."},{"label":"B","text":"India is more likely to have a progressive income tax system and means tested benefits than Norway."},{"label":"C","text":"Norway is more likely to have a progressive tax system and public sector pensions than India."},{"label":"D","text":"Norway is likely to have a higher percentage of tax generated from indirect taxes and privately funded pensions than India."}],"correct":"","image":"/images/econ-a2-mcq/119_479_231_835_569_0.jpg"},{"id":12,"text":"A reason for government intervention in the workings of the economy is to attempt to correct a market failure. Sometimes, though, government failure may occur. What is not a possible reason for government failure?","options":[{"label":"A","text":"Governments may have to make decisions on the basis of out-of-date information."},{"label":"B","text":"Governments may make decisions that reduce negative externalities."},{"label":"C","text":"The extent of the market failure may be difficult to judge."},{"label":"D","text":"When circumstances change, a government may be unable to respond quickly."}],"correct":""},{"id":13,"text":"A government wishes to support growth in the economy's fishing industry. Which policy is likely to achieve sustainable growth in the fishing industry?","options":[{"label":"A","text":"giving more modern fishing boats with larger nets to workers who fish for a living"},{"label":"B","text":"paying bonus payments for larger fish catches to workers who fish for a living"},{"label":"C","text":"setting up a fish cooperative so that workers who fish for a living receive a higher price for the fish that they catch"},{"label":"D","text":"subsidising the building of a fish farm in order to encourage workers who fish for a living to switch from sea fishing"}],"correct":""},{"id":14,"text":"Four citizens have each been unemployed for the past six months. Which citizen would not be characterised as being structurally unemployed?","options":[{"label":"A","text":"worked as a coal miner but coal-fired power stations are now being closed and is not willing to retrain"},{"label":"B","text":"no longer works in a town centre coffee shop because fewer people are buying goods in the town centre since a pandemic"},{"label":"C","text":"cannot move with the firm that has relocated because of changing demand for its products"},{"label":"D","text":"has many skills and is waiting to decide which job might be the most suitable"}],"correct":""},{"id":15,"text":"What is the most effective policy a government could introduce to reduce frictional unemployment?","options":[{"label":"A","text":"cut welfare spending on benefits"},{"label":"B","text":"improve information about job vacancies"},{"label":"C","text":"reduce tax rates"},{"label":"D","text":"raise interest rates"}],"correct":""},{"id":16,"text":"In a closed economy with no government sector, when will an increase in investment spending generate the largest increase in equilibrium national income?","options":[{"label":"A","text":"when households have a high level of autonomous consumption"},{"label":"B","text":"when households have a high level of compulsory saving"},{"label":"C","text":"when households have a high marginal propensity to consume"},{"label":"D","text":"when households have a high marginal propensity to save"}],"correct":""},{"id":17,"text":"What would reduce the effectiveness of a supply-side stimulus to the economy?","options":[{"label":"A","text":"an imposition of maximum hours in a working week"},{"label":"B","text":"an increase in public sector spending"},{"label":"C","text":"the provision of new training schemes"},{"label":"D","text":"the relaxation of import controls on raw materials"}],"correct":""},{"id":18,"text":"To indicate the changing income distribution, the Kuznets curve plots gross domestic product per capita against an economic variable X. What is variable X?","options":[{"label":"A","text":"the exchange rate"},{"label":"B","text":"the level of income inequality"},{"label":"C","text":"the price level"},{"label":"D","text":"the rate of interest"}],"correct":""},{"id":19,"text":"The table shows some United Nations population statistics for 2010 and estimates for 2050. } Which relationship can be confirmed from the table?","options":[{"label":"A","text":"The least developed regions have the largest urban populations, actual or predicted, in both years."},{"label":"B","text":"The more developed regions have the lowest growth rate of urbanisation between 2010 and 2050."},{"label":"C","text":"The type of region with the greatest total population in 2010 is predicted to have the greatest rate of population growth by 2050."},{"label":"D","text":"The type of region with the greatest urban population in 2010 is predicted to have the highest level of urbanisation by 2050."}],"correct":"","table":"<table><tr><td>total population (m) 2010</td><td>total population (m) 2050</td><td>urban population (m) 2010</td><td>urban population (m) 2050</td><td>population urbanised (%) 2010</td><td>population urbanised (%) 2050</td></tr><tr><td>more developed</td><td>1237</td><td>1275</td><td>930</td><td>1100</td><td>75</td><td>86</td></tr><tr><td>less developed</td><td>5671</td><td>7875</td><td>2556</td><td>5186</td><td>45</td><td>66</td></tr><tr><td>least developed</td><td>855</td><td>1673</td><td>249</td><td>914</td><td>29</td><td>55</td></tr></table>"},{"id":20,"text":"The diagram shows a Lorenz curve with two areas, X and Y, identified. How is the corresponding Gini coefficient calculated?","options":[{"label":"A","text":"X divided by (X plus Y)"},{"label":"B","text":"(X plus Y) divided by X"},{"label":"C","text":"(X plus Y) divided by Y"},{"label":"D","text":"Y divided by (X plus Y)"}],"correct":"","image":"/images/econ-a2-mcq/123_562_1140_670_524_0.jpg"},{"id":21,"text":"The table shows some United Nations population statistics for 2010 and estimates for 2050. Which relationship can be confirmed from the table?","options":[{"label":"A","text":"The least developed regions have the largest urban populations, actual or predicted, in both years."},{"label":"B","text":"The more developed regions have the lowest growth rate of urbanisation between 2010 and 2050."},{"label":"C","text":"The type of region with the greatest total population in 2010 is predicted to have the greatest rate of population growth by 2050."},{"label":"D","text":"The type of region with the greatest urban population in 2010 is predicted to have the highest level of urbanisation by 2050."}],"correct":"","table":"<table><tr><td>type of region</td><td>total population (m) 2010</td><td>total population (m) 2050</td><td>urban population (m) 2010</td><td>urban population (m) 2050</td><td>population urbanised (%) 2010</td><td>population urbanised (%) 2050</td></tr><tr><td>more developed</td><td>1237</td><td>1275</td><td>930</td><td>1100</td><td>75</td><td>86</td></tr><tr><td>less developed</td><td>5671</td><td>7875</td><td>2556</td><td>5186</td><td>45</td><td>66</td></tr><tr><td>least developed</td><td>855</td><td>1673</td><td>249</td><td>914</td><td>29</td><td>55</td></tr></table>"}];

const paper_10: MCQQuestion[] = [{"id":1,"text":"Economists normally assume that the marginal utility from consuming additional goods is positive and diminishing. What is the effect on total satisfaction of consuming extra units of the good?","options":[{"label":"A","text":"Total satisfaction falls at a decreasing rate."},{"label":"B","text":"Total satisfaction falls at an increasing rate."},{"label":"C","text":"Total satisfaction rises at a decreasing rate."},{"label":"D","text":"Total satisfaction rises at an increasing rate."}],"correct":""},{"id":2,"text":"The diagram shows a long-run average cost curve (LRAC), and three short-run average cost curves \\(\\left( {{\\mathrm{{SRAC}}}_{1},{\\mathrm{{SRAC}}}_{2}}\\right.\\) and \\(\\left. {\\mathrm{{SRAC}}}_{3}\\right)\\) for an individual firm. Each short-run average cost curve represents a fixed factor of production. Between levels of output OL and OM, which statement is not correct?","options":[{"label":"A","text":"Average fixed costs are falling."},{"label":"B","text":"Economies of scale are being experienced."},{"label":"C","text":"The law of diminishing returns is operative."},{"label":"D","text":"There are decreasing returns to scale."}],"correct":"","image":"/images/econ-a2-mcq/126_430_303_939_449_0.jpg"},{"id":3,"text":"Which combination of reactions by rivals results in a kinked demand curve for an oligopolist when a price is changed?","options":[{"label":"A","text":"copying both a price rise and a price fall"},{"label":"B","text":"copying a price rise and ignoring a price fall"},{"label":"C","text":"ignoring a price rise and copying a price fall"},{"label":"D","text":"ignoring both a price rise and a price fall"}],"correct":""},{"id":4,"text":"What is a key condition for effective price discrimination?","options":[{"label":"A","text":"The product cannot be resold to another consumer."},{"label":"B","text":"The product must be price inelastic."},{"label":"C","text":"The profits from one market can be used to subsidise another market."},{"label":"D","text":"There are low barriers to entry into the market."}],"correct":""},{"id":5,"text":"A city council is considering building a passenger terminal at its port so that the city can benefit from large cruise ships that could then dock there. It undertakes a cost-benefit analysis. What would be included as an external cost in the city council's cost-benefit analysis?","options":[{"label":"A","text":"the cost of a ticket for a passenger to travel on a cruise ship"},{"label":"B","text":"the cost of fuel to operate the cruise ships"},{"label":"C","text":"the costs paid by cruise ships when they dock at the port"},{"label":"D","text":"the cost to a fishing fleet of relocating to another port"}],"correct":""},{"id":6,"text":"Some multinational oil companies extracting oil in developing countries are now required to repair the damage they do to the environment. What best describes the total costs incurred by the oil companies in such circumstances?","options":[{"label":"A","text":"external costs"},{"label":"B","text":"private costs plus external costs"},{"label":"C","text":"social costs plus external costs"},{"label":"D","text":"social costs plus private costs"}],"correct":""},{"id":7,"text":"Which statement is not an example of government failure?","options":[{"label":"A","text":"government intervention leading to a less efficient allocation of resources"},{"label":"B","text":"government intervention leading to a net loss of economic welfare"},{"label":"C","text":"government intervention leading to an increase in consumer surplus"},{"label":"D","text":"government intervention leading to social costs exceeding social benefits"}],"correct":""},{"id":8,"text":"A firm is faced with a shortage of labour. It decides to introduce its own training scheme for school leavers. Which effect is this most likely to have on the firm?","options":[{"label":"A","text":"a decrease in the number of workers it employs"},{"label":"B","text":"a decrease in the productivity of its workforce"},{"label":"C","text":"an increase in the geographical mobility of its labour"},{"label":"D","text":"a shift of the supply curve for its labour to the right"}],"correct":""},{"id":9,"text":"What is likely to result if a government introduces a new regressive tax?","options":[{"label":"A","text":"Aggregate demand will increase."},{"label":"B","text":"Employment opportunities will increase."},{"label":"C","text":"Income equality will improve."},{"label":"D","text":"Tax revenues will increase."}],"correct":""},{"id":10,"text":"What might decrease if a closed economy with a government sector decides to allow international trade?","options":[{"label":"A","text":"components of aggregate expenditure"},{"label":"B","text":"number of injections into the circular flow of income"},{"label":"C","text":"number of leakages from the circular flow of income"},{"label":"D","text":"value of the economy's multiplier"}],"correct":""},{"id":11,"text":"Which policy to counter climate change is considered to be regulatory rather than market based?","options":[{"label":"A","text":"the introduction of carbon taxes on pollution"},{"label":"B","text":"the operation of tradable pollution permits"},{"label":"C","text":"the provision of government subsidies"},{"label":"D","text":"the setting of industrial emission standards"}],"correct":""},{"id":12,"text":"Which cause of economic growth is most likely to ensure that the growth is sustainable?","options":[{"label":"A","text":"deregulation of industrial production that uses mineral resources and fossil fuel"},{"label":"B","text":"increased government spending on environmental education, financed through taxes on harmful goods"},{"label":"C","text":"increased trade barriers on imports to protect domestic jobs and incomes"},{"label":"D","text":"reduced planning regulations to encourage construction in areas of natural beauty"}],"correct":""},{"id":13,"text":"In all major towns in a country, a government adopts a policy of opening centres where job vacancies are advertised. Which type of unemployment is the government aiming to reduce with this policy?","options":[{"label":"A","text":"cyclical"},{"label":"B","text":"frictional"},{"label":"C","text":"regional"},{"label":"D","text":"seasonal"}],"correct":""},{"id":14,"text":"What is the basic assumption underlying the accelerator theory?","options":[{"label":"A","text":"Investment depends on the level of business confidence."},{"label":"B","text":"Investment depends on the level of savings."},{"label":"C","text":"Investment depends on the rate of change in national income."},{"label":"D","text":"Investment depends on the rate of change of interest rates."}],"correct":""},{"id":15,"text":"The Laffer curve shows expected tax revenues at different tax rates. An increase in the tax rate above 50\\% is expected to decrease tax revenue. What is the reason for this?","options":[{"label":"A","text":"decreased incentive for emigration"},{"label":"B","text":"decreased incentive for tax evasion"},{"label":"C","text":"increased incentive for people to work"},{"label":"D","text":"increased incentive for people to work fewer hours"}],"correct":"","image":"/images/econ-a2-mcq/131_482_1161_833_454_0.jpg"},{"id":16,"text":"The table shows data on the unemployment and inflation rates for four countries in 2010 and 2014. } Which countries had a typical Phillips curve?","options":[{"label":"A","text":"Australia and Japan"},{"label":"B","text":"Australia only"},{"label":"C","text":"Japan only"},{"label":"D","text":"Canada and the United States"}],"correct":"","table":"<table><tr><td>*country</td><td>2|c|unemployment rate (% of workforce)</td><td>2|c|inflation rate (% per annum)</td></tr><tr><td>2010</td><td>2014</td><td>2010</td><td>2014</td></tr><tr><td>Australia</td><td>5.2</td><td>6.1</td><td>2.7</td><td>1.6</td></tr><tr><td>Canada</td><td>8.0</td><td>6.9</td><td>2.2</td><td>1.9</td></tr><tr><td>Japan</td><td>5.1</td><td>3.6</td><td>-0.3</td><td>2.5</td></tr><tr><td>United States</td><td>9.6</td><td>6.2</td><td>1.7</td><td>0.6</td></tr></table>"},{"id":17,"text":"Purchasing power parity (PPP) allows a comparison of the purchasing power in two countries. What is a definition of PPP?","options":[{"label":"A","text":"the amount of the domestic currency needed to purchase a unit of foreign currency"},{"label":"B","text":"the quantity of a currency required to purchase the same basket of goods in both countries"},{"label":"C","text":"the quantity of goods and services that can be purchased by a person on an average income"},{"label":"D","text":"the value of expenditure by households on goods and services in a country"}],"correct":""},{"id":18,"text":"The turning point on the Kuznets curve for income inequality has been estimated to be in the region of US\\$10500. For a country that has a GDP per capita of \\$8000, what is most likely?","options":[{"label":"A","text":"A reduction in GDP per capita will have no effect on income inequality."},{"label":"B","text":"A reduction in GDP per capita will increase income inequality."},{"label":"C","text":"An increase in GDP per capita will have no effect on income inequality."},{"label":"D","text":"An increase in GDP per capita will increase income inequality."}],"correct":""},{"id":19,"text":"The Laffer curve shows expected tax revenues at different tax rates. An increase in the tax rate above 50% is expected to decrease tax revenue. What is the reason for this?","options":[{"label":"A","text":"decreased incentive for emigration"},{"label":"B","text":"decreased incentive for tax evasion"},{"label":"C","text":"increased incentive for people to work"},{"label":"D","text":"increased incentive for people to work fewer hours"}],"correct":"","image":"/images/econ-a2-mcq/131_482_1161_833_454_0.jpg"},{"id":20,"text":"The table shows data on the unemployment and inflation rates for four countries in 2010 and 2014. Which countries had a typical Phillips curve?","options":[{"label":"A","text":"Australia and Japan"},{"label":"B","text":"Australia only"},{"label":"C","text":"Japan only"},{"label":"D","text":"Canada and the United States"}],"correct":"","table":"<table><tr><td rowspan=\"2\">country</td><td colspan=\"2\">unemployment rate (% of workforce)</td><td colspan=\"2\">inflation rate (% per annum)</td></tr><tr><td>2010</td><td>2014</td><td>2010</td><td>2014</td></tr><tr><td>Australia</td><td>5.2</td><td>6.1</td><td>2.7</td><td>1.6</td></tr><tr><td>Canada</td><td>8.0</td><td>6.9</td><td>2.2</td><td>1.9</td></tr><tr><td>Japan</td><td>5.1</td><td>3.6</td><td>-0.3</td><td>2.5</td></tr><tr><td>United States</td><td>9.6</td><td>6.2</td><td>1.7</td><td>0.6</td></tr></table>"}];

const paper_11: MCQQuestion[] = [{"id":1,"text":"When choosing to buy two products, the satisfaction gained by the consumption of different combinations of these two products can be represented by an indifference curve. Which statement about such an indifference curve diagram is correct?","options":[{"label":"A","text":"The range of indifference curves shows the combination of products a consumer can purchase with a given income."},{"label":"B","text":"If an indifference curve is a downward-sloping straight line, the principle of diminishing marginal utility must be operating."},{"label":"C","text":"Indifference curves never cross, because this means that a consumer would be indifferent between combinations of two goods, even when one combination provides more of each good."},{"label":"D","text":"The gap between indifference curves is always constant."}],"correct":""},{"id":2,"text":"Negative externalities, such as air pollution due to car emissions, can cause damage to people's health in cities. Which response is most likely to occur from this situation?","options":[{"label":"A","text":"car manufacturers will automatically bear any external costs"},{"label":"B","text":"market failure will be resolved when private costs equal external costs"},{"label":"C","text":"most people will decide to use buses rather than cars"},{"label":"D","text":"some form of government intervention to improve economic efficiency"}],"correct":""},{"id":3,"text":"The merger of two large firms in the Singapore market supplying taxis and private hire vehicles resulted in a single firm with \\({80}\\%\\) of the market. The remaining 20\\% of the market consisted of thousands of independent taxi drivers. Which statement best describes what has effectively occurred in the market structure?","options":[{"label":"A","text":"The market has become monopolistically competitive."},{"label":"B","text":"The market has changed from an oligopoly to a monopoly."},{"label":"C","text":"The market has changed from perfect competition to an oligopoly."},{"label":"D","text":"The market remains an oligopoly."}],"correct":""},{"id":4,"text":"The diagram shows the cost and revenue curves of a profit-maximising, monopolistically competitive firm in long-run equilibrium. Which statement correctly describes the performance of this firm?","options":[{"label":"A","text":"It is allocatively efficient."},{"label":"B","text":"It is making abnormal losses."},{"label":"C","text":"It is making abnormal profits."},{"label":"D","text":"It is making normal profits."}],"correct":"","image":"/images/econ-a2-mcq/137_569_759_656_577_0.jpg"},{"id":5,"text":"A firm changes its aim and chooses to produce where marginal revenue (MR) is zero instead of where MR is equal to marginal cost (MC). Which explanation for this is not correct?","options":[{"label":"A","text":"The firm wishes to increase sales."},{"label":"B","text":"The firm wishes to increase its output."},{"label":"C","text":"The firm wishes to reduce prices."},{"label":"D","text":"The firm wishes to gain more profits."}],"correct":""},{"id":6,"text":"A firm operating in the airline industry uses third degree price discrimination. Which condition is most likely to allow this to happen?","options":[{"label":"A","text":"Consumers are able to buy cheaply and then sell the product at a higher price."},{"label":"B","text":"Price elasticity of demand is the same for all consumers in the market."},{"label":"C","text":"The firm faces a perfectly elastic demand curve."},{"label":"D","text":"The firm is able to keep the different market segments separate."}],"correct":""},{"id":7,"text":"What is not an example of a moral hazard?","options":[{"label":"A","text":"People with a higher risk of unemployment are more likely to undertake training."},{"label":"B","text":"People with free dental care are less likely to take care of their teeth with good oral hygiene."},{"label":"C","text":"People with insurance against car theft are more likely to park their car in high crime areas."},{"label":"D","text":"People with unemployment benefits are less likely to undertake retraining if they become unemployed."}],"correct":""},{"id":8,"text":"In recent years, the fuel cost of operating a jet aircraft has declined. Over the same period, improved design has led to much quieter aircraft. How would this affect the marginal private cost (MPC) and the marginal external cost (MEC) of air travel?","options":[{"label":"A","text":"a downward shift of both the MPC and the MEC curves"},{"label":"B","text":"a downward shift of the MPC curve and a movement left along the MEC curve"},{"label":"C","text":"a movement left along both the MPC and the MEC curves"},{"label":"D","text":"a movement left along the MPC curve and a downward shift of the MEC curve"}],"correct":""},{"id":9,"text":"A backward-sloping supply curve of labour is one where, beyond a certain point, the supply of labour","options":[{"label":"A","text":"decreases as the demand for labour rises."},{"label":"B","text":"increases as the demand for labour rises."},{"label":"C","text":"decreases as wages rise."},{"label":"D","text":"increases as wages rise."}],"correct":""},{"id":10,"text":"At present, motorists who drive their cars within area 1 on the map pay a daily congestion charge of \\$8. Which car journeys would decrease in number if the congestion charge area were extended to include area 2?","options":[{"label":"A","text":"journeys from point \\(\\mathrm{X}\\) to point \\(\\mathrm{Z}\\)"},{"label":"B","text":"journeys from point \\(X\\) to point \\(Y\\)"},{"label":"C","text":"journeys from point \\(Y\\) to point \\(Z\\)"},{"label":"D","text":"journeys from point \\(Z\\) to point \\(Y\\)"}],"correct":"","image":"/images/econ-a2-mcq/140_562_264_674_464_0.jpg"},{"id":11,"text":"What is most likely to lead to an increase in the size of the national income?","options":[{"label":"A","text":"a fall in interest rates on savings accounts"},{"label":"B","text":"a fall in the prices of imported goods"},{"label":"C","text":"a decrease in government spending"},{"label":"D","text":"an increase in direct taxes"}],"correct":""},{"id":12,"text":"Which government policy is most likely to improve occupational mobility?","options":[{"label":"A","text":"decreased income tax rates"},{"label":"B","text":"increased government spending on education and training"},{"label":"C","text":"increased government spending on infrastructure"},{"label":"D","text":"increased subsidies to firms to employ school leavers"}],"correct":""},{"id":13,"text":"What is likely to happen when the productive capacity of a free enterprise economy increases over a long period of time?","options":[{"label":"A","text":"Future generations will be less well-off than present generations."},{"label":"B","text":"Increasing the production of one good cannot be done without decreasing the production of another."},{"label":"C","text":"Individuals will have more choices due to a wider range of consumer goods."},{"label":"D","text":"Rising levels of output will cause per capita incomes to equalise."}],"correct":""},{"id":14,"text":"The accelerator principle refers to a relationship between investment and","options":[{"label":"A","text":"the level of GDP."},{"label":"B","text":"changes in GDP."},{"label":"C","text":"the level of interest rates."},{"label":"D","text":"changes in interest rates."}],"correct":""},{"id":15,"text":"What is likely to be the effect of an increase in the budget deficit?","options":[{"label":"A","text":"an increase in effective demand"},{"label":"B","text":"an increase in unemployment"},{"label":"C","text":"a reduction in inflation"},{"label":"D","text":"a reduction in the volume of spending"}],"correct":""},{"id":16,"text":"The table gives details of the inflation and unemployment rates for different countries in 2008 and 2011. } Which countries experienced a trade-off between their inflation and unemployment rates?","options":[{"label":"A","text":"Canada and Germany"},{"label":"B","text":"Canada only"},{"label":"C","text":"France and Japan"},{"label":"D","text":"France only"}],"correct":"","table":"<table><tr><td>*country</td><td>2|c|inflation rate (% per annum)</td><td>2|c|unemployment rate (% of workforce)</td></tr><tr><td>2008</td><td>2011</td><td>2008</td><td>2011</td></tr><tr><td>Canada</td><td>2.38</td><td>2.89</td><td>6.15</td><td>7.47</td></tr><tr><td>France</td><td>3.16</td><td>2.29</td><td>7.81</td><td>9.68</td></tr><tr><td>Germany</td><td>2.75</td><td>2.48</td><td>7.60</td><td>5.98</td></tr><tr><td>Japan</td><td>1.37</td><td>-0.28</td><td>3.99</td><td>4.55</td></tr></table>"},{"id":17,"text":"Which government policy would boost economic growth but not necessarily promote economic development?","options":[{"label":"A","text":"creating a more equal distribution of income and wealth"},{"label":"B","text":"diverting government spending from industry to education"},{"label":"C","text":"encouraging the extraction of finite natural resources"},{"label":"D","text":"introducing tighter controls on air pollution"}],"correct":""},{"id":18,"text":"Which policy measure to encourage economic growth might be based on the concept of the Laffer curve?","options":[{"label":"A","text":"cuts in direct taxes"},{"label":"B","text":"exchange rate depreciation"},{"label":"C","text":"investment subsidies"},{"label":"D","text":"quantitative easing"}],"correct":""},{"id":19,"text":"What has not accompanied global economic growth over the last 25 years?","options":[{"label":"A","text":"a depletion of non-renewable resources"},{"label":"B","text":"decreased international trade"},{"label":"C","text":"growing urbanisation"},{"label":"D","text":"increased atmospheric pollution"}],"correct":""},{"id":20,"text":"When assessing income distribution in an economy, which change in the Gini coefficient suggests that a country is distributing its income more equally?","options":[{"label":"A","text":"It has moved closer to one."},{"label":"B","text":"It has moved closer to zero."},{"label":"C","text":"It has moved from negative to positive."},{"label":"D","text":"It has moved from positive to negative."}],"correct":""},{"id":21,"text":"In 2021, a very large cargo ship carrying over 18000 cargo containers blocked the Suez Canal for seven days. It delayed over 350 other cargo ships, causing shortages of products in markets around the world as supplies were disrupted. Which consequence of globalisation is best illustrated by this event?","options":[{"label":"A","text":"cheaper products for consumers"},{"label":"B","text":"greater choice of products for consumers"},{"label":"C","text":"increased interdependence between countries"},{"label":"D","text":"increased migration of labour between countries"}],"correct":""},{"id":22,"text":"The graphs show the Human Development Index (HDI) and its component parts for Zimbabwe. Between years 3-7, which components of HDI have comparable changes to its overall change?","options":[{"label":"A","text":"education, GNI per capita and life expectancy"},{"label":"B","text":"education and GNI per capita only"},{"label":"C","text":"education and life expectancy only"},{"label":"D","text":"GNI per capita and life expectancy only"}],"correct":"","image":"/images/econ-a2-mcq/145_213_232_1369_1033_0.jpg"},{"id":23,"text":"Country X decides to devalue its currency to eliminate a balance of payments deficit. Why might devaluation have a positive effect on its macroeconomy?","options":[{"label":"A","text":"Competitive pricing of exports may create employment potential in country X."},{"label":"B","text":"Foreign importers may depreciate their own currencies and reduce any advantage gained by country X."},{"label":"C","text":"Inelastic demand for imported raw materials may lead to cost inflation in country X."},{"label":"D","text":"Loss of import duties by country X may reduce government backing for trade promotion."}],"correct":""},{"id":24,"text":"Which cause of economic growth would involve the least cost for present and future generations of a country's population?","options":[{"label":"A","text":"increased exploitation of a country's mineral resources"},{"label":"B","text":"investment financed by borrowing from abroad"},{"label":"C","text":"investment financed by high rates of domestic savings"},{"label":"D","text":"technological innovations in production processes"}],"correct":""},{"id":25,"text":"Which curve is shown in the diagram?","options":[{"label":"A","text":"Kuznets curve"},{"label":"B","text":"Laffer curve"},{"label":"C","text":"Lorenz curve"},{"label":"D","text":"Phillips curve"}],"correct":"","image":"/images/econ-a2-mcq/111_581_1161_632_370_0.jpg"},{"id":26,"text":"Which indicator is least likely to be used when measuring the comparative economic development of an economy?","options":[{"label":"A","text":"mean years of schooling"},{"label":"B","text":"average life expectancy at birth"},{"label":"C","text":"level of real GNP per head"},{"label":"D","text":"size of population"}],"correct":""},{"id":27,"text":"What is an example of an expenditure-switching policy?","options":[{"label":"A","text":"an increase in income tax rates"},{"label":"B","text":"an increase in interest rates"},{"label":"C","text":"an increase in tariff rates"},{"label":"D","text":") an increase in the supply of money"}],"correct":""}];

const paper_12: MCQQuestion[] = [{"id":1,"text":"The diagram shows the marginal utility (MU) from the consumption of quantities of good X. What happens to the total utility as consumption of X rises from 1 to 6 units?","options":[{"label":"A","text":"It falls continuously."},{"label":"B","text":"It falls and then rises."},{"label":"C","text":"It rises continuously."},{"label":"D","text":"It rises and then falls."}],"correct":"","image":"/images/econ-a2-mcq/147_536_232_728_410_0.jpg"},{"id":2,"text":"An indifference curve is typically drawn with a convex shape. Which economic concept explains the reason for this convex shape?","options":[{"label":"A","text":"allocative efficiency"},{"label":"B","text":"diminishing marginal rate of substitution"},{"label":"C","text":"Pareto optimality"},{"label":"D","text":"the equi-marginal principle"}],"correct":""},{"id":3,"text":"What is most likely to increase the principal-agent problem?","options":[{"label":"A","text":"ensuring the actions of agents are known by the managers"},{"label":"B","text":"linking the rewards of managers with the profitability of the firm"},{"label":"C","text":"removing from managers the opportunity to hold shares"},{"label":"D","text":"preparing contracts that compel agents to work in the interest of the principal"}],"correct":""},{"id":4,"text":"The table shows a firm's total fixed cost and total variable cost. } What can be concluded from the table?","options":[{"label":"A","text":"Average fixed cost falls."},{"label":"B","text":"Average fixed cost is constant."},{"label":"C","text":"Average variable cost falls."},{"label":"D","text":"Average variable cost rises."}],"correct":"","table":"<table><tr><td>total fixed cost $</td><td>total variable cost $</td></tr><tr><td>1</td><td>1000</td><td>1000</td></tr><tr><td>2</td><td>1000</td><td>2000</td></tr><tr><td>3</td><td>1000</td><td>3000</td></tr><tr><td>4</td><td>1000</td><td>4000</td></tr><tr><td>5</td><td>1000</td><td>5000</td></tr><tr><td>6</td><td>1000</td><td>6000</td></tr></table>"},{"id":5,"text":"The world's largest coffee restaurant chain purchased a large coffee bean farm in Costa Rica. The farm has research and development facilities to study specific diseases that devastate the coffee bean crop. How is this type of takeover classified?","options":[{"label":"A","text":"horizontal integration"},{"label":"B","text":"organic growth"},{"label":"C","text":"vertical backward integration"},{"label":"D","text":"vertical forward integration"}],"correct":""},{"id":6,"text":"Which condition is necessary for a firm to practise third degree price discrimination effectively?","options":[{"label":"A","text":"All consumers and producers must be in the same geographical location."},{"label":"B","text":"Customers must be divided into separate markets for the same product."},{"label":"C","text":"Each separate market must have identical price elasticities of demand."},{"label":"D","text":"Price undercutting is required to enter a monopolistic market."}],"correct":""},{"id":7,"text":"A traffic study concluded that there would be significant benefits if 10\\% of car drivers switched to using motorcycles during peak traffic times. Which benefit of this change would be considered a private benefit?","options":[{"label":"A","text":"faster journeys for those who continued to go by car"},{"label":"B","text":"faster journeys for those who switched to motorcycles"},{"label":"C","text":"increased safety for cyclists"},{"label":"D","text":"reduced levels of air pollution for pedestrians"}],"correct":""},{"id":8,"text":"What is consistent with a movement towards Pareto optimality?","options":[{"label":"A","text":"when negative externality lowers the utility of an individual"},{"label":"B","text":"when consumption of a good is non-rival"},{"label":"C","text":"when reallocation of resources can make someone better off without making any other person worse off"},{"label":"D","text":"when trade takes place to make one nation better off at the expense of its trading partner"}],"correct":""},{"id":9,"text":"What is most likely to increase relative poverty in a country?","options":[{"label":"A","text":"increasing means-tested benefit levels"},{"label":"B","text":"increasing the power of trade unions"},{"label":"C","text":"making the tax system more progressive"},{"label":"D","text":"removing the national minimum wage"}],"correct":""},{"id":10,"text":"Which policy is not designed to correct a market failure?","options":[{"label":"A","text":"government provision of healthcare"},{"label":"B","text":"price controls on large firms"},{"label":"C","text":"regulations to limit smoke pollution"},{"label":"D","text":"introducing import quotas"}],"correct":""},{"id":11,"text":"To control the cost of living, governments have sometimes imposed a maximum price on certain goods that is below the free market price. What is often an undesirable side effect of such a policy?","options":[{"label":"A","text":"accelerating general inflation"},{"label":"B","text":"an increase in profits above normal profits"},{"label":"C","text":"an increase in the stocks of unsold goods held by firms"},{"label":"D","text":"shortages of the good"}],"correct":""},{"id":12,"text":"When is an increase in national income most likely to induce an increase in investment spending?","options":[{"label":"A","text":"when firms have spare production capacity"},{"label":"B","text":"when firms use labour-intensive production"},{"label":"C","text":"when the increase in income is regarded as permanent"},{"label":"D","text":"when the increase in income is regarded as temporary"}],"correct":""},{"id":13,"text":"What is a function of money?","options":[{"label":"A","text":"It can be divided into small units."},{"label":"B","text":"It can be easily carried."},{"label":"C","text":"It is a standard of deferred payment."},{"label":"D","text":"It is widely accepted."}],"correct":""},{"id":14,"text":"A pandemic encourages many workers in developed countries to work from home, leading to a closure of city centre businesses such as coffee shops and retailers. If this way of working continues after the pandemic, what is the most likely result?","options":[{"label":"A","text":"Frictional unemployment will decrease."},{"label":"B","text":"The geographical mobility of labour will increase."},{"label":"C","text":"Structural unemployment will increase."},{"label":"D","text":"Voluntary unemployment will increase."}],"correct":""},{"id":15,"text":"In its 2020 population census, China reported that the total population was just below 1.4 billion. The birth rate had continued to decline, the number of those reaching retirement age had increased and the percentage size of the workforce had decreased. Which change of policy would most quickly sustain China's economic growth in view of these population changes?","options":[{"label":"A","text":"Allow more immigration of labour."},{"label":"B","text":"Encourage women to leave work to have more children."},{"label":"C","text":"Increase research in technology to improve labour productivity."},{"label":"D","text":"Tax the labour force more to pay for the increasing number of pensions."}],"correct":""},{"id":16,"text":"Other things remaining equal, what will reduce the level of national income in an economy?","options":[{"label":"A","text":"a fall in planned savings"},{"label":"B","text":"a fall in the marginal propensity to import"},{"label":"C","text":"an increase in the average propensity to consume"},{"label":"D","text":"a reduction in the level of defence expenditure"}],"correct":""},{"id":17,"text":"What, according to the accelerator principle, will cause the level of investment to fall?","options":[{"label":"A","text":"a decrease in confidence"},{"label":"B","text":"a decrease in the rate of growth of national income"},{"label":"C","text":"an increase in the price of capital equipment"},{"label":"D","text":"an increase in the rate of interest"}],"correct":""},{"id":18,"text":"What is measured on the vertical axis of the Phillips curve?","options":[{"label":"A","text":"the rate of change of real wages"},{"label":"B","text":"the rate of change of take-home pay"},{"label":"C","text":"the rate of inflation"},{"label":"D","text":"the rate of interest"}],"correct":""},{"id":19,"text":"South Africa has attempted to improve the level of economic growth by attracting foreign direct investment (FDI). What can be deduced from this diagram about the relationship between FDI and GDP growth between 2008 and 2018?","options":[{"label":"A","text":"The relationship between level of FDI and GDP growth is generally weak."},{"label":"B","text":"Increases in FDI are in line with improvements in GDP growth."},{"label":"C","text":"Lowering FDI is linked to stable GDP growth."},{"label":"D","text":"Negative GDP growth is linked to a lack of inflows of FDI."}],"correct":"","image":"/images/econ-a2-mcq/153_204_267_1396_461_0.jpg"},{"id":20,"text":"Which change would be most likely to indicate that a country has experienced economic development?","options":[{"label":"A","text":"an appreciation in the country's currency"},{"label":"B","text":"an improvement in the average citizen's quality of life"},{"label":"C","text":"an improvement in the country's trade balance"},{"label":"D","text":") an increase in the country's real GDP"}],"correct":""},{"id":21,"text":"What is a government macroeconomic aim?","options":[{"label":"A","text":"a fall in the general price level of goods and services"},{"label":"B","text":"an increase in monopoly regulation"},{"label":"C","text":"lower taxes on consumer goods"},{"label":"D","text":"a minimum wage for low paid agricultural workers"}],"correct":""},{"id":22,"text":"Under which circumstances will low wages and low-cost land in a low-income country not attract foreign investment in manufacturing?","options":[{"label":"A","text":"if the country creates genuine independence for their central bank"},{"label":"B","text":"if the country embarks on a programme of privatisation"},{"label":"C","text":"if the country lacks well-developed infrastructure"},{"label":"D","text":"if the country permits repatriation of profits"}],"correct":""},{"id":23,"text":"What is the role of the International Monetary Fund (IMF)?","options":[{"label":"A","text":"to advise countries that are experiencing trade disagreements"},{"label":"B","text":"to help charities providing emergency assistance to countries in need"},{"label":"C","text":"- to offer short-term assistance to countries with balance of payments problems"},{"label":"D","text":") to provide interest-free credit to developing countries for infrastructure purposes"}],"correct":""}];

const paper_13: MCQQuestion[] = [{"id":1,"text":"A person buys two pairs of socks. What does the purchase of the second pair of socks lead to?","options":[{"label":"A","text":"a decrease in marginal productivity"},{"label":"B","text":"a decrease in marginal utility"},{"label":"C","text":"an increase in marginal productivity"},{"label":"D","text":"an increase in marginal utility"}],"correct":""},{"id":2,"text":"What does an indifference curve show?","options":[{"label":"A","text":"the amount of two products achievable with given income and prices"},{"label":"B","text":"the different combinations of two goods that give a consumer equal utility"},{"label":"C","text":"the income available to buy the two goods"},{"label":"D","text":"the rate at which marginal utility changes as consumption changes"}],"correct":""},{"id":3,"text":"In which market structure is dynamic efficiency least likely to occur?","options":[{"label":"A","text":"oligopoly"},{"label":"B","text":"monopolistic competition"},{"label":"C","text":"monopoly"},{"label":"D","text":"perfectly competitive"}],"correct":""},{"id":4,"text":"Which type of employment contract is most likely to overcome the principal agent problem?","options":[{"label":"A","text":"increasing monthly salaries of waiters in a restaurant to decrease their dependence on tips from customers"},{"label":"B","text":"linking workers' pay with the profits of the firm to motivate them to raise the profitability of the firm"},{"label":"C","text":"making full fee payment in advance to a lawyer to motivate him to prepare a legal case well"},{"label":"D","text":"offering permanent contracts to give workers job security"}],"correct":""},{"id":5,"text":"Company R manufactures steel. Company S produces ships. Company T operates oil tankers. Company V operates cruise liners. Which statement is correct?","options":[{"label":"A","text":"If R takes over S, this is an example of forwards vertical integration."},{"label":"B","text":"If S takes over V, this is an example of backwards vertical integration."},{"label":"C","text":"If T takes over S, this is an example of diversification."},{"label":"D","text":"If V takes over S, this is an example of horizontal integration."}],"correct":""},{"id":6,"text":"There are two firms in an industry. Firm X faces a choice. It can either act independently or work with its rival. If it acts independently its profit could be \\$900 a week but it could be only \\$400 a week depending on what its rival does. If it works with its rival the joint profit of the two firms together would be \\$1400, \\$700 each. It has no knowledge of what the rival's policy will be. Which concept describes this situation?","options":[{"label":"A","text":"contestable market"},{"label":"B","text":"kinked demand curve"},{"label":"C","text":"principal agent problem"},{"label":"D","text":"prisoner's dilemma"}],"correct":""},{"id":7,"text":"A government wishes to use market forces to remove a negative externality in the consumption of a good. Which policy is likely to be the most effective?","options":[{"label":"A","text":"It should provide information about the undesirable side-effects of the good."},{"label":"B","text":"It should give producers a subsidy, to allow consumers to purchase the product more cheaply."},{"label":"C","text":"It should impose an indirect tax on consumers, to reduce consumption to the socially efficient level."},{"label":"D","text":"It should not interfere at all, to allow the free market to generate maximum efficiency."}],"correct":""},{"id":8,"text":"A government decides to replace a private company with its own company to collect household waste. Why could such action be justified?","options":[{"label":"A","text":"Waste collection is a public good."},{"label":"B","text":"Costs of waste collection are bound to be lower if paid out of local taxes."},{"label":"C","text":"Private companies are always less efficient than government companies."},{"label":"D","text":"Private companies might put profits before customer needs."}],"correct":""},{"id":9,"text":"What is a failure of government microeconomic intervention?","options":[{"label":"A","text":"An indirect tax equal to external costs is imposed on cigarettes and the demand falls."},{"label":"B","text":"Limits are placed on a trade union's restrictions that increase labour mobility."},{"label":"C","text":"Price controls on bread are removed which allow a free market to operate."},{"label":"D","text":"Tariffs are imposed on imported goods which cause the Gini coefficient to increase."}],"correct":""},{"id":10,"text":"What would shift the marginal revenue product curve for workers producing electric vehicles to the right?","options":[{"label":"A","text":"a decrease in the price of petrol vehicles"},{"label":"B","text":"a decrease in the productivity of electric vehicles workers"},{"label":"C","text":"an increase in the price of electric vehicles"},{"label":"D","text":"an increase in the wage rate of electric vehicles workers"}],"correct":""},{"id":11,"text":"Which change is likely to result in a decrease in the demand for money?","options":[{"label":"A","text":"a decrease in the use of credit cards by consumers"},{"label":"B","text":"a switch from monthly to weekly payments of wages"},{"label":"C","text":"a decrease in interest rates"},{"label":"D","text":"an increase in the perceived risks involved in holding government bonds"}],"correct":""},{"id":12,"text":"Which combination of factors is most likely to lead to a decrease in structural unemployment?","options":[{"label":"A","text":"a fall in inflation and an increase in lending for low income households"},{"label":"B","text":"a fall in real wages and an increase in subsidies for technological improvements"},{"label":"C","text":"an increase in tariffs and lower taxes for new businesses"},{"label":"D","text":"the introduction of a national minimum wage and better working conditions"}],"correct":""},{"id":13,"text":"Why might country X have a higher natural rate of unemployment than country Y?","options":[{"label":"A","text":"There is a higher level of trade unionisation in X."},{"label":"B","text":"There is more training and education in X."},{"label":"C","text":"There are greater incentives to find work in X."},{"label":"D","text":"There is a higher level of job vacancy information in X."}],"correct":""},{"id":14,"text":"Over the period of a year, nominal national income increased by 2\\%, inflation was 3\\% and population increased by 1\\%. Which statement is correct?","options":[{"label":"A","text":"Real income decreased by 2\\% per head."},{"label":"B","text":"Real income increased by 1\\% per head."},{"label":"C","text":"Real income increased by \\(4\\%\\) per head."},{"label":"D","text":"There was no change in real income per head."}],"correct":""},{"id":15,"text":"What is likely to be the most effective policy to reduce inflation caused by a rapid rise in import prices?","options":[{"label":"A","text":"a decrease in the domestic rate of interest"},{"label":"B","text":"a decrease in the rate of income tax"},{"label":"C","text":"an increase in trade tariffs on imports"},{"label":"D","text":"a revaluation of the exchange rate"}],"correct":""},{"id":16,"text":"Which macroeconomic policy objective will not apply to a government in a closed economy?","options":[{"label":"A","text":"achieving a low and steady rate of inflation"},{"label":"B","text":"achieving a more equal income distribution"},{"label":"C","text":"achieving a surplus on the balance of payments"},{"label":"D","text":"achieving a sustainable rate of economic growth"}],"correct":""},{"id":17,"text":"The government increases interest rates in order to reduce the rate of inflation. What will also result from this action?","options":[{"label":"A","text":"a depreciation of the country's currency"},{"label":"B","text":"a fall in the level of savings"},{"label":"C","text":"a reduction in economic growth"},{"label":"D","text":"a reduction in unemployment"}],"correct":""},{"id":18,"text":"The diagram shows the relationship between the income tax rate and tax revenue. income tax rate Which statement is correct?","options":[{"label":"A","text":"A tax rate cut from \\(Y\\) to \\(Z\\) will cause tax revenue to decrease."},{"label":"B","text":"At tax rates below Z a tax rate cut will cause tax revenue to increase."},{"label":"C","text":"The greater the rate of tax beyond Z, the smaller will be the tax revenue generated."},{"label":"D","text":"Tax revenue will always increase as the rate of income tax increases."}],"correct":"","image":"/images/econ-a2-mcq/164_458_655_881_371_0.jpg"},{"id":19,"text":"In which situation is devaluation of the currency most likely to cause inflation?","options":[{"label":"A","text":"Excess capacity is available."},{"label":"B","text":"Import tariffs are reduced."},{"label":"C","text":"Local substitutes of imported raw materials are unavailable."},{"label":"D","text":"The demand for exports is price inelastic."}],"correct":""},{"id":20,"text":"A country imports most of the raw materials used as factor inputs. Which policy is most likely to control cost-push inflation?","options":[{"label":"A","text":"an appreciation of the exchange rate"},{"label":"B","text":"an increase in the rate of income tax"},{"label":"C","text":"an increase in the rate of interest"},{"label":"D","text":"an increase in the rate of sales tax"}],"correct":""},{"id":21,"text":"Germany, one of the world's strongest trading nations, achieved a surplus on current account of the balance of payments in 2021-2022. Which income flow would not have been included in the calculation of Germany's current account?","options":[{"label":"A","text":"Declining sales of German cars for export overseas."},{"label":"B","text":"Falling earnings of foreign exchange from visitors to Germany."},{"label":"C","text":"Increasing transfers of aid to less developed countries."},{"label":"D","text":"Investment in a natural gas pipeline link to its main foreign supplier."}],"correct":""},{"id":22,"text":"A country maintains its foreign exchange rate against the United States dollar, within a narrow but changing band. What is this type of exchange rate?","options":[{"label":"A","text":"fixed"},{"label":"B","text":"floating"},{"label":"C","text":"managed float"},{"label":"D","text":"trade-weighted"}],"correct":""},{"id":23,"text":"What is likely to happen in a developing country as it becomes more developed?","options":[{"label":"A","text":"A lower percentage of people will go to university."},{"label":"B","text":"Average life expectancy will rise."},{"label":"C","text":"The rate of population growth will increase."},{"label":"D","text":"The tertiary sector will decline in importance."}],"correct":""}];

const paper_14: MCQQuestion[] = [{"id":1,"text":"Which statement about the concept of utility is correct?","options":[{"label":"A","text":"Diminishing marginal utility means that producers become less efficient the more they produce."},{"label":"B","text":"If marginal utility is above average utility, average utility must be rising."},{"label":"C","text":"The equi-marginal principle says that a consumer gets equal total satisfaction from each item purchased."},{"label":"D","text":"Total utility continually rises as the level of consumption rises."}],"correct":""},{"id":2,"text":"A medical team provides vaccinations for children to prevent an outbreak of an infectious disease. Why would this be described as a positive externality?","options":[{"label":"A","text":"Additional benefit might be gained as the disease no longer spreads."},{"label":"B","text":"Any kind of medical help will improve the condition of the children."},{"label":"C","text":"No action would be taken unless the medical team intervened."},{"label":"D","text":"The social benefits of vaccination are less than the social costs."}],"correct":""},{"id":3,"text":"Oligopoly firms seek to maximise profits. How will this affect the pricing behaviour of oligopoly firms involved in a non-collusive market?","options":[{"label":"A","text":"A price is fixed for the product that never changes throughout its life cycle."},{"label":"B","text":"Firms will agree on the level of advertising costs for a new product."},{"label":"C","text":"If one firm raises its price, other firms will maintain their original price to increase their market share."},{"label":"D","text":"If one firm lowers its price, other firms will increase their price."}],"correct":""},{"id":4,"text":"An economic activity definitely creates a net social benefit when the value of social benefit minus","options":[{"label":"A","text":"private benefit is zero."},{"label":"B","text":"private benefit is negative."},{"label":"C","text":"social cost is positive."},{"label":"D","text":"social cost is negative."}],"correct":""},{"id":5,"text":"Which assumption is essential for a market to be contestable?","options":[{"label":"A","text":"The market is supplied by a large number of firms."},{"label":"B","text":"Firms are free to enter and leave the market."},{"label":"C","text":"Firms cannot earn abnormal profits in the short run."},{"label":"D","text":"Firms produce differentiated goods."}],"correct":""},{"id":6,"text":"A firm that raises capital through a share issue has to satisfy both shareholders' expectations and management aims. The management aims to produce at a non-profit maximum output. Which strategy would necessarily prevent this aim?","options":[{"label":"A","text":"fixing output where MC = MR in the long run"},{"label":"B","text":"operating price discrimination to maximise revenue"},{"label":"C","text":"rewarding shareholders more than returns to innovation"},{"label":"D","text":"separating ownership and control of the firm"}],"correct":""},{"id":7,"text":"A major UK chemical firm was bought by its rival, a Dutch chemical firm. What definitely occurred when the Dutch firm bought the UK firm?","options":[{"label":"A","text":"a partnership"},{"label":"B","text":"economies of scale"},{"label":"C","text":"horizontal integration"},{"label":"D","text":"increased profits"}],"correct":""},{"id":8,"text":"Which statement is correct for a firm classed as a natural monopoly?","options":[{"label":"A","text":"It will always operate in the public sector and earn normal profits."},{"label":"B","text":"It will have high barriers to entry and be the dominant producer."},{"label":"C","text":"It will easily benefit from external economies of scale."},{"label":"D","text":"It will have higher average costs than a monopolistically competitive firm."}],"correct":""},{"id":9,"text":"The government can use policies to try and reduce the environmental damage caused by the amount of rubbish (garbage) created by firms and households. Which policy to reduce rubbish is most likely to lead to government failure?","options":[{"label":"A","text":"an incentive payment for firms who reduce the levels of rubbish"},{"label":"B","text":"a tax on the amount of rubbish a firm or household creates"},{"label":"C","text":"an advertising campaign about the problems created by rubbish"},{"label":"D","text":"government grants to firms researching how to safely dispose of rubbish"}],"correct":""},{"id":10,"text":"What would supporters of a nationalised public transport service expect to be the most likely outcome from the privatisation of train and bus services?","options":[{"label":"A","text":"fewer destinations served by trains and buses"},{"label":"B","text":"lower fares"},{"label":"C","text":"more frequent services to all destinations"},{"label":"D","text":"more people employed in public transport services"}],"correct":""},{"id":11,"text":"What will cause a household to be caught in the poverty trap?","options":[{"label":"A","text":"A household earns less than the international poverty line of \\$2.15 per person per day."},{"label":"B","text":"A household spends more than it earns in a month."},{"label":"C","text":"A household's earnings rise at a lower rate than the rise in inflation."},{"label":"D","text":"An extra dollar earnt by a household causes a greater loss in government benefit payments."}],"correct":""},{"id":12,"text":"What will cause an outward shift in the demand for labour curve?","options":[{"label":"A","text":"a decrease in the top rate of income tax"},{"label":"B","text":"an increase in the demand for the final product"},{"label":"C","text":"an increase in subsidies to firms"},{"label":"D","text":"an increase in the size of the working population"}],"correct":""},{"id":13,"text":"The diagram shows what happens when the employees of a profit-maximising monopsonist employer form a trade union and successfully negotiate a wage rate of \\({\\mathrm{{OW}}}_{\\mathrm{T}}\\) . What is the effect of the new wage rate on employment?","options":[{"label":"A","text":"It falls from \\({\\mathrm{{OQ}}}_{2}\\) to \\({\\mathrm{{OQ}}}_{1}\\) ."},{"label":"B","text":"It falls from \\({\\mathrm{{OQ}}}_{2}\\) to \\({\\mathrm{{OQ}}}_{3}\\) ."},{"label":"C","text":"It rises from \\({\\mathrm{{OQ}}}_{1}\\) to \\({\\mathrm{{OQ}}}_{3}\\) ."},{"label":"D","text":"It rises from \\({\\mathrm{{OQ}}}_{1}\\) to \\({\\mathrm{{OQ}}}_{4}\\) ."}],"correct":"","image":"/images/econ-a2-mcq/173_516_269_758_637_0.jpg"},{"id":14,"text":"A world financial crisis was partly linked to the actions of commercial banks. Which actions of the commercial banks could have led to the financial crisis?","options":[{"label":"A","text":"being subject to tight controls by the central bank over credit creation"},{"label":"B","text":"holding reserves above the reserve ratio agreed with the central bank"},{"label":"C","text":"taking excessive risks by demanding insufficient security from borrowers"},{"label":"D","text":"widening the gap in favour of a bank's assets over liabilities"}],"correct":""},{"id":15,"text":"What is most likely to result from a decrease in the natural rate of unemployment?","options":[{"label":"A","text":"a decrease in government expenditure on goods and services"},{"label":"B","text":"a decrease in the level of government payments to the unemployed"},{"label":"C","text":"a decrease in trade union membership"},{"label":"D","text":"a decrease in interest rates"}],"correct":""},{"id":16,"text":"The table gives the percentage (\\%) rates of youth unemployment and total unemployment in France and the UK in 2001 and 2005. } What can be concluded from the table?","options":[{"label":"A","text":"France and the UK experienced the same trends in unemployment."},{"label":"B","text":"France had a higher number of unemployed people than the UK."},{"label":"C","text":"The UK used a different definition of unemployment from France."},{"label":"D","text":"The UK was more successful than France in controlling unemployment."}],"correct":"","table":"<table><tr><td>*</td><td>2|c|France</td><td>2|c|UK</td></tr><tr><td>youth unemployment (%)</td><td>total unemployment (%)</td><td>youth unemployment (%)</td><td>total unemployment (%)</td></tr><tr><td>2001</td><td>19.2</td><td>8.7</td><td>12.0</td><td>5.2</td></tr><tr><td>2005</td><td>22.1</td><td>10.1</td><td>12.5</td><td>4.8</td></tr></table>"},{"id":17,"text":"What is a necessary assumption of the Keynesian multiplier model?","options":[{"label":"A","text":"increasing average propensity to save"},{"label":"B","text":"flexible costs and prices"},{"label":"C","text":"full employment of resources"},{"label":"D","text":"open economies"}],"correct":""},{"id":18,"text":"An economy has a sudden increase in inflation caused by a large rise in energy prices. It also enters a recession with rising unemployment.","options":[{"label":"A","text":"decrease in which policy variable is most likely to reduce the impact of the recession without increasing the price level further?"},{"label":"B","text":"government spending"},{"label":"C","text":"indirect taxation"},{"label":"D","text":"interest rate"}],"correct":""},{"id":19,"text":"What is not a threat to globalisation?","options":[{"label":"A","text":"rising fear of losing jobs to immigrant workers"},{"label":"B","text":"rising political tensions among major economies of the world"},{"label":"C","text":"stronger trade unions in industries producing substitutes of imports"},{"label":"D","text":"withdrawal of government support for inefficient industries"}],"correct":""},{"id":20,"text":"Singapore has one of the highest population densities in the world. It discourages car use through a high tax on second cars. Which additional policy would help to relieve road congestion in the short run?","options":[{"label":"A","text":"limiting the total number of car licences issued"},{"label":"B","text":"encouraging restrictions on the size of families"},{"label":"C","text":"improving infrastructure by building new roads"},{"label":"D","text":"replacing diesel cars by electric cars"}],"correct":""},{"id":21,"text":"What is not an example of an expenditure-reducing policy?","options":[{"label":"A","text":"a decrease in government spending"},{"label":"B","text":"a depreciation of the exchange rate"},{"label":"C","text":"an increase in direct taxes"},{"label":"D","text":"an increase in interest rates"}],"correct":""},{"id":22,"text":"What does the J-curve effect show?","options":[{"label":"A","text":"A successful currency depreciation requires the sum of the import and export elasticities of demand to be greater than 1."},{"label":"B","text":"After a currency devaluation, the current account is likely to get worse before it gets better."},{"label":"C","text":"In the short run, the demand for imports and exports tends to be price elastic."},{"label":"D","text":"The value of the terms of trade will affect the success of a currency's devaluation."}],"correct":""},{"id":23,"text":"What is the most likely consequence of an increase in the number of multinational companies?","options":[{"label":"A","text":"a decrease in advancements in technology"},{"label":"B","text":"a decrease in foreign direct investment"},{"label":"C","text":"an increase in exports"},{"label":"D","text":"an increase in unemployment"}],"correct":""},{"id":24,"text":"What will increase the size of a country's optimum population?","options":[{"label":"A","text":"a rise in the birth rate"},{"label":"B","text":"a lowering of the age of retirement"},{"label":"C","text":"a rise in the stock of capital available in the country"},{"label":"D","text":"a decrease in the productivity of the country's industries"}],"correct":""},{"id":25,"text":"The table shows the values of the Gini coefficient for some countries in a given year. } Using this information, which statement is correct?","options":[{"label":"A","text":"Income is distributed more equally in Denmark than France."},{"label":"B","text":"Income is distributed more equally in Namibia than Zambia."},{"label":"C","text":"Income per capita is higher in Zambia than Namibia."},{"label":"D","text":"There are proportionally more people below the poverty line in Zambia than France."}],"correct":"","table":"<table><tr><td>Gini coefficient</td></tr><tr><td>Namibia</td><td>74.3</td></tr><tr><td>Zambia</td><td>50.4</td></tr><tr><td>France</td><td>32.7</td></tr><tr><td>Denmark</td><td>24.7</td></tr></table>"},{"id":26,"text":"The table shows the values of the Gini coefficient for some countries in a given year. Using this information, which statement is correct?","options":[{"label":"A","text":"Income is distributed more equally in Denmark than France."},{"label":"B","text":"Income is distributed more equally in Namibia than Zambia."},{"label":"C","text":"Income per capita is higher in Zambia than Namibia."},{"label":"D","text":"There are proportionally more people below the poverty line in Zambia than France."}],"correct":"","table":"<table><tr><td></td><td>Gini coefficient</td></tr><tr><td>Namibia</td><td>74.3</td></tr><tr><td>Zambia</td><td>50.4</td></tr><tr><td>France</td><td>32.7</td></tr><tr><td>Denmark</td><td>24.7</td></tr></table>"}];

const paper_15: MCQQuestion[] = [{"id":1,"text":"The table shows the total utility gained by a consumer from the consumption of water. } What can be concluded from this table?","options":[{"label":"A","text":"Marginal utility increases as consumption increases."},{"label":"B","text":"The consumer cannot switch expenditure to another product to increase total utility."},{"label":"C","text":"The marginal utility of the 3rd unit is 8."},{"label":"D","text":"The marginal utility of the 5th unit is 2."}],"correct":"","table":"<table><tr><td>total utility</td></tr><tr><td>0</td><td>0</td></tr><tr><td>1</td><td>30</td></tr><tr><td>2</td><td>40</td></tr><tr><td>3</td><td>48</td></tr><tr><td>4</td><td>54</td></tr><tr><td>5</td><td>58</td></tr></table>"},{"id":2,"text":"Assuming the absence of price controls, in which industry is an individual firm least likely to be able to alter the price at which it sells its product?","options":[{"label":"A","text":"air transportation"},{"label":"B","text":"hairdressing"},{"label":"C","text":"steel production"},{"label":"D","text":"wheat farming"}],"correct":""},{"id":3,"text":"A firm has the choice between five levels of output. The table shows the total cost and total revenue of producing at each output level. The firm could sell whatever output it produces. } The firm decides to produce 4000 units. What is the firm's aim?","options":[{"label":"A","text":"to maximise profit"},{"label":"B","text":"to maximise sales"},{"label":"C","text":"to maximise revenue"},{"label":"D","text":"to minimise average costs"}],"correct":"","table":"<table><tr><td>total cost $</td><td>total revenue $</td></tr><tr><td>1000</td><td>8000</td><td>10000</td></tr><tr><td>2000</td><td>12000</td><td>18000</td></tr><tr><td>3000</td><td>19000</td><td>24000</td></tr><tr><td>4000</td><td>23000</td><td>28000</td></tr><tr><td>5000</td><td>25000</td><td>25000</td></tr></table>"},{"id":4,"text":"What is likely to make it more difficult for a small firm to survive?","options":[{"label":"A","text":"increased preference on the part of consumers for distinctive non-standardised products"},{"label":"B","text":"reductions in the rate of interest charged by commercial banks"},{"label":"C","text":"the absence of effective barriers to the entry of potential competitors"},{"label":"D","text":"the existence of decreasing returns to scale"}],"correct":""},{"id":5,"text":"A market structure in which a small number of firms face competition from potential entrants. What does this describe?","options":[{"label":"A","text":"a contestable market"},{"label":"B","text":"a monopoly"},{"label":"C","text":"monopolistic competition"},{"label":"D","text":"perfect competition"}],"correct":""},{"id":6,"text":"What is an example of backward vertical integration?","options":[{"label":"A","text":"a bakery buying a wheat farm"},{"label":"B","text":"a car manufacturer buying a car showroom"},{"label":"C","text":"a vineyard buying an apple orchard"},{"label":"D","text":"two rival supermarkets joining together"}],"correct":""},{"id":7,"text":"A government wants to introduce a policy that will reduce the pollution caused by the production of a good. Which policy would not make use of market forces?","options":[{"label":"A","text":"a quota to limit the production of the good"},{"label":"B","text":"a regulation to ban the production of the good"},{"label":"C","text":"a tax on the production of the good"},{"label":"D","text":"a tradable pollution permit system for producers of the good"}],"correct":""},{"id":8,"text":"The table shows the annual percentage change in the output per worker employed for four nationalised industries before and after privatisation. } What can be concluded about the effect of privatisation?","options":[{"label":"A","text":"Employment fell in the railway industry."},{"label":"B","text":"Employment was unchanged in the telecommunications industry."},{"label":"C","text":"Output was greatest in the electricity supply industry."},{"label":"D","text":"Workers became less efficient in the shipbuilding industry."}],"correct":"","table":"<table><tr><td>before privatisation %</td><td>after privatisation %</td></tr><tr><td>railways</td><td>-4</td><td>2</td></tr><tr><td>electricity supply</td><td>7</td><td>9</td></tr><tr><td>shipbuilding</td><td>4</td><td>-1</td></tr><tr><td>telecommunications</td><td>6</td><td>6</td></tr></table>"},{"id":9,"text":"Most workers in a country are employed in the manufacturing sector where they are paid a fixed wage rate per hour. What will lead to an increase in the net advantage of workers currently employed in the manufacturing sector?","options":[{"label":"A","text":"a reduction in working hours available"},{"label":"B","text":"a shift in the country's economy to the service sector"},{"label":"C","text":"a subsidised lunch is made available"},{"label":"D","text":"an increase in the number of jobs available"}],"correct":""},{"id":10,"text":"When will a profit-maximising firm employ the optimum number of workers?","options":[{"label":"A","text":"when the average revenue product of labour equals the average cost of hiring workers"},{"label":"B","text":"when the marginal revenue product of labour equals the average cost of hiring workers"},{"label":"C","text":"when the marginal revenue product of labour equals the marginal cost of hiring workers"},{"label":"D","text":"when the marginal revenue product of labour equals the trade union supplied cost of workers"}],"correct":""},{"id":11,"text":"What is not a function of a commercial bank?","options":[{"label":"A","text":"to help firms raise finance"},{"label":"B","text":"to hold cash on deposit for firms"},{"label":"C","text":"to lend money to households"},{"label":"D","text":"to provide savings accounts"}],"correct":""},{"id":12,"text":"In 2020 in a country, the unemployment rate of the 16-64 age group seeking work was 4.0\\%. The employment rate for this group in the same period was 76.6\\%. What can be concluded from this?","options":[{"label":"A","text":"19.4\\% of the economy is working illegally."},{"label":"B","text":"23.4\\% of the age group is economically inactive."},{"label":"C","text":"80.6\\% of the age group is economically active."},{"label":"D","text":"The data is inaccurate."}],"correct":""},{"id":13,"text":"Which statement relating to unemployment benefits provided by a government is not valid?","options":[{"label":"A","text":"They allow firms to dismiss workers as unemployment benefits provide support to unemployed workers."},{"label":"B","text":"They force firms to raise wages to encourage workers to work rather than relying on unemployment benefits."},{"label":"C","text":"They provide a safety net to workers which might reduce their efforts to find a suitable job."},{"label":"D","text":"They increase government spending and force it to raise taxes."}],"correct":""},{"id":14,"text":"Country X has a marginal propensity to consume (MPC) of 0.7. Its marginal propensity to save (MPS), marginal rate of taxation (MRT) and marginal propensity to import (MPM) are each 0.1. What is likely to lead to the biggest increase in the national income multiplier?","options":[{"label":"A","text":"a 5\\% increase in the MPC together with a 5\\% fall in the MRT"},{"label":"B","text":"a 5\\% increase in the MPM together with a 5\\% fall in the MRT"},{"label":"C","text":"a 5\\% increase in the MPS together with a 5\\% fall in the MPM"},{"label":"D","text":"a 5\\% increase in the MRT together with a 5\\% fall in the MPS"}],"correct":""},{"id":15,"text":"The diagrams show the performance of an economy using different measures. If an economy is currently at point X on each diagram, what is the most likely conclusion that can be made based on this evidence?","options":[{"label":"A","text":"Prices will increase significantly as the economy grows in the near future."},{"label":"B","text":"Supply-side policies would be the best option to encourage economic growth."},{"label":"C","text":"The economy is currently experiencing a deflationary gap."},{"label":"D","text":"There are shortages of skilled labour throughout the economy."}],"correct":"","image":"/images/econ-a2-mcq/186_207_1116_1390_397_0.jpg"},{"id":16,"text":"Which combination of policies would be most likely to bring a country out of recession?","options":[{"label":"A","text":"expansionary fiscal and monetary policy as well as supply-side policies"},{"label":"B","text":"expansionary fiscal policy and tight monetary policy"},{"label":"C","text":"tight fiscal and monetary policy"},{"label":"D","text":"supply-side policies alone"}],"correct":""},{"id":17,"text":"The inflation rate in a country increased. Which effect would this most likely have on the country's balance of payments?","options":[{"label":"A","text":"an improvement in the current account balance"},{"label":"B","text":"an increase in price competitiveness"},{"label":"C","text":"an increase in export revenue"},{"label":"D","text":"an increase in import expenditure"}],"correct":""},{"id":18,"text":"The table shows indicators for the macroeconomies of two South American countries over one year. During this year, both governments attempted to reduce unemployment by expanding aggregate demand. } Based on the information given, what is the most likely reason why Argentina achieved a higher \\% change in the unemployment rate than Chile?","options":[{"label":"A","text":"Argentina had a greater \\% change in GDP growth."},{"label":"B","text":"Chile's performance on the current account balance was worse."},{"label":"C","text":"Each country had a weak exchange rate against the US dollar."},{"label":"D","text":"Wage increases in each country were linked to their respective rates of inflation."}],"correct":"","table":"<table><tr><td>GDP % change</td><td>current account balance % of GDP</td><td>change in currency units against US dollar</td></tr><tr><td>Argentina</td><td>17.9</td><td>1.7</td><td>-18.9</td></tr><tr><td>Chile</td><td>17.2</td><td>-1.8</td><td>-13.3</td></tr></table>"},{"id":19,"text":"A measure encourages consumers to change spending on imports to spending on domestically produced goods. What does this describe?","options":[{"label":"A","text":"an expenditure-reducing policy"},{"label":"B","text":"an expenditure-switching policy"},{"label":"C","text":"the law of comparative advantage"},{"label":"D","text":"the Marshall-Lerner condition"}],"correct":""},{"id":20,"text":"The macroeconomic objective of a government is to move the current account of the balance of payments from deficit to surplus. To achieve this, it devalues the currency. Under which condition would a devaluation of the currency achieve this objective?","options":[{"label":"A","text":"if the combined price elasticity of demand for exports and imports is greater than 1"},{"label":"B","text":"if the combined price elasticity of demand for exports and imports is less than 1"},{"label":"C","text":"if the income elasticity of demand is less than 1"},{"label":"D","text":"if other countries decide to impose tariffs on all imported goods and services"}],"correct":""},{"id":21,"text":"The table gives information about the population of three countries in a given year. } Which conclusion can be drawn about the countries in the table in that year?","options":[{"label":"A","text":"China had the highest percentage of children who died in infancy."},{"label":"B","text":"People in Hong Kong lived the longest."},{"label":"C","text":"Singapore had the largest number of people aged over 16."},{"label":"D","text":"The population of Singapore was expected to fall in the next five years."}],"correct":"","table":"<table><tr><td>birth rate per 1000</td><td>death rate per 1000</td><td>infant mortality rate per 1000</td><td>% of population under 16</td></tr><tr><td>Singapore</td><td>12</td><td>4</td><td>5</td><td>18</td></tr><tr><td>Hong Kong</td><td>15</td><td>6</td><td>8</td><td>20</td></tr><tr><td>China</td><td>20</td><td>9</td><td>28</td><td>38</td></tr></table>"},{"id":22,"text":"During a certain period, a country with a constant population expands its output per head. It also experiences a significant increase in river and atmospheric pollution. In the absence of any other changes, which measure would show a decrease in living standards?","options":[{"label":"A","text":"Gross Domestic Product per head"},{"label":"B","text":"Gross National Product per head"},{"label":"C","text":"Human Development Index"},{"label":"D","text":"Measure of Economic Welfare"}],"correct":""},{"id":23,"text":"The table shows indicators for the macroeconomies of two South American countries over one year. During this year, both governments attempted to reduce unemployment by expanding aggregate demand. Based on the information given, what is the most likely reason why Argentina achieved a higher % change in the unemployment rate than Chile?","options":[{"label":"A","text":"Argentina had a greater % change in GDP growth."},{"label":"B","text":"Chile's performance on the current account balance was worse."},{"label":"C","text":"Each country had a weak exchange rate against the US dollar."},{"label":"D","text":"Wage increases in each country were linked to their respective rates of inflation."}],"correct":"","table":"<table><tr><td>country</td><td>GDP % change</td><td>current account balance % of GDP</td><td>change in currency units against US dollar</td></tr><tr><td>Argentina</td><td>17.9</td><td>1.7</td><td>-18.9</td></tr><tr><td>Chile</td><td>17.2</td><td>-1.8</td><td>-13.3</td></tr></table>"},{"id":24,"text":"The table gives information about the population of three countries in a given year. Which conclusion can be drawn about the countries in the table in that year?","options":[{"label":"A","text":"China had the highest percentage of children who died in infancy."},{"label":"B","text":"People in Hong Kong lived the longest."},{"label":"C","text":"Singapore had the largest number of people aged over 16."},{"label":"D","text":"The population of Singapore was expected to fall in the next five years."}],"correct":"","table":"<table><tr><td></td><td>birth rate per 1000</td><td>death rate per 1000</td><td>infant mortality rate per 1000</td><td>% of population under 16</td></tr><tr><td>Singapore</td><td>12</td><td>4</td><td>5</td><td>18</td></tr><tr><td>Hong Kong</td><td>15</td><td>6</td><td>8</td><td>20</td></tr><tr><td>China</td><td>20</td><td>9</td><td>28</td><td>38</td></tr></table>"}];

const paper_16: MCQQuestion[] = [{"id":1,"text":"A Belgian traffic study concluded that there would be significant benefits if 10\\% of car drivers switched to using motorcycles during peak traffic times. Which result would be considered a cost of this change?","options":[{"label":"A","text":"reduced travel times"},{"label":"B","text":"reduced car emissions"},{"label":"C","text":"reduced safety standards"},{"label":"D","text":"reduced traffic queues"}],"correct":""},{"id":2,"text":"The diagram shows a firm's long-run average cost curve (LRAC). What could explain the shape of the curve from X to Y?","options":[{"label":"A","text":"a decrease in total fixed cost"},{"label":"B","text":"increasing returns to scale"},{"label":"C","text":"internal diseconomies of scale"},{"label":"D","text":"more than one factor of production is variable"}],"correct":"","image":"/images/econ-a2-mcq/192_545_232_705_433_0.jpg"},{"id":3,"text":"LMN Ltd operates as a relatively small, family-owned producer in an industry dominated by a few large firms. Its product is unique so the owners are confident they will be able to sell enough to provide them with sufficient revenue to allow a minimum acceptable level of performance for the firm. Other than survival, what is the most likely objective of LMN Ltd?","options":[{"label":"A","text":"profit maximising"},{"label":"B","text":"profit satisficing"},{"label":"C","text":"revenue maximising"},{"label":"D","text":"sales maximising"}],"correct":""},{"id":4,"text":"What is a characteristic of monopolistic competition?","options":[{"label":"A","text":"no barriers to entry"},{"label":"B","text":"identical products"},{"label":"C","text":"price takers"},{"label":"D","text":"small number of buyers and sellers"}],"correct":""},{"id":5,"text":"What is likely to have its cause in the separation of ownership and control in a firm?","options":[{"label":"A","text":"contestable markets"},{"label":"B","text":"diseconomies of scale"},{"label":"C","text":"principal-agent problem"},{"label":"D","text":"prisoner's dilemma"}],"correct":""},{"id":6,"text":"Which government policy would not be classified as regulation?","options":[{"label":"A","text":"a ban on cocaine consumption"},{"label":"B","text":"compulsory wearing of seatbelts in cars"},{"label":"C","text":"licences for the extraction of water from rivers"},{"label":"D","text":"taxation of cigarettes"}],"correct":""},{"id":7,"text":"A government removes a subsidy on a rural school bus service. What is the effect of this on the market for this bus service?","options":[{"label":"A","text":"Deadweight loss decreases."},{"label":"B","text":"Private marginal costs increase."},{"label":"C","text":"Private marginal benefit decreases."},{"label":"D","text":"Social marginal costs decrease."}],"correct":""},{"id":8,"text":"The graph shows the percentage growth in average earnings for an economy. What is the most likely cause of the pattern shown in the graph?","options":[{"label":"A","text":"a decrease in the supply of labour"},{"label":"B","text":"a decrease in the interest rate"},{"label":"C","text":"an increase in productivity"},{"label":"D","text":") an increase in the size of the labour force"}],"correct":"","image":"/images/econ-a2-mcq/196_589_236_616_391_0.jpg"},{"id":9,"text":"The table shows the output of chairs at a factory when different numbers of workers are employed. } When will diminishing marginal returns to labour set in?","options":[{"label":"A","text":"when the second worker is employed"},{"label":"B","text":"when the third worker is employed"},{"label":"C","text":"then the fourth worker is employed"},{"label":"D","text":"when the fifth worker is employed"}],"correct":"","table":"<table><tr><td>0</td><td>1</td><td>2</td><td>3</td><td>4</td><td>5</td></tr><tr><td>number of chairs produced</td><td>0</td><td>7</td><td>17</td><td>26</td><td>34</td><td>40</td></tr></table>"},{"id":10,"text":"In the diagram, D represents the long-run demand curve for labour in a firm operating in an imperfect market. When there is a fall in the amount of capital invested per worker, the marginal revenue productivity of labour (MRP) curve shifts from \\({\\mathrm{{MRP}}}_{1}\\) to \\({\\mathrm{{MRP}}}_{2}\\) . labour employed How does this shift affect the amount of labour employed in the long run, when wages fall?","options":[{"label":"A","text":"It falls from \\({L}_{3}\\) to \\({L}_{2}\\) ."},{"label":"B","text":"It increases from \\({L}_{1}\\) to \\({L}_{2}\\) ."},{"label":"C","text":"It increases from \\({L}_{2}\\) to \\({L}_{3}\\) ."},{"label":"D","text":"It remains the same at \\({L}_{1}\\) ."}],"correct":"","image":"/images/econ-a2-mcq/197_618_371_557_539_0.jpg"},{"id":11,"text":"Which statement about money is correct?","options":[{"label":"A","text":"It consists solely of deposits held by commercial banks."},{"label":"B","text":"It functions as a medium of exchange."},{"label":"C","text":"Its monetary value equals its production costs."},{"label":"D","text":"It operates only when there is a double coincidence of wants."}],"correct":""},{"id":12,"text":"In country X, unemployment is rising at the same time as the number of job vacancies is increasing. What is the most likely reason for this?","options":[{"label":"A","text":"Economic growth is falling."},{"label":"B","text":"Economic growth is rising."},{"label":"C","text":"Geographical mobility of labour is rising."},{"label":"D","text":"Occupational immobility of labour is rising."}],"correct":""},{"id":13,"text":"An increase in which variable affecting labour markets is most likely to reduce the natural rate of unemployment?","options":[{"label":"A","text":"the level of unemployment benefit"},{"label":"B","text":"the militancy of trade unions"},{"label":"C","text":"the national minimum wage"},{"label":"D","text":"the participation on training courses"}],"correct":""},{"id":14,"text":"A consumer has an income of \\$1000 per week. The consumer spends 80\\% of this on goods and services. Following an increase in the consumer's income to \\$1200 per week, consumption increases to \\$900 per week. Which statement is correct?","options":[{"label":"A","text":"The average propensity to consume does not change."},{"label":"B","text":"The initial average propensity to consume is 5 ."},{"label":"C","text":"The marginal propensity to consume is 0.5 ."},{"label":"D","text":"The marginal propensity to consume is 2."}],"correct":""},{"id":15,"text":"What is not an aim of macroeconomic policy?","options":[{"label":"A","text":"economic development"},{"label":"B","text":"exchange rate stability"},{"label":"C","text":"Pareto optimality"},{"label":"D","text":"satisfactory balance of payments"}],"correct":""},{"id":16,"text":"The diagram shows an increase in aggregate demand (AD) from \\({\\mathrm{{AD}}}_{1}\\) to \\({\\mathrm{{AD}}}_{2}\\) . How can the subsequent impact on short-run and long-run macroeconomic equilibrium positions be shown using expectations-augmented Phillips curves?","options":[{"label":"A","text":"F to G to H"},{"label":"B","text":"F to G to K"},{"label":"C","text":"F to J to H"},{"label":"D","text":"F to J to K"}],"correct":"","image":"/images/econ-a2-mcq/199_526_836_750_485_0.jpg"},{"id":17,"text":"How could high interest rates increase a country's rate of inflation?","options":[{"label":"A","text":"by increasing the current borrowing costs of business"},{"label":"B","text":"by increasing the current borrowing costs of government"},{"label":"C","text":"by increasing the foreign exchange rate of the currency"},{"label":"D","text":"by increasing the opportunity cost of spending"}],"correct":""},{"id":18,"text":"What is most likely to influence subsequent increases in national income as a result of a government policy of reduced interest rates?","options":[{"label":"A","text":"marginal cost"},{"label":"B","text":"marginal efficiency of capital"},{"label":"C","text":"marginal product"},{"label":"D","text":"marginal utility"}],"correct":""},{"id":19,"text":"Which policy to reduce a current account deficit on the balance of payments could be described as an expenditure-switching policy?","options":[{"label":"A","text":"a decrease in government spending"},{"label":"B","text":"a decrease in the exchange rate of the country's currency"},{"label":"C","text":"an increase in domestic income taxes"},{"label":"D","text":"an increase in domestic interest rates"}],"correct":""},{"id":20,"text":"It is often argued that the UN Human Development Index (HDI) is a better indicator of economic development than income per capita because it adjusts for","options":[{"label":"A","text":"average hours worked by the population."},{"label":"B","text":"environmental pollution."},{"label":"C","text":"inequality in income distribution."},{"label":"D","text":"life expectancy at birth."}],"correct":""},{"id":21,"text":"Some conditions for providing foreign aid to low-income countries can be restrictive. Which kind of aid fits this description?","options":[{"label":"A","text":"food aid in the event of natural catastrophes such as severe drought"},{"label":"B","text":"grants that are tied to purchasing donor country goods"},{"label":"C","text":"loans that are repaid over a long period at a low rate of interest"},{"label":"D","text":"technical assistance using highly skilled worker transfers to provide support"}],"correct":""},{"id":22,"text":"What is most likely to cause the living standards of a country to rise?","options":[{"label":"A","text":"an increase in the number of doctors"},{"label":"B","text":"an increase in the gold reserves"},{"label":"C","text":"an increase in the number of people per house"},{"label":"D","text":"an increase in the money supply"}],"correct":""},{"id":23,"text":"The government increases interest rates in order to reduce the rate of inflation. What will also result from this action?","options":[{"label":"A","text":"a depreciation of the country's currency"},{"label":"B","text":"a fall in the level of savings"},{"label":"C","text":"a reduction in economic growth"},{"label":"D","text":"a reduction in unemployment"}],"correct":""},{"id":24,"text":"The diagram shows the relationship between the income tax rate and tax revenue. income tax rate Which statement is correct?","options":[{"label":"A","text":"A tax rate cut from \\( Y \\) to \\( Z \\) will cause tax revenue to decrease."},{"label":"B","text":"At tax rates below Z a tax rate cut will cause tax revenue to increase."},{"label":"C","text":"The greater the rate of tax beyond Z, the smaller will be the tax revenue generated."},{"label":"D","text":"Tax revenue will always increase as the rate of income tax increases."}],"correct":"","image":"/images/econ-a2-mcq/164_458_655_881_371_0.jpg"},{"id":25,"text":"In which situation is devaluation of the currency most likely to cause inflation?","options":[{"label":"A","text":"Excess capacity is available."},{"label":"B","text":"Import tariffs are reduced."},{"label":"C","text":"Local substitutes of imported raw materials are unavailable."},{"label":"D","text":"The demand for exports is price inelastic."}],"correct":""},{"id":26,"text":"A country imports most of the raw materials used as factor inputs. Which policy is most likely to control cost-push inflation?","options":[{"label":"A","text":"an appreciation of the exchange rate"},{"label":"B","text":"an increase in the rate of income tax"},{"label":"C","text":"an increase in the rate of interest"},{"label":"D","text":"an increase in the rate of sales tax"}],"correct":""},{"id":27,"text":"Germany, one of the world's strongest trading nations, achieved a surplus on current account of the balance of payments in 2021-2022. Which income flow would not have been included in the calculation of Germany's current account?","options":[{"label":"A","text":"Declining sales of German cars for export overseas."},{"label":"B","text":"Falling earnings of foreign exchange from visitors to Germany."},{"label":"C","text":"Increasing transfers of aid to less developed countries."},{"label":"D","text":"Investment in a natural gas pipeline link to its main foreign supplier."}],"correct":""},{"id":28,"text":"A country maintains its foreign exchange rate against the United States dollar, within a narrow but changing band. What is this type of exchange rate?","options":[{"label":"A","text":"fixed"},{"label":"B","text":"floating"},{"label":"C","text":"managed float"},{"label":"D","text":"trade-weighted"}],"correct":""},{"id":29,"text":"What is likely to happen in a developing country as it becomes more developed?","options":[{"label":"A","text":"A lower percentage of people will go to university."},{"label":"B","text":"Average life expectancy will rise."},{"label":"C","text":"The rate of population growth will increase."},{"label":"D","text":"The tertiary sector will decline in importance."}],"correct":""}];

const paper_17: MCQQuestion[] = [{"id":1,"text":"Which cost will continually decrease as a firm's output increases in the short run?","options":[{"label":"A","text":"average cost"},{"label":"B","text":"average fixed cost"},{"label":"C","text":"average variable cost"},{"label":"D","text":"marginal cost"}],"correct":""},{"id":2,"text":"What is an example of market failure?","options":[{"label":"A","text":"a firm incurring a loss by selling goods at prices below the average cost"},{"label":"B","text":"a guaranteed price that results in the accumulation of unsold stocks"},{"label":"C","text":"low income earners being unable to buy high-priced goods"},{"label":"D","text":"under-provision of a socially desirable good"}],"correct":""},{"id":3,"text":"What is likely to prevent the development of an effective cartel in an industry?","options":[{"label":"A","text":"a high concentration ratio"},{"label":"B","text":"a limit-pricing policy"},{"label":"C","text":"high fixed costs"},{"label":"D","text":"low barriers to entry"}],"correct":""},{"id":4,"text":"Which statement about the downward sloping demand curve of an inferior good is correct?","options":[{"label":"A","text":"Negative income effect and substitution effect move in opposite directions, leading to a steeper demand curve."},{"label":"B","text":"Negative income effect and substitution effect move in the same direction, leading to a flatter demand curve."},{"label":"C","text":"Positive income effect and substitution effect move in opposite directions, leading to a steeper demand curve."},{"label":"D","text":"Positive income effect and substitution effect move in the same direction, leading to a flatter demand curve."}],"correct":""},{"id":5,"text":"The diagram shows the private and social costs and benefits of production in a free market that result in market failure. Which change in output would be necessary to overcome this market failure?","options":[{"label":"A","text":"from K to M"},{"label":"B","text":"from M to N"},{"label":"C","text":"from M to L"},{"label":"D","text":"from N to L"}],"correct":"","image":"/images/econ-a2-mcq/218_651_794_706_468_0.jpg"},{"id":6,"text":"What is not an example of government failure?","options":[{"label":"A","text":"decreased maximum price causing producers to leave the market"},{"label":"B","text":"higher guaranteed price encouraging suppliers to overproduce"},{"label":"C","text":"increased minimum wage leading to employers dismissing workers"},{"label":"D","text":"increased subsidies encouraging the consumption of a socially desirable product"}],"correct":""},{"id":7,"text":"When does a more equal distribution of income occur?","options":[{"label":"A","text":"when a country's income tax system is made more progressive"},{"label":"B","text":"when someone is made better off without making someone else worse off"},{"label":"C","text":"when the best use is made of scarce resources"},{"label":"D","text":"when there is an increase in the Gini coefficient"}],"correct":""},{"id":8,"text":"What is not a reason for imposing a tax on producers based on the amount of pollution caused in the production process?","options":[{"label":"A","text":"Firms have a financial incentive to reduce pollution."},{"label":"B","text":"It is relatively hard to administer and monitor this tax scheme."},{"label":"C","text":"Some firms cause less pollution than others."},{"label":"D","text":"Taxes on pollution reduce negative production externalities."}],"correct":""},{"id":9,"text":"A government introduced a tax on soft drinks containing sugar. It was forecast that the tax would raise £520m per year for the government. However, the tax received was £240m. What is the most likely reason why the tax collected was lower than forecast?","options":[{"label":"A","text":"a specific tax instead of an ad valorem tax was introduced"},{"label":"B","text":"fewer drinks than originally forecast contained sugar"},{"label":"C","text":"most retailers did not increase the price of soft drinks"},{"label":"D","text":"the demand for soft drinks was price inelastic"}],"correct":""},{"id":10,"text":"A government's aim is to reduce real wage rates. Which policy should be used to achieve this aim?","options":[{"label":"A","text":"Award public sector workers pay increases below the rate of inflation."},{"label":"B","text":"Encourage private sector pay awards to be in line with company profits."},{"label":"C","text":"Introduce a minimum hourly wage for non-unionised, low-paid workers."},{"label":"D","text":"Remove any restrictions on trade unions to bargain for wages."}],"correct":""},{"id":11,"text":"How is marginal revenue product calculated?","options":[{"label":"A","text":"marginal physical product \\(\\times\\) marginal revenue"},{"label":"B","text":"marginal physical product \\(\\div\\) price"},{"label":"C","text":"total physical product \\(\\times\\) marginal cost"},{"label":"D","text":"total physical product \\(\\div\\) marginal cost"}],"correct":""},{"id":12,"text":"A teacher currently earns \\$30000. She would be willing to continue in that teaching job, provided she earned at least \\$25000. Also, she would prefer to remain a teacher than change to her next best alternative employment as an accountant where she could earn \\$40000. Which statement is correct?","options":[{"label":"A","text":"Her economic rent as a teacher is \\$5000."},{"label":"B","text":"Her economic rent as an accountant is \\$10000."},{"label":"C","text":"Her transfer earnings as a teacher are \\$30000."},{"label":"D","text":"Her transfer earnings as an accountant are \\$15000."}],"correct":""},{"id":13,"text":"What does the accelerator principle explain?","options":[{"label":"A","text":"how changes in consumption lead to changes in income"},{"label":"B","text":"how changes in income lead to changes in consumption"},{"label":"C","text":"; how changes in income lead to changes in investment"},{"label":"D","text":") how changes in investment lead to changes in income"}],"correct":""},{"id":14,"text":"The diagram shows an economy's production possibility curve. What causes a movement from point X to point Y?","options":[{"label":"A","text":"a positive output gap"},{"label":"B","text":"a recession"},{"label":"C","text":"catual economic growth"},{"label":"D","text":"potential economic growth"}],"correct":"","image":"/images/econ-a2-mcq/221_727_611_558_428_0.jpg"},{"id":15,"text":"In the quantity theory of money equation, MV = PT, V is defined as the income velocity of circulation. Which change would tend to reduce the value of V?","options":[{"label":"A","text":"a move to monthly rather than weekly salary payments by firms"},{"label":"B","text":"an increase in interest rates"},{"label":"C","text":"an increase in the use of cash machines to reduce money balances held"},{"label":"D","text":"a decrease in the use of credit cards by individuals"}],"correct":""},{"id":16,"text":"What is likely to improve the occupational mobility of labour?","options":[{"label":"A","text":"a decrease in income tax that increases aggregate demand"},{"label":"B","text":"a decrease in unemployment benefit"},{"label":"C","text":"an increase in retraining schemes for the unemployed"},{"label":"D","text":"more advertising of employment vacancies in the economy"}],"correct":""},{"id":17,"text":"Which policy may increase economic growth without causing inflation?","options":[{"label":"A","text":"giving subsidies to producers"},{"label":"B","text":"increasing government spending"},{"label":"C","text":"lowering direct taxes"},{"label":"D","text":"lowering interest rates"}],"correct":""},{"id":18,"text":"The current account on the balance of payments moves into deficit. What is a possible reason for this?","options":[{"label":"A","text":"a decrease in tax revenue"},{"label":"B","text":"export-led growth"},{"label":"C","text":"repayment of debts to other countries"},{"label":"D","text":"the import of new technology"}],"correct":""},{"id":19,"text":"Which policy would not lead to an increase in the value of a country's currency?","options":[{"label":"A","text":"an increase in domestic inflation"},{"label":"B","text":"an increase in domestic interest rates"},{"label":"C","text":"an increase in incomes abroad"},{"label":"D","text":"an increase in tourists visiting the country"}],"correct":""},{"id":20,"text":"In an economy with unemployed resources the marginal propensity to consume is 0.2 . The government increases its budget deficit and finances it by selling bonds to the non-bank private sector. What is the likely consequence of this?","options":[{"label":"A","text":"The currency will depreciate, increasing exports and reducing the trade deficit."},{"label":"B","text":"The increase in real output will be limited as the value of the multiplier is low."},{"label":"C","text":"The money supply will fall, leading to a reduction in aggregate demand."},{"label":"D","text":"There will be a decrease in the rate of interest, causing demand-pull inflation."}],"correct":""},{"id":21,"text":"The graph plots the Gini coefficient and GDP per head for three countries, X, Y and Z. What can be concluded from the graph?","options":[{"label":"A","text":"Average incomes are higher in country X than in country Z."},{"label":"B","text":"Country X is the least developed country."},{"label":"C","text":"Income is equally distributed in country Y."},{"label":"D","text":"The distribution of income in country \\(Y\\) is more even than in country \\(X\\) ."}],"correct":"","image":"/images/econ-a2-mcq/224_576_973_857_406_0.jpg"},{"id":22,"text":"What is least likely to lead to an increase in optimum population?","options":[{"label":"A","text":"an improvement in labour productivity"},{"label":"B","text":"an improvement in the quality of capital and technology"},{"label":"C","text":"an increase in birth rate and a fall in death rate"},{"label":"D","text":"an increase in the availability of natural resources"}],"correct":""},{"id":23,"text":"What is not included as a weighted indicator of poverty in the Multidimensional Poverty Index (MPI)?","options":[{"label":"A","text":"cooking fuel"},{"label":"B","text":"electricity"},{"label":"C","text":"medication"},{"label":"D","text":"water"}],"correct":""},{"id":24,"text":"Which role is performed by the World Bank but not by the International Monetary Fund (IMF)?","options":[{"label":"A","text":"facilitating free trade among member countries"},{"label":"B","text":"providing assistance to member countries to plan fiscal policies"},{"label":"C","text":"providing bailout packages to countries facing external account challenges"},{"label":"D","text":"providing monetary assistance to member countries to build infrastructure"}],"correct":""},{"id":25,"text":"Some economists argue there is little evidence of the value of aid in improving economic development in less-developed countries. Which situation supports this claim?","options":[{"label":"A","text":"Capacity to benefit from transfer of communications technology has increased."},{"label":"B","text":"Investment in infrastructure has created transport links and port facilities."},{"label":"C","text":"Over-reliance on technical assistance has impaired local initiatives and innovation."},{"label":"D","text":"Projects for education and training have helped to enhance the supply side."}],"correct":""}];

const paper_18: MCQQuestion[] = [{"id":1,"text":"The diagram shows the cost and revenue curves for a natural monopoly. Which statement is correct?","options":[{"label":"A","text":"\\({\\mathrm{P}}_{2}\\) and \\({\\mathrm{Q}}_{2}\\) will achieve both allocative efficiency and productive efficiency."},{"label":"B","text":"\\({P}_{2}\\) and \\({Q}_{1}\\) will achieve productive efficiency but not allocative efficiency."},{"label":"C","text":"\\({\\mathrm{P}}_{3}\\) and \\({\\mathrm{Q}}_{3}\\) will achieve allocative efficiency but not productive efficiency."},{"label":"D","text":"\\({P}_{3}\\) and \\({Q}_{3}\\) will achieve both allocative efficiency and productive efficiency."}],"correct":"","image":"/images/econ-a2-mcq/228_475_720_844_614_0.jpg"},{"id":2,"text":"What would not affect the budget line of an individual consumer?","options":[{"label":"A","text":"the individual's preference for various goods"},{"label":"B","text":"the level of income tax"},{"label":"C","text":"the money prices of goods"},{"label":"D","text":"the incomes earned by the individual"}],"correct":""},{"id":3,"text":"The diagram shows the marginal private costs (MPC) and marginal private benefits (MPB) of a product. Consumers initially estimate that marginal private costs are at \\({\\mathrm{{MPC}}}_{1}\\) and marginal private benefits are at \\({\\mathrm{{MPB}}}_{1}\\) . What is the impact on the market demand for the product if the consumer realises they have underestimated the MPC of buying the product but not the MPB?","options":[{"label":"A","text":"The consumer underconsumes the product by \\({Q}_{1}{Q}_{2}\\) ."},{"label":"B","text":"The consumer underconsumes the product by \\({Q}_{1}{Q}_{3}\\) ."},{"label":"C","text":"The consumer overconsumes the product by \\({Q}_{1}{Q}_{3}\\) ."},{"label":"D","text":"The consumer overconsumes the product by \\({Q}_{1}{Q}_{4}\\) ."}],"correct":"","image":"/images/econ-a2-mcq/229_544_324_713_617_0.jpg"},{"id":4,"text":"What is an internal economy of scale?","options":[{"label":"A","text":"efficient local transport networks"},{"label":"B","text":"improved access to spare parts as a result of industry growth"},{"label":"C","text":"lower risks from supplying a wider range of customers"},{"label":"D","text":"the training of skilled labour at a college financed by local firms"}],"correct":""},{"id":5,"text":"A government introduces tradeable pollution permits to reduce pollution. What is an advantage of this scheme?","options":[{"label":"A","text":"It allows consumers to determine the optimum pollution level."},{"label":"B","text":"It can provide rewards for firms that reduce pollution."},{"label":"C","text":"It enables the government to raise revenue from the resale of permits."},{"label":"D","text":"It uses the market system with no administrative costs."}],"correct":""},{"id":6,"text":"To reduce traffic congestion, a government built a new highway. A majority of the citizens were opposed to this. Some citizens responded by switching from public transport to private cars. This caused car journeys to take even longer. What can be concluded about government failure in this case?","options":[{"label":"A","text":"It occurred because the government's opportunity costs were not considered."},{"label":"B","text":"It occurred because the wishes of the majority of citizens were ignored."},{"label":"C","text":"It occurred because the result was unintended."},{"label":"D","text":"It occurred from over-reliance on the market system."}],"correct":""},{"id":7,"text":"What could result in an individual being caught in the poverty trap if their income increases?","options":[{"label":"A","text":"national minimum wage is changed"},{"label":"B","text":"benefits payments are means-tested"},{"label":"C","text":"subsidised housing payments for low-income earners are increased"},{"label":"D","text":"the income level at which income tax is first paid is increased"}],"correct":""},{"id":8,"text":"What is an example of 'nudge' theory as applied to the prevention of tax evasion?","options":[{"label":"A","text":"employing an extensive administration to ensure detection of evasion"},{"label":"B","text":"imposing heavy penalties on those who do evade tax"},{"label":"C","text":"providing information to taxpayers about the undesirable effects of tax evasion"},{"label":"D","text":"requiring employers to inform the tax authorities of workers' pay"}],"correct":""},{"id":9,"text":"In an economy with no government sector or foreign trade, the marginal propensity to consume is 0.6. If the equilibrium level of national income is \\(\\$ {10000}\\) million and the full employment level of national income is \\$15000 million, by how much would investment have to increase to achieve full employment?","options":[{"label":"A","text":"\\$1666 million"},{"label":"B","text":"\\$2000 million"},{"label":"C","text":"\\$3012 million"},{"label":"D","text":"\\$5000 million"}],"correct":""},{"id":10,"text":"What is a factor affecting the occupational mobility of labour?","options":[{"label":"A","text":"education and training"},{"label":"B","text":"immigration controls"},{"label":"C","text":"price of housing"},{"label":"D","text":"transport infrastructure"}],"correct":""},{"id":11,"text":"A government increases its inflation rate target from 3\\% to 5\\%. What is a likely reason for this?","options":[{"label":"A","text":"to increase economic sustainability"},{"label":"B","text":"to increase saving"},{"label":"C","text":"to reduce a balance of payments deficit"},{"label":"D","text":"to reduce unemployment"}],"correct":""},{"id":12,"text":"What would be a macroeconomic policy objective for a government in a developed economy?","options":[{"label":"A","text":"to improve sustainability"},{"label":"B","text":"to provide public goods"},{"label":"C","text":"to reduce the power of trade unions"},{"label":"D","text":"to subsidise the electricity supply industry"}],"correct":""},{"id":13,"text":"An economy is at its natural rate of unemployment. Under which circumstances will an increase in government spending aimed at reducing unemployment be most likely to conflict with a government's objective of low inflation?","options":[{"label":"A","text":"if inflationary expectations are unchanged"},{"label":"B","text":"if inflationary expectations fall"},{"label":"C","text":"if labour productivity increases"},{"label":"D","text":"if labour supply increases"}],"correct":""},{"id":14,"text":"A country's government imposes a tariff on steel imports. What is the likely impact of this tariff on this country's economy?","options":[{"label":"A","text":"It will make this country's steel exports more price competitive."},{"label":"B","text":"It will lead to productive inefficiency in this country's steel industry."},{"label":"C","text":"There will be an improvement in this country's terms of trade."},{"label":"D","text":"There will be a decrease in producer surplus for this country's steel producers."}],"correct":""},{"id":15,"text":"Which measurement is not included in the calculation of the Human Development Index?","options":[{"label":"A","text":"average years of schooling"},{"label":"B","text":"Gross National Income per capita"},{"label":"C","text":"infant mortality rate"},{"label":"D","text":"life expectancy at birth"}],"correct":""},{"id":16,"text":"What is not a function of the International Monetary Fund (IMF)?","options":[{"label":"A","text":"to encourage exchange rate stability"},{"label":"B","text":"to provide financial assistance for a country with failed economic policies"},{"label":"C","text":"to provide funds for a water purifying plant in a developing country"},{"label":"D","text":"to provide loans for countries following a natural disaster"}],"correct":""},{"id":17,"text":"The diagram shows the effect of trade creation if a tariff is removed. Which areas show the total net gain to the domestic economy?","options":[{"label":"A","text":"v, w, x and y"},{"label":"B","text":"v, w and x only"},{"label":"C","text":"w and x only"},{"label":"D","text":"w and y only"}],"correct":"","image":"/images/econ-a2-mcq/238_414_249_971_605_0.jpg"},{"id":18,"text":"Which statement relating to unemployment benefits provided by a government is not valid?","options":[{"label":"A","text":"They allow firms to dismiss workers as unemployment benefits provide support to unemployed workers."},{"label":"B","text":"They force firms to raise wages to encourage workers to work rather than relying on unemployment benefits."},{"label":"C","text":"They provide a safety net to workers which might reduce their efforts to find a suitable job."},{"label":"D","text":"They increase government spending and force it to raise taxes."}],"correct":""},{"id":19,"text":"Country X has a marginal propensity to consume (MPC) of 0.7. Its marginal propensity to save (MPS), marginal rate of taxation (MRT) and marginal propensity to import (MPM) are each 0.1. What is likely to lead to the biggest increase in the national income multiplier?","options":[{"label":"A","text":"a 5% increase in the MPC together with a 5% fall in the MRT"},{"label":"B","text":"a 5% increase in the MPM together with a 5% fall in the MRT"},{"label":"C","text":"a 5% increase in the MPS together with a 5% fall in the MPM"},{"label":"D","text":"a 5% increase in the MRT together with a 5% fall in the MPS"}],"correct":""},{"id":20,"text":"The diagrams show the performance of an economy using different measures. If an economy is currently at point X on each diagram, what is the most likely conclusion that can be made based on this evidence?","options":[{"label":"A","text":"Prices will increase significantly as the economy grows in the near future."},{"label":"B","text":"Supply-side policies would be the best option to encourage economic growth."},{"label":"C","text":"The economy is currently experiencing a deflationary gap."},{"label":"D","text":"There are shortages of skilled labour throughout the economy."}],"correct":"","image":"/images/econ-a2-mcq/186_207_1116_1390_397_0.jpg"},{"id":21,"text":"Which combination of policies would be most likely to bring a country out of recession?","options":[{"label":"A","text":"expansionary fiscal and monetary policy as well as supply-side policies"},{"label":"B","text":"expansionary fiscal policy and tight monetary policy"},{"label":"C","text":"tight fiscal and monetary policy"},{"label":"D","text":"supply-side policies alone"}],"correct":""},{"id":22,"text":"The inflation rate in a country increased. Which effect would this most likely have on the country's balance of payments?","options":[{"label":"A","text":"an improvement in the current account balance"},{"label":"B","text":"an increase in price competitiveness"},{"label":"C","text":"an increase in export revenue"},{"label":"D","text":"an increase in import expenditure"}],"correct":""},{"id":23,"text":"The table shows indicators for the macroeconomies of two South American countries over one year. During this year, both governments attempted to reduce unemployment by expanding aggregate demand. Based on the information given, what is the most likely reason why Argentina achieved a higher % change in the unemployment rate than Chile?","options":[{"label":"A","text":"Argentina had a greater % change in GDP growth."},{"label":"B","text":"Chile's performance on the current account balance was worse."},{"label":"C","text":"Each country had a weak exchange rate against the US dollar."},{"label":"D","text":"Wage increases in each country were linked to their respective rates of inflation."}],"correct":"","table":"<table><tr><td>country</td><td>GDP % change</td><td>current account balance % of GDP</td><td>change in currency units against US dollar</td></tr><tr><td>Argentina</td><td>17.9</td><td>1.7</td><td>-18.9</td></tr><tr><td>Chile</td><td>17.2</td><td>-1.8</td><td>-13.3</td></tr></table>"},{"id":24,"text":"A measure encourages consumers to change spending on imports to spending on domestically produced goods. What does this describe?","options":[{"label":"A","text":"an expenditure-reducing policy"},{"label":"B","text":"an expenditure-switching policy"},{"label":"C","text":"the law of comparative advantage"},{"label":"D","text":"the Marshall-Lerner condition"}],"correct":""},{"id":25,"text":"The macroeconomic objective of a government is to move the current account of the balance of payments from deficit to surplus. To achieve this, it devalues the currency. Under which condition would a devaluation of the currency achieve this objective?","options":[{"label":"A","text":"if the combined price elasticity of demand for exports and imports is greater than 1"},{"label":"B","text":"if the combined price elasticity of demand for exports and imports is less than 1"},{"label":"C","text":"if the income elasticity of demand is less than 1"},{"label":"D","text":"if other countries decide to impose tariffs on all imported goods and services"}],"correct":""},{"id":26,"text":"The table gives information about the population of three countries in a given year. Which conclusion can be drawn about the countries in the table in that year?","options":[{"label":"A","text":"China had the highest percentage of children who died in infancy."},{"label":"B","text":"People in Hong Kong lived the longest."},{"label":"C","text":"Singapore had the largest number of people aged over 16."},{"label":"D","text":"The population of Singapore was expected to fall in the next five years."}],"correct":"","table":"<table><tr><td></td><td>birth rate per 1000</td><td>death rate per 1000</td><td>infant mortality rate per 1000</td><td>% of population under 16</td></tr><tr><td>Singapore</td><td>12</td><td>4</td><td>5</td><td>18</td></tr><tr><td>Hong Kong</td><td>15</td><td>6</td><td>8</td><td>20</td></tr><tr><td>China</td><td>20</td><td>9</td><td>28</td><td>38</td></tr></table>"},{"id":27,"text":"During a certain period, a country with a constant population expands its output per head. It also experiences a significant increase in river and atmospheric pollution. In the absence of any other changes, which measure would show a decrease in living standards?","options":[{"label":"A","text":"Gross Domestic Product per head"},{"label":"B","text":"Gross National Product per head"},{"label":"C","text":"Human Development Index"},{"label":"D","text":"Measure of Economic Welfare"}],"correct":""}];

const paper_19: MCQQuestion[] = [{"id":1,"text":"The diagram shows budget lines for an individual consumer. What could explain the shift in the budget line from QR to ST?","options":[{"label":"A","text":"a decrease in the consumer's real income"},{"label":"B","text":"a decrease in the quality of both goods"},{"label":"C","text":"an increase in the consumer's money income"},{"label":"D","text":"an increase in the price of both goods"}],"correct":"","image":"/images/econ-a2-mcq/239_595_250_620_545_0.jpg"},{"id":2,"text":"When is allocative efficiency achieved?","options":[{"label":"A","text":"when a perfectly competitive market is in equilibrium"},{"label":"B","text":"when everybody who needs the product can obtain it"},{"label":"C","text":"when firms produce at the lowest possible cost"},{"label":"D","text":"when monopolistic firms make normal profits"}],"correct":""},{"id":3,"text":"When might a moral hazard occur?","options":[{"label":"A","text":"When a consumer does not have full information about a product."},{"label":"B","text":"When a person undertakes an activity that causes harm to another person."},{"label":"C","text":"When a person undertakes a risky activity, knowing another person bears the risk."},{"label":"D","text":"When the seller of a product has more information than the buyer."}],"correct":""},{"id":4,"text":"What would enable a firm to increase its market share in a monopolistically competitive market?","options":[{"label":"A","text":"barriers to entry"},{"label":"B","text":"collusion"},{"label":"C","text":"lack of competition"},{"label":"D","text":"successful advertising"}],"correct":""},{"id":5,"text":"Two manufacturing firms in the same industry, producing similar products, are considering merging together. What would be the least convincing reason for merging?","options":[{"label":"A","text":"It would enable greater bargaining power when buying raw materials."},{"label":"B","text":"It would enable technical economies of scale."},{"label":"C","text":"It would produce savings in management and administration costs."},{"label":"D","text":"It would reduce the dependence of the firms on the suppliers of raw materials."}],"correct":""},{"id":6,"text":"The marginal social benefit of consuming a drink is less than the marginal private benefit. What would be the best policy to improve resource allocation in this market?","options":[{"label":"A","text":"give a subsidy to the producers of the drink"},{"label":"B","text":"increase competition in the drink industry"},{"label":"C","text":"impose a maximum price for the drink above the market equilibrium price"},{"label":"D","text":"impose a per unit tax on the drink"}],"correct":""},{"id":7,"text":"A country's government banned cigarette smoking in enclosed public spaces, such as offices, shops, bars and restaurants. What is a government failure arising from this ban?","options":[{"label":"A","text":"decreased consumption of cigarettes by smokers"},{"label":"B","text":"decreased levels of passive cigarette smoking by non-smokers"},{"label":"C","text":"increased litter from used cigarettes outside offices and shops"},{"label":"D","text":"increased sales of cigarette substitutes like nicotine patches and gum"}],"correct":""},{"id":8,"text":"A worker has a low wage. They have little incentive to earn extra income because they will pay more income tax and receive fewer means-tested benefits. What describes this worker's situation?","options":[{"label":"A","text":"employment trap"},{"label":"B","text":"liquidity trap"},{"label":"C","text":"poverty trap"},{"label":"D","text":"unemployment trap"}],"correct":""},{"id":9,"text":"What is not an outcome of the existence of private property rights?","options":[{"label":"A","text":"They encourage private owners to conserve property when its value is expected to rise."},{"label":"B","text":"They give private owners the incentive to manage their property carefully."},{"label":"C","text":"They make private owners accountable for damage to others from property misuse."},{"label":"D","text":"They prevent private owners gaining from using resources to benefit others."}],"correct":""},{"id":10,"text":"The diagram shows the labour market for a profit maximising industry with a monopsony employer. What will decrease if a minimum wage of \\({\\mathrm{W}}_{1}\\) is introduced?","options":[{"label":"A","text":"economic rent"},{"label":"B","text":"transfer earnings"},{"label":"C","text":"unemployment"},{"label":"D","text":"wages"}],"correct":"","image":"/images/econ-a2-mcq/242_405_249_992_509_0.jpg"},{"id":11,"text":"What is not a factor affecting the supply of labour?","options":[{"label":"A","text":"emigration rates"},{"label":"B","text":"labour participation rate"},{"label":"C","text":"labour productivity"},{"label":"D","text":"unemployment benefits"}],"correct":""},{"id":12,"text":"An initial injection into the circular flow of income causes a much larger increase in GDP. What does this define?","options":[{"label":"A","text":"autonomous investment"},{"label":"B","text":"demand-pull inflation"},{"label":"C","text":"the accelerator principle"},{"label":"D","text":"the national income multiplier"}],"correct":""},{"id":13,"text":"An increase in a country's inflation rate causes real incomes to decline, but consumers decide to maintain their living standards. What has increased?","options":[{"label":"A","text":"autonomous consumer spending"},{"label":"B","text":"autonomous saving"},{"label":"C","text":"induced consumer spending"},{"label":"D","text":"induced savings"}],"correct":""},{"id":14,"text":"A government decreases interest rates to reduce unemployment but finds this has little effect due to hysteresis. What causes this hysteresis?","options":[{"label":"A","text":"capital investment increases"},{"label":"B","text":"fewer people are encouraged to save"},{"label":"C","text":"skills of unemployed workers become outdated"},{"label":"D","text":"the money supply increases"}],"correct":""},{"id":15,"text":"In a closed economy, the central bank raises interest rates to reduce an increasing rate of inflation. Which macroeconomic policy objective is this targeting?","options":[{"label":"A","text":"a surplus on the current account of the balance of payments"},{"label":"B","text":"faster economic growth"},{"label":"C","text":"full employment"},{"label":"D","text":"stable prices"}],"correct":""},{"id":16,"text":"A government sets a target for the annual rate of inflation to be no more than 3\\%. Which circumstances would make it difficult to achieve the target?","options":[{"label":"A","text":"if devaluation of the currency leads to a trade surplus"},{"label":"B","text":"if interest rates are increased to control effective demand"},{"label":"C","text":"if the government increases its tax revenue"},{"label":"D","text":"if wage increases are kept in line with productivity"}],"correct":""},{"id":17,"text":"What is the most likely consequence when there is an increase in the national debt?","options":[{"label":"A","text":"the creation of additional money"},{"label":"B","text":"a current account deficit on the balance of payments"},{"label":"C","text":"a surplus in the government's budget"},{"label":"D","text":"the crowding out of private sector investment"}],"correct":""},{"id":18,"text":"Which policy will help to reduce income inequality?","options":[{"label":"A","text":"to increase indirect taxes"},{"label":"B","text":"to increase trade union power"},{"label":"C","text":"to increase the rate of interest"},{"label":"D","text":"to reduce welfare payments"}],"correct":""},{"id":19,"text":"The value of the currency of an open economy with a fixed exchange rate is significantly below its purchasing power parity value. If the economy decides to adopt a floating exchange rate, which of its macroeconomic policy aims is most likely to benefit?","options":[{"label":"A","text":"low inflation"},{"label":"B","text":"low unemployment"},{"label":"C","text":"reduced deficit on the current account of the balance of payments"},{"label":"D","text":"steady economic growth"}],"correct":""},{"id":20,"text":"Which policy will help to correct a deficit on the current account of the balance of payments?","options":[{"label":"A","text":"decreasing direct taxes"},{"label":"B","text":"decreasing government regulations"},{"label":"C","text":"increasing exchange rates"},{"label":"D","text":"increasing government spending"}],"correct":""},{"id":21,"text":"The following are four conditions sometimes attached to IMF loans to low-income countries. Which condition would conflict with the 'infant industry' argument?","options":[{"label":"A","text":"the need to allow free trade"},{"label":"B","text":"the need to control inflation"},{"label":"C","text":"the need to have a contractionary fiscal policy"},{"label":"D","text":"the need to privatise government enterprises"}],"correct":""},{"id":22,"text":"A government sets a target for the annual rate of inflation to be no more than 3%. Which circumstances would make it difficult to achieve the target?","options":[{"label":"A","text":"if devaluation of the currency leads to a trade surplus"},{"label":"B","text":"if interest rates are increased to control effective demand"},{"label":"C","text":"if the government increases its tax revenue"},{"label":"D","text":"if wage increases are kept in line with productivity"}],"correct":""}];

const paper_20: MCQQuestion[] = [{"id":1,"text":"What is likely to lead to the principal-agent problem?","options":[{"label":"A","text":"a manager of a business makes decisions on behalf of the owner"},{"label":"B","text":"music festival tickets are purchased by a person who intends to sell them at a large profit"},{"label":"C","text":"the government is the only buyer of a pharmaceutical product"},{"label":"D","text":"there is only one firm that manufactures the product"}],"correct":""},{"id":2,"text":"A small European airline currently produces at point X on its long-run average cost curve (LRAC). It wants a bigger share of the European airline market and proposes to merge with another small European airline. The newly merged firm would produce at point \\(Y\\) on the long-run average cost curve, as shown. Why might the newly merged firm be able to produce at point Y?","options":[{"label":"A","text":"The new airline can negotiate discounts when buying fuel."},{"label":"B","text":"The new airline has many layers of management."},{"label":"C","text":"The new airline is unable to hire enough pilots."},{"label":"D","text":"The workforce of the new airline lacks morale and is demotivated."}],"correct":"","image":"/images/econ-a2-mcq/250_552_721_695_423_0.jpg"},{"id":3,"text":"A consumer maximises his total utility by initially buying 10 units of good X and 10 units of good Y. Assuming both goods are normal, what would cause this utility-maximising consumer to purchase more of good Y and less of good X?","options":[{"label":"A","text":"an increase in the marginal utility of good Y"},{"label":"B","text":"an increase in the price of good Y"},{"label":"C","text":"an increase in the tax on the consumption of good Y"},{"label":"D","text":"an increase in the tax on the income of consumers"}],"correct":""},{"id":4,"text":"What is most likely to lead to a Pareto-optimal outcome?","options":[{"label":"A","text":"offering bulk-buy discounts to customers who join a loyalty scheme"},{"label":"B","text":"switching labour from producing low-priced products to producing high-priced products"},{"label":"C","text":"switching production from labour-intensive products to capital-intensive products"},{"label":"D","text":"training low-skilled workers to operate machinery effectively"}],"correct":""},{"id":5,"text":"The diagram shows the cost and revenue curves of a firm. The firm changes its objective from revenue maximisation to sales maximisation. What will be the effect on quantity produced?","options":[{"label":"A","text":"it will decrease from \\(\\mathrm{Y}\\) to \\(\\mathrm{W}\\)"},{"label":"B","text":"it will decrease from \\(\\mathrm{Z}\\) to \\(\\mathrm{W}\\)"},{"label":"C","text":"it will increase from \\(X\\) to \\(Y\\)"},{"label":"D","text":"it will increase from \\(X\\) to \\(Z\\)"}],"correct":"","image":"/images/econ-a2-mcq/253_503_250_793_561_0.jpg"},{"id":6,"text":"Which government policy is intended to correct a negative externality?","options":[{"label":"A","text":"guaranteed minimum prices for farmers producing certain agricultural products"},{"label":"B","text":"imposition of taxes on factories releasing pollutants into rivers"},{"label":"C","text":"rent controls on housing occupied by low-income individuals"},{"label":"D","text":"the provision of free books for children of poorer households"}],"correct":""},{"id":7,"text":"Which policy is most likely to contribute to people ending up in a poverty trap?","options":[{"label":"A","text":"legal minimum wage"},{"label":"B","text":"means-tested benefits"},{"label":"C","text":"prevention of cheaper imports"},{"label":"D","text":"proportional taxation"}],"correct":""},{"id":8,"text":"Extra fishing boats start to operate from a local harbour which depends on fishing for its main income. Which action by the local authority is an example of nudge theory?","options":[{"label":"A","text":"insisting that all fish caught are sold to local people"},{"label":"B","text":"increasing the licence fees for new boats"},{"label":"C","text":"distributing leaflets about the need to safeguard fish stocks"},{"label":"D","text":"restricting the areas in which boats can fish"}],"correct":""},{"id":9,"text":"The diagram shows the effect of introducing an effective national minimum wage (NMW) in a labour market with a profit maximising monopsonist employer. labour employed What is the effect of the NMW on the deadweight welfare loss in this market?","options":[{"label":"A","text":"It falls from RST to UVT."},{"label":"B","text":"It falls from RSVU to UVT."},{"label":"C","text":"It rises from UVT to RST."},{"label":"D","text":"It rises from UVT to RSVU."}],"correct":"","image":"/images/econ-a2-mcq/255_474_759_851_580_0.jpg"},{"id":10,"text":"What is an advantage of pollution permits, when compared with an alternative policy of taxes levied on the quantity of pollutants emitted by firms?","options":[{"label":"A","text":"firms cannot sell any surplus permits"},{"label":"B","text":"no monitoring of firms' emissions is required"},{"label":"C","text":"pollution levels can be reduced to zero"},{"label":"D","text":"the reduction in the level of pollution is more predictable"}],"correct":""},{"id":11,"text":"Which statement about the quantity theory of money is correct?","options":[{"label":"A","text":"It suggests changes in liquidity preference lead to proportional changes in the price level."},{"label":"B","text":"It suggests changes in the money supply lead to proportional changes in the price level."},{"label":"C","text":"It suggests changes in the price level lead to proportional changes in liquidity preference."},{"label":"D","text":"It suggests changes in the price level lead to proportional changes in the money supply."}],"correct":""},{"id":12,"text":"What is a part of Keynesian economic analysis?","options":[{"label":"A","text":"a liquidity trap below which interest rates are ineffective"},{"label":"B","text":"an equilibrium price that always clears the market"},{"label":"C","text":"a small value for the government expenditure multiplier"},{"label":"D","text":"a vertical short-run aggregate supply curve"}],"correct":""},{"id":13,"text":"What describes a Keynesian measure to reduce cyclical unemployment?","options":[{"label":"A","text":"adopting a supply-side policy to retrain unskilled workers"},{"label":"B","text":"allowing the private sector to take over the supply of merit goods"},{"label":"C","text":"increasing the ratio of capital equipment to manual labour in production"},{"label":"D","text":"using fiscal policy to increase effective demand"}],"correct":""},{"id":14,"text":"What is a likely consequence of an increase in government spending on education?","options":[{"label":"A","text":"increase in the supply of unskilled labour"},{"label":"B","text":"increase in occupational mobility"},{"label":"C","text":"increase in the rate of unemployment"},{"label":"D","text":"increase in trade union power"}],"correct":""},{"id":15,"text":"What may prevent a government achieving a faster rate of growth of real GDP?","options":[{"label":"A","text":"The multiplier has a small value."},{"label":"B","text":"The consumer price index is below its target set by the central bank."},{"label":"C","text":"The economy is operating on the vertical section of the long-run aggregate supply curve."},{"label":"D","text":"There is a large negative output gap in the economy."}],"correct":""},{"id":16,"text":"A fall in domestic investment leads to an increase in unemployment. Which other economic problem is likely to occur as a result?","options":[{"label":"A","text":"an increase in interest rates on loans for house purchases"},{"label":"B","text":"an increase in the current account balance of payments deficit"},{"label":"C","text":"an increase in the government budget deficit"},{"label":"D","text":"an increase in the rate of price inflation"}],"correct":""},{"id":17,"text":"To overcome deflation in an economy the government increases the size of its budget deficit and funds this by increasing the money supply. What is most likely to reduce the effectiveness of these measures?","options":[{"label":"A","text":"a high marginal propensity to save"},{"label":"B","text":"a rise in business confidence"},{"label":"C","text":"an inelastic demand for money"},{"label":"D","text":"low cash deposit ratios for commercial banks"}],"correct":""},{"id":18,"text":"What does the Kuznets curve show about the relationship between economic development and inequality?","options":[{"label":"A","text":"the Gini coefficient initially falls as countries develop from low to high income levels"},{"label":"B","text":"the Gini coefficient initially rises as countries develop from low to high income levels"},{"label":"C","text":"there is always a negative relationship between GDP per capita and the Gini coefficient"},{"label":"D","text":"there is always a positive relationship between GDP per capita and the Gini coefficient"}],"correct":""},{"id":19,"text":"Which statement describes a multinational company (MNC)?","options":[{"label":"A","text":"A firm that avoids paying indirect taxes."},{"label":"B","text":"A firm that conducts operations in different countries."},{"label":"C","text":"A firm that experiences diseconomies of scale at low levels of output."},{"label":"D","text":"A firm that trades internationally."}],"correct":""},{"id":20,"text":"What occurs in a monetary union?","options":[{"label":"A","text":"Countries have the same currency."},{"label":"B","text":"Countries use the same fiscal policy."},{"label":"C","text":"Countries have the same domestic rates of sales tax."},{"label":"D","text":"The government budget in each country is balanced."}],"correct":""},{"id":21,"text":"What is the main role of the World Bank?","options":[{"label":"A","text":"to ensure that exchange rate systems are working efficiently"},{"label":"B","text":"to help countries enter international markets where trade barriers exist"},{"label":"C","text":"to offer short-term assistance to countries with balance of payments problems"},{"label":"D","text":"to provide low-interest loans to developing countries for infrastructure projects"}],"correct":""},{"id":22,"text":"As a member of the European Union, Greece must trade at the same exchange rate, tied to the euro, as stronger economies such as Germany. Greece has a persistent balance of payments deficit. How would changing to a floating exchange rate help Greece?","options":[{"label":"A","text":"Exchange rates will be less volatile which encourages international investment."},{"label":"B","text":"Its currency should be less open to attacks by international speculators."},{"label":"C","text":"Its currency would be allowed to depreciate which will make its exports more competitive."},{"label":"D","text":"The value of its exports and imports will automatically balance."}],"correct":""}];

const paper_21: MCQQuestion[] = [{"id":1,"text":"Why would an economy wish to achieve economic efficiency?","options":[{"label":"A","text":"to achieve an equal distribution of income"},{"label":"B","text":"to achieve full employment"},{"label":"C","text":"to ensure resources are not wasted"},{"label":"D","text":"to ensure international competitiveness"}],"correct":""},{"id":2,"text":"A firm has set a low price in the short run to act as a barrier to entry for new firms entering the market. This is an example of which pricing strategy?","options":[{"label":"A","text":"limit pricing"},{"label":"B","text":"predatory pricing"},{"label":"C","text":"price discrimination"},{"label":"D","text":"price leadership"}],"correct":""},{"id":3,"text":"A dentist is found to have charged patients for treatment they did not need. What is the likely cause of this market failure?","options":[{"label":"A","text":"a minimum price"},{"label":"B","text":"asymmetric information"},{"label":"C","text":"non-excludability"},{"label":"D","text":"productive inefficiency"}],"correct":""},{"id":4,"text":"Assuming there are no externalities, where would a nationalised firm set output to maximise social welfare?","options":[{"label":"A","text":"where average revenue equals average cost"},{"label":"B","text":"where average revenue equals marginal cost"},{"label":"C","text":"where marginal revenue equals marginal cost"},{"label":"D","text":"where marginal revenue is zero"}],"correct":""},{"id":5,"text":"Which method of government intervention may correct market failure caused by the under-consumption of a merit good?","options":[{"label":"A","text":"minimum price"},{"label":"B","text":"privatisation"},{"label":"C","text":"indirect taxation"},{"label":"D","text":"subsidy"}],"correct":""},{"id":6,"text":"Some governments introduce rent controls (maximum prices) on houses rented from private landlords. They impose such rent controls to improve living standards for individuals with low incomes. What might be the effects of rent controls in the long run?","options":[{"label":"A","text":"The long-run supply of rental houses will contract."},{"label":"B","text":"The number of unoccupied privately rented houses will increase over time."},{"label":"C","text":"The price of owner-occupied houses will increase."},{"label":"D","text":"There will be no effect on the supply of rental housing."}],"correct":""},{"id":7,"text":"Which stage of the business (trade) cycle is most likely to be characterised by an increasing negative output gap?","options":[{"label":"A","text":"boom"},{"label":"B","text":"recession"},{"label":"C","text":"recovery"},{"label":"D","text":"trough"}],"correct":""},{"id":8,"text":"Which policy is most likely to lead to a reduction in the natural rate of unemployment?","options":[{"label":"A","text":"an increase in government expenditure on goods and services"},{"label":"B","text":"an increase in government expenditure on training schemes to address skill shortages"},{"label":"C","text":"an increase in the period when the unemployed are eligible for welfare benefits"},{"label":"D","text":"an increase in the minimum wage"}],"correct":""},{"id":9,"text":"On a diagram showing a production possibility curve, what definitely represents long-run economic growth?","options":[{"label":"A","text":"a change in the slope of the curve"},{"label":"B","text":"a movement from a point below the curve to a point on the curve"},{"label":"C","text":"a movement from one point to another along a given curve"},{"label":"D","text":"an outward shift of the curve"}],"correct":""},{"id":10,"text":"What would cause the short-run Phillips curve to shift to the right?","options":[{"label":"A","text":"the unemployment rate is above the natural rate of unemployment, decreasing inflationary expectations"},{"label":"B","text":"the unemployment rate is above the natural rate of unemployment, increasing inflationary expectations"},{"label":"C","text":"the unemployment rate is below the natural rate of unemployment, decreasing inflationary expectations"},{"label":"D","text":"the unemployment rate is below the natural rate of unemployment, increasing inflationary expectations"}],"correct":""},{"id":11,"text":"Which macroeconomic policy is most likely to be used as a long-run means of reducing inflationary pressures?","options":[{"label":"A","text":"exchange rate policy"},{"label":"B","text":"fiscal policy"},{"label":"C","text":"supply-side policy"},{"label":"D","text":"monetary policy"}],"correct":""},{"id":12,"text":"A government reduces both the income tax paid by all earners and the amount of means-tested benefits paid to those receiving low or no incomes. What is most likely to be its objective?","options":[{"label":"A","text":"a more equitable income distribution"},{"label":"B","text":"a reduction in the rate of inflation"},{"label":"C","text":"a reduction in the trade deficit"},{"label":"D","text":"an increase in the rate of economic growth"}],"correct":""},{"id":13,"text":"What is not a likely feature of a customs union?","options":[{"label":"A","text":"common external tariffs with non-member nations"},{"label":"B","text":"elimination of tariffs between member nations"},{"label":"C","text":"elimination of quotas between member nations"},{"label":"D","text":"shared common currency among member nations"}],"correct":""},{"id":14,"text":"A central bank officially lowers the price of its currency relative to an agreed rate in terms of other currencies. What type of central bank policy is this?","options":[{"label":"A","text":"appreciation"},{"label":"B","text":"depreciation"},{"label":"C","text":"devaluation"},{"label":"D","text":"revaluation"}],"correct":""},{"id":15,"text":"Which variable is included in the calculation of both the Human Development Index (HDI) and the Multidimensional Poverty Index (MPI)?","options":[{"label":"A","text":"child mortality rate"},{"label":"B","text":"gross national income (GNI) per capita"},{"label":"C","text":"life expectancy at birth"},{"label":"D","text":"years of schooling"}],"correct":""},{"id":16,"text":"The table shows the value of the Gini coefficient for an economy from 2018 to 2020. } What is most likely to explain the change in the value of the Gini coefficient between 2018 and 2020?","options":[{"label":"A","text":"an increase in indirect taxes"},{"label":"B","text":"an increase in long-term unemployment"},{"label":"C","text":"an increase in the national minimum wage"},{"label":"D","text":"an increase in population"}],"correct":"","table":"<table><tr><td>Gini coefficient</td></tr><tr><td>2018</td><td>0.29</td></tr><tr><td>2019</td><td>0.28</td></tr><tr><td>2020</td><td>0.27</td></tr></table>"},{"id":17,"text":"The table shows the value of the Gini coefficient for an economy from 2018 to 2020. What is most likely to explain the change in the value of the Gini coefficient between 2018 and 2020?","options":[{"label":"A","text":"an increase in indirect taxes"},{"label":"B","text":"an increase in long-term unemployment"},{"label":"C","text":"an increase in the national minimum wage"},{"label":"D","text":"an increase in population"}],"correct":"","table":"<table><tr><td>year</td><td>Gini coefficient</td></tr><tr><td>2018</td><td>0.29</td></tr><tr><td>2019</td><td>0.28</td></tr><tr><td>2020</td><td>0.27</td></tr></table>"}];

const paper_22: MCQQuestion[] = [{"id":1,"text":"What will act as a barrier to collusion between firms?","options":[{"label":"A","text":"an ability to detect price cuts by rivals"},{"label":"B","text":"the abolition of anti-trust measures"},{"label":"C","text":"the existence of a small number of firms in the industry"},{"label":"D","text":"unstable demand conditions for products"}],"correct":""},{"id":2,"text":"The diagram shows two indifference curves. What do indifference curves indicate?","options":[{"label":"A","text":"Consumers get more satisfaction on curve \\({I}_{1}\\) from consuming more of \\(X\\) and less of \\(Y\\) ."},{"label":"B","text":"Consumers get more satisfaction on curve \\({I}_{2}\\) from consuming less of \\(X\\) and more of \\(Y\\) ."},{"label":"C","text":"Each point on the curve represents the marginal rate of substitution of good \\(X\\) for good \\(Y\\) ."},{"label":"D","text":"Movement from \\({I}_{1}\\) to \\({I}_{2}\\) cannot be made unless the indifference curves cross."}],"correct":"","image":"/images/econ-a2-mcq/272_653_612_462_387_0.jpg"},{"id":3,"text":"A firm has fixed costs of \\$300 and can produce two units per hour. Its total variable costs are \\$200 for one unit and \\$300 for two units. Which cost will fall by the lowest amount when the second unit is produced?","options":[{"label":"A","text":"average fixed cost"},{"label":"B","text":"average total cost"},{"label":"C","text":"average variable cost"},{"label":"D","text":"marginal cost"}],"correct":""},{"id":4,"text":"What is the most likely evidence that an economy has reached a position of Pareto optimality?","options":[{"label":"A","text":"price volatility"},{"label":"B","text":"a large current account deficit"},{"label":"C","text":"a regressive taxation system"},{"label":"D","text":"full employment"}],"correct":""},{"id":5,"text":"A firm is operating at a level of output which corresponds to the point where MR = 0. What objective is the firm achieving?","options":[{"label":"A","text":"maximising consumer surplus"},{"label":"B","text":"maximising profit"},{"label":"C","text":"maximising sales"},{"label":"D","text":"maximising revenue"}],"correct":""},{"id":6,"text":"What is a potential benefit of the privatisation of a country's railway services?","options":[{"label":"A","text":"higher levels of competition"},{"label":"B","text":"higher costs passed on in the form of higher prices"},{"label":"C","text":"opportunity for government regulation"},{"label":"D","text":"potential for a private monopoly"}],"correct":""},{"id":7,"text":"A government introduces a national minimum wage. What is not a benefit of this to the economy?","options":[{"label":"A","text":"It boosts the morale of workers and enhances labour productivity."},{"label":"B","text":"It raises incomes of poorer workers."},{"label":"C","text":"It reduces government spending on welfare payments."},{"label":"D","text":"It reduces structural unemployment."}],"correct":""},{"id":8,"text":"An increase in which variable would shift the supply curve for farm workers to the right?","options":[{"label":"A","text":"job security"},{"label":"B","text":"the hourly wage rate"},{"label":"C","text":"the productivity of farm workers"},{"label":"D","text":"the qualifications required"}],"correct":""},{"id":9,"text":"The diagram represents the demand and supply of labour in a competitive industry. labour What is true about unit of labour L when they are paid wage W?","options":[{"label":"A","text":"L is paid only economic rent."},{"label":"B","text":"L is paid an element of economic rent and transfer earnings."},{"label":"C","text":"L is paid below transfer earnings and leaves the industry."},{"label":"D","text":"L is paid exactly transfer earnings and remains in work."}],"correct":"","image":"/images/econ-a2-mcq/276_641_252_485_420_0.jpg"},{"id":10,"text":"What leads to an inflationary gap?","options":[{"label":"A","text":"Aggregate demand is greater than the maximum potential output of the economy."},{"label":"B","text":"Investment increases at a greater rate than profits received by a firm."},{"label":"C","text":"The economy is operating below its full capacity."},{"label":"D","text":"Innovation results in increased productivity in the economy."}],"correct":""},{"id":11,"text":"An open economy has a positive output gap. What is likely to be decreasing?","options":[{"label":"A","text":"expenditure on imports"},{"label":"B","text":"leisure time of workers"},{"label":"C","text":"nominal wage rates"},{"label":"D","text":"the general price level"}],"correct":""},{"id":12,"text":"In a two-sector economy, autonomous consumer expenditure increases by \\$100 billion, autonomous investment expenditure increases by \\$200 billion, and the marginal propensity to consume is 0.5 . What will the increase in National Income be?","options":[{"label":"A","text":"\\$150 billion"},{"label":"B","text":"\\$300 billion"},{"label":"C","text":"\\$450 billion"},{"label":"D","text":"\\$600 billion"}],"correct":""},{"id":13,"text":"Which government policy is least likely to promote inclusive economic growth?","options":[{"label":"A","text":"increasing the national minimum wage"},{"label":"B","text":"investment in transport and infrastructure"},{"label":"C","text":"legislation reducing the power of trade unions"},{"label":"D","text":"using taxes and transfer payments to redistribute income"}],"correct":""},{"id":14,"text":"What is an example of a demand-side macroeconomic policy that would reduce cyclical unemployment?","options":[{"label":"A","text":"an increase in government spending on new infrastructure such as roads"},{"label":"B","text":"an increase in government spending on retraining workers"},{"label":"C","text":"a reduction in the rate of tax on imports"},{"label":"D","text":"an increase in the rate of tax on goods and services"}],"correct":""},{"id":15,"text":"The diagram shows two liquidity preference curves \\({\\mathrm{{LP}}}_{1}\\) and \\({\\mathrm{{LP}}}_{2}\\) . What would cause the liquidity preference curve to shift from \\({\\mathrm{{LP}}}_{1}\\) to \\({\\mathrm{{LP}}}_{2}\\) ?","options":[{"label":"A","text":"There has been a fall in national income."},{"label":"B","text":"There has been a rise in the general price level."},{"label":"C","text":"There has been an increase in government borrowing."},{"label":"D","text":"There has been an increase in the rate of interest."}],"correct":"","image":"/images/econ-a2-mcq/278_575_250_618_447_0.jpg"},{"id":16,"text":"What does the Phillips curve show?","options":[{"label":"A","text":"the relationship between economic growth and employment"},{"label":"B","text":"the relationship between inequality and income per capita"},{"label":"C","text":"the relationship between inflation and unemployment"},{"label":"D","text":"the relationship between prices and national income"}],"correct":""},{"id":17,"text":"A government is aiming to increase the role of market forces. Which policy might achieve this?","options":[{"label":"A","text":"deregulation"},{"label":"B","text":"nationalisation"},{"label":"C","text":"price controls"},{"label":"D","text":"production quotas"}],"correct":""},{"id":18,"text":"A country has a progressive income tax system. What is not a valid reason for a government's decision to reduce the rate of income tax paid on higher incomes?","options":[{"label":"A","text":"to attract highly skilled workers from abroad"},{"label":"B","text":"to prevent tax evasion"},{"label":"C","text":"to provide work incentives"},{"label":"D","text":"to reduce income inequalities"}],"correct":""},{"id":19,"text":"A political party proposed a policy of quantitative easing (the creation of money by the central bank). When would such a policy be least likely to destabilise the macroeconomy in the short run?","options":[{"label":"A","text":"when the economy was experiencing a high level of inflation"},{"label":"B","text":"when the economy had price stability but there was full employment of the labour force"},{"label":"C","text":"when there was a deep recession with high levels of unemployment"},{"label":"D","text":"when there was full employment and a current account balance of payments deficit"}],"correct":""},{"id":20,"text":"What does the Laffer curve show?","options":[{"label":"A","text":"the amount of tax revenue received at each tax rate"},{"label":"B","text":"the impact on the distribution of income after tax rates rise"},{"label":"C","text":"the rise in inflation following a fall in unemployment due to a cut in income tax"},{"label":"D","text":"the rise in poverty due to a rise in the basic rate of income tax"}],"correct":""},{"id":21,"text":"What might cause income inequality to worsen in a country?","options":[{"label":"A","text":"increased discrimination"},{"label":"B","text":"increased labour market participation"},{"label":"C","text":"increased skill level of workers"},{"label":"D","text":"increased welfare payments"}],"correct":""},{"id":22,"text":"A multinational company is planning to invest in a new factory in a low-income country. What is not a possible benefit to the low-income country?","options":[{"label":"A","text":"acquiring improved technology"},{"label":"B","text":"better training for the workforce"},{"label":"C","text":"extra tax revenue for the government"},{"label":"D","text":"increased competition for small domestic producers"}],"correct":""},{"id":23,"text":"A country with fixed exchange rates faces a surplus on its current account. Which policy is most desirable to maintain the fixed exchange rate?","options":[{"label":"A","text":"an increase in subsidies given to exporters"},{"label":"B","text":"the imposition of trade barriers on the import of non-essential goods"},{"label":"C","text":"the sale of foreign currencies in the foreign exchange market"},{"label":"D","text":"the use of expansionary monetary policy"}],"correct":""},{"id":24,"text":"Which criticism of foreign direct investment (FDI) is least valid? AIt encourages competition, reduces prices and forces the less efficient domestic firms to leave the market. BIt brings workers from its own country and provides only low paying jobs to low skilled local workers. C It is usually withdrawn quickly in case of a global crisis, making developing countries more vulnerable to global shocks.","options":[{"label":"D","text":"Its actions often result in environmental degradation, and over exploitation of natural resources."},{"label":"A","text":"Permission to reproduce items where third-party owned material protected by copyright is included has been sought and cleared where possible. Every reasonable effort has been made by the publisher (UCLES) to trace copyright holders, but if any items requiring clearance have unwittingly been included, the publisher will be pleased to make amends at the earliest possible opportunity."},{"label":"B","text":"To avoid the issue of disclosure of answer-related information to candidates, all copyright acknowledgements are reproduced online in the Cambridge Assessment International Education Copyright Acknowledgements Booklet. This is produced for each series of examinations and is freely available to download at www.cambridgeinternational.org after the live examination series."},{"label":"C","text":"Cambridge Assessment International Education is part of Cambridge Assessment. Cambridge Assessment is the brand name of the University of Cambridge Local Examinations Syndicate (UCLES), which is a department of the University of Cambridge."}],"correct":""}];

